import React from 'react';
import { Card, Stack, Heading, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper function to map weather conditions to emoji icons
 */
function getWeatherEmoji(condition: string): string {
  const lowerCondition = condition.toLowerCase();

  const iconMap: Record<string, string> = {
    sunny: '☀️',
    clear: '☀️',
    cloudy: '☁️',
    cloud: '☁️',
    overcast: '☁️',
    rainy: '🌧️',
    rain: '🌧️',
    drizzle: '🌦️',
    thunderstorm: '⛈️',
    thunder: '⛈️',
    snowy: '❄️',
    snow: '❄️',
    windy: '💨',
    wind: '💨',
    fog: '🌫️',
    foggy: '🌫️',
    partly: '⛅',
    'partly cloudy': '⛅',
  };

  for (const [key, emoji] of Object.entries(iconMap)) {
    if (lowerCondition.includes(key)) {
      return emoji;
    }
  }

  return '☁️'; // Default fallback
}

/**
 * WeatherCard - A static weather display component
 * 
 * Shows current temperature, condition, humidity, wind speed, and a 5-day forecast.
 * All data is provided via props - no internal state or callbacks.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 25, low: 15 },
    { day: 'Tue', icon: '☁️', high: 22, low: 14 },
    { day: 'Wed', icon: '🌧️', high: 18, low: 12 },
    { day: 'Thu', icon: '☀️', high: 26, low: 16 },
    { day: 'Fri', icon: '⛅', high: 24, low: 15 },
  ],
}: Props) {
  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border={true}
    >
      <Stack direction="vertical" gap={16} align="stretch">
        {/* Header - City Name */}
        <Heading
          level={3}
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {city}
        </Heading>

        {/* Current Weather Section */}
        <Stack direction="horizontal" gap={16} align="center" justify="start">
          {/* Weather Icon */}
          <div
            style={{
              minWidth: '80px',
              height: '80px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '56px',
              lineHeight: '1',
            }}
          >
            {getWeatherEmoji(condition)}
          </div>

          {/* Temperature and Condition */}
          <Stack direction="vertical" gap={4} align="start" justify="center">
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {temperature}°{unit}
            </Text>
            <Text
              size="lg"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Weather Details Section */}
        <Stack direction="horizontal" gap={16} align="start" justify="between">
          {/* Humidity */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              size="sm"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              size="base"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              size="sm"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              size="base"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} km/h
            </Text>
          </Stack>

          {/* Unit Display */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              size="sm"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Unit
            </Text>
            <Text
              size="base"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              °{unit}
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin={16}
          color="var(--ggui-color-outline, #d4d4d8)"
        />

        {/* 5-Day Forecast Section */}
        <Stack
          direction="vertical"
          gap={8}
          align="stretch"
        >
          <Text
            variant="label"
            size="sm"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            5-Day Forecast
          </Text>

          {/* Forecast Items Row */}
          <Stack
            direction="horizontal"
            gap={8}
            align="stretch"
            justify="between"
          >
            {forecast.map((item, index) => (
              <Box
                key={index}
                padding={12}
                background="var(--ggui-color-primary-50, #f0f9ff)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  flex: 1,
                  minWidth: '0',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                }}
              >
                <Stack
                  direction="vertical"
                  gap={6}
                  align="center"
                  justify="center"
                >
                  {/* Day Name */}
                  <Text
                    variant="label"
                    size="sm"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    {item.day ?? `Day ${index + 1}`}
                  </Text>

                  {/* Weather Icon */}
                  <div
                    style={{
                      fontSize: '24px',
                      lineHeight: '1',
                    }}
                  >
                    {item.icon ?? '☁️'}
                  </div>

                  {/* High Temperature */}
                  <Text
                    weight="semibold"
                    size="sm"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    {item.high}°
                  </Text>

                  {/* Low Temperature */}
                  <Text
                    variant="caption"
                    size="xs"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Heading,
  Text,
  Badge,
  Button,
  Icon,
  Input,
  Select,
  Avatar,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: string;
  column: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: {
    action: 'create' | 'move' | 'edit';
    taskId?: string;
    data: Record<string, unknown>;
  }) => void;
}

const generateId = () =>
  `task-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

const priorityVariantMap: Record<'low' | 'medium' | 'high', 'info' | 'warning' | 'error'> = {
  low: 'info',
  medium: 'warning',
  high: 'error',
};

const priorityLabelMap = {
  low: 'Low',
  medium: 'Medium',
  high: 'High',
};

function GeneratedComponent({
  tasks: initialTasks,
  columns: initialColumns,
  onTaskUpdate,
}: Props) {
  const columns: Column[] = useMemo(() => {
    return (initialColumns ?? []).map((col, idx) => ({
      id: col?.id ?? `col-${idx}`,
      name: col?.name ?? `Column ${idx + 1}`,
    }));
  }, [initialColumns]);

  const [tasks, setTasks] = useState<Task[]>(() =>
    (initialTasks ?? []).map((t) => ({
      id: t?.id ?? generateId(),
      title: t?.title ?? 'Untitled Task',
      priority: t?.priority ?? 'medium',
      assignee: t?.assignee ?? '',
      column: t?.column ?? (columns[0]?.id ?? 'todo'),
      dueDate: t?.dueDate,
    }))
  );

  const [showAddForm, setShowAddForm] = useState<{ [columnId: string]: boolean }>({});
  const [newTaskTitle, setNewTaskTitle] = useState<{ [columnId: string]: string }>({});
  const [newTaskPriority, setNewTaskPriority] = useState<{ [columnId: string]: string }>({});
  const [titleError, setTitleError] = useState<{ [columnId: string]: string }>({});
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [editError, setEditError] = useState<string>('');

  const tasksByColumn = useMemo(() => {
    const map: { [key: string]: Task[] } = {};
    columns.forEach((col) => {
      map[col.id!] = tasks.filter((t) => t.column === col.id);
    });
    return map;
  }, [tasks, columns]);

  const completedCount = tasks.filter((t) => t.column === 'done').length;
  const totalCount = tasks.length;

  const handleOpenAddForm = (columnId: string) => {
    setShowAddForm((prev) => ({ ...prev, [columnId]: true }));
    setNewTaskTitle((prev) => ({ ...prev, [columnId]: '' }));
    setNewTaskPriority((prev) => ({ ...prev, [columnId]: 'medium' }));
    setTitleError((prev) => ({ ...prev, [columnId]: '' }));
  };

  const handleCloseAddForm = (columnId: string) => {
    setShowAddForm((prev) => ({ ...prev, [columnId]: false }));
    setNewTaskTitle((prev) => ({ ...prev, [columnId]: '' }));
    setTitleError((prev) => ({ ...prev, [columnId]: '' }));
  };

  const handleAddTask = (columnId: string) => {
    const title = (newTaskTitle[columnId] ?? '').trim();
    const priority = (newTaskPriority[columnId] ?? 'medium') as 'low' | 'medium' | 'high';

    if (!title) {
      setTitleError((prev) => ({ ...prev, [columnId]: 'Task title is required' }));
      return;
    }

    setIsSubmitting(true);
    setTitleError((prev) => ({ ...prev, [columnId]: '' }));

    const newTask: Task = {
      id: generateId(),
      title,
      priority,
      column: columnId,
      assignee: '',
    };

    onTaskUpdate?.({
      action: 'create',
      data: { title, priority, column: columnId },
    });

    setTasks((prev) => [...prev, newTask]);
    handleCloseAddForm(columnId);
    setIsSubmitting(false);
  };

  const handleMoveTask = (taskId: string, newColumnId: string) => {
    const task = tasks.find((t) => t.id === taskId);
    if (!task) return;

    onTaskUpdate?.({
      action: 'move',
      taskId,
      data: { column: newColumnId },
    });

    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: newColumnId } : t))
    );
  };

  const handleStartEditTask = (task: Task) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
    setEditError('');
  };

  const handleSaveEditTask = (taskId: string) => {
    const newTitle = editingTitle.trim();
    if (!newTitle) {
      setEditError('Task title cannot be empty');
      return;
    }

    onTaskUpdate?.({
      action: 'edit',
      taskId,
      data: { title: newTitle },
    });

    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    setEditingTaskId(null);
    setEditingTitle('');
    setEditError('');
  };

  const handleCancelEdit = () => {
    setEditingTaskId(null);
    setEditingTitle('');
    setEditError('');
  };

  const handleKeyDownEdit = (
    e: React.KeyboardEvent<HTMLInputElement>,
    taskId: string
  ) => {
    if (e.key === 'Enter') {
      handleSaveEditTask(taskId);
    } else if (e.key === 'Escape') {
      handleCancelEdit();
    }
  };

  return (
    <Container maxWidth="full" padding={16}>
      <Stack gap={16} direction="vertical">
        {/* Summary Bar */}
        <Stack direction="horizontal" align="center" gap={16}>
          <Heading level={1}>Task Board</Heading>
          <Spacer size="flex" />
          <Text
            variant="body"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {completedCount} of {totalCount} tasks completed
          </Text>
        </Stack>

        {/* Columns Container */}
        <Stack direction="horizontal" gap={16} align="stretch">
          {columns.map((column) => {
            const columnId = column.id!;
            const columnTasks = tasksByColumn[columnId] ?? [];
            const isOpen = showAddForm[columnId] ?? false;

            return (
              <Card
                key={columnId}
                shadow="sm"
                padding={16}
                border
                radius="lg"
                style={{
                  flex: '1 1 0',
                  minWidth: '300px',
                  display: 'flex',
                  flexDirection: 'column',
                }}
              >
                <Stack
                  gap={12}
                  direction="vertical"
                  style={{
                    flex: '1 1 auto',
                    display: 'flex',
                    flexDirection: 'column',
                  }}
                >
                  {/* Column Header */}
                  <Stack direction="horizontal" align="center" gap={8}>
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default" size="sm" pill>
                      {columnTasks.length}
                    </Badge>
                  </Stack>

                  <Divider orientation="horizontal" margin={8} />

                  {/* Task List */}
                  <Stack
                    gap={8}
                    direction="vertical"
                    style={{
                      flex: '1 1 auto',
                      overflowY: 'auto',
                      maxHeight: '500px',
                    }}
                  >
                    {columnTasks.map((task) => (
                      <Card
                        key={task.id}
                        shadow="sm"
                        padding={12}
                        border
                        radius="md"
                      >
                        <Stack gap={8} direction="vertical">
                          {/* Task Title with Edit */}
                          {editingTaskId === task.id ? (
                            <Stack gap={4} direction="horizontal" align="center">
                              <Input
                                label="Task title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                onKeyDown={(e) =>
                                  handleKeyDownEdit(
                                    e as React.KeyboardEvent<HTMLInputElement>,
                                    task.id
                                  )
                                }
                                placeholder="Task title"
                                error={editError}
                                autoFocus
                              />
                              <Button
                                variant="primary"
                                size="xs"
                                onClick={() => handleSaveEditTask(task.id)}
                                aria-label="Save task edit"
                              >
                                ✓
                              </Button>
                              <Button
                                variant="ghost"
                                size="xs"
                                onClick={handleCancelEdit}
                                aria-label="Cancel task edit"
                              >
                                ✕
                              </Button>
                            </Stack>
                          ) : (
                            <Stack
                              gap={8}
                              direction="horizontal"
                              align="center"
                            >
                              <Text
                                variant="body"
                                truncate
                                as="span"
                                style={{ flex: 1, cursor: 'pointer' }}
                              >
                                {task.title}
                              </Text>
                              <Button
                                variant="ghost"
                                size="xs"
                                leftIcon={<Icon name="plus" size={14} />}
                                onClick={() => handleStartEditTask(task)}
                                aria-label="Edit task"
                              />
                            </Stack>
                          )}

                          {/* Priority Badge + Assignee + Due Date */}
                          <Stack
                            direction="horizontal"
                            gap={8}
                            align="center"
                          >
                            <Badge
                              variant={priorityVariantMap[task.priority]}
                              size="sm"
                              pill
                            >
                              {priorityLabelMap[task.priority]}
                            </Badge>

                            {task.assignee && (
                              <Avatar name={task.assignee} size="sm" />
                            )}

                            {task.dueDate && (
                              <Text
                                variant="caption"
                                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                                as="span"
                              >
                                {new Date(task.dueDate).toLocaleDateString(
                                  undefined,
                                  {
                                    month: 'short',
                                    day: 'numeric',
                                  }
                                )}
                              </Text>
                            )}
                          </Stack>

                          {/* Move Task Select */}
                          <Select
                            value={task.column}
                            onChange={(newColumn) =>
                              handleMoveTask(task.id, newColumn)
                            }
                            options={columns
                              .filter((c) => c.id !== columnId)
                              .map((c) => ({
                                value: c.id!,
                                label: c.name!,
                              }))}
                            placeholder="Move to..."
                            size="sm"
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Flexible Spacer */}
                  <Spacer size="flex" />

                  {/* Add Task Section */}
                  {!isOpen ? (
                    <Button
                      variant="secondary"
                      fullWidth
                      onClick={() => handleOpenAddForm(columnId)}
                      leftIcon={<Icon name="plus" size={16} />}
                    >
                      Add Task
                    </Button>
                  ) : (
                    <Card shadow="none" border padding={12} radius="md">
                      <Stack gap={8} direction="vertical">
                        <Input
                          label="Task title"
                          value={newTaskTitle[columnId] ?? ''}
                          onChange={(value) =>
                            setNewTaskTitle((prev) => ({
                              ...prev,
                              [columnId]: value,
                            }))
                          }
                          placeholder="Enter task title"
                          error={titleError[columnId]}
                          size="sm"
                          autoFocus
                        />

                        <Select
                          label="Priority"
                          value={newTaskPriority[columnId] ?? 'medium'}
                          onChange={(value) =>
                            setNewTaskPriority((prev) => ({
                              ...prev,
                              [columnId]: value,
                            }))
                          }
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />

                        <Stack direction="horizontal" gap={8}>
                          <Button
                            variant="primary"
                            size="sm"
                            fullWidth
                            onClick={() => handleAddTask(columnId)}
                            loading={isSubmitting}
                            disabled={isSubmitting}
                          >
                            Add Task
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            fullWidth
                            onClick={() => handleCloseAddForm(columnId)}
                            disabled={isSubmitting}
                          >
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

export default GeneratedComponent;

import React, { useMemo, useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Badge,
  Text,
  Heading,
  Divider,
  Button,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: ElementData[];
}

const getCategoryColor = (category?: string): string => {
  const colorMap: Record<string, string> = {
    'Alkali Metal': 'var(--ggui-color-primary-500, #0ea5e9)',
    'Alkaline Earth Metal': 'var(--ggui-color-primary-300, #7dd3fc)',
    'Lanthanide': 'var(--ggui-color-warning-500, #f59e0b)',
    'Actinide': 'var(--ggui-color-warning-600, #d97706)',
    'Transition Metal': 'var(--ggui-color-info-500, #06b6d4)',
    'Post-transition Metal': 'var(--ggui-color-neutral-500, #6b7280)',
    'Nonmetal': 'var(--ggui-color-success-500, #22c55e)',
    'Noble Gas': 'var(--ggui-color-error-500, #ef4444)',
    'Halogen': 'var(--ggui-color-error-400, #fca5a5)',
    'Metalloid': 'var(--ggui-color-neutral-400, #9ca3af)',
  };
  return colorMap[category ?? ''] || 'var(--ggui-color-neutral-300, #d1d5db)';
};

const getCategoryVariant = (category?: string): 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' | 'default' => {
  const variantMap: Record<string, 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' | 'default'> = {
    'Alkali Metal': 'primary',
    'Alkaline Earth Metal': 'primary',
    'Lanthanide': 'warning',
    'Actinide': 'warning',
    'Transition Metal': 'info',
    'Post-transition Metal': 'default',
    'Nonmetal': 'success',
    'Noble Gas': 'error',
    'Halogen': 'error',
    'Metalloid': 'default',
  };
  return variantMap[category ?? ''] || 'default';
};

export default function PeriodicTable({ elements }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const uniqueCategories = [...new Set(elements.map((e) => e.category))].filter(
      Boolean
    );
    return uniqueCategories as string[];
  }, [elements]);

  const visibleElementIds = useMemo(() => {
    return new Set(filteredElements.map((e) => e.atomicNumber));
  }, [filteredElements]);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1} align="center">
          Periodic Table of Elements
        </Heading>

        <Stack gap={8}>
          <Text variant="label" as="label">
            Search elements
          </Text>
          <input
            type="search"
            placeholder="Search by name or symbol (e.g., 'Gold' or 'Au')"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.currentTarget.value)}
            style={{
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 12px)',
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              border: '1px solid var(--ggui-color-neutral-300, #d1d5db)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              fontFamily: 'inherit',
            }}
          />
        </Stack>

        <Stack gap={8}>
          <Heading level={4}>Legend</Heading>
          <Stack direction="horizontal" gap={12} wrap>
            {categories.map((category) => (
              <Badge
                key={category}
                variant={getCategoryVariant(category)}
                pill
                size="md"
              >
                {category}
              </Badge>
            ))}
          </Stack>
        </Stack>

        <Box
          padding={24}
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius={12}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          {elements.map((element) => {
            const isVisible = visibleElementIds.has(element.atomicNumber);
            const isSelected =
              selectedElement?.atomicNumber === element.atomicNumber;
            const bgColor = getCategoryColor(element.category);

            return (
              <button
                key={element.atomicNumber}
                onClick={() => setSelectedElement(element)}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  display: isVisible ? 'flex' : 'none',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  background: bgColor,
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  cursor: 'pointer',
                  transition: 'all 200ms ease-in-out',
                  border: isSelected
                    ? '2px solid var(--ggui-color-onSurface, #18181b)'
                    : '1px solid transparent',
                  minHeight: '60px',
                  opacity: isVisible ? 1 : 0.5,
                  boxShadow: isSelected
                    ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                    : 'none',
                }}
                aria-pressed={isSelected}
                title={`${element.name} (${element.symbol})`}
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  size="xs"
                  align="center"
                  as="span"
                >
                  {element.atomicNumber}
                </Text>

                <Text
                  as="span"
                  size="lg"
                  weight="bold"
                  color="var(--ggui-color-onSurface, #18181b)"
                  align="center"
                >
                  {element.symbol}
                </Text>

                {element.name && (
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    size="xs"
                    align="center"
                    truncate
                    as="span"
                  >
                    {element.name}
                  </Text>
                )}
              </button>
            );
          })}
        </Box>

        {selectedElement && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={12}>
              <Heading
                level={3}
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {selectedElement.name || selectedElement.symbol}
              </Heading>

              <Stack direction="horizontal" gap={16} align="start">
                <Text
                  as="span"
                  size="2xl"
                  weight="bold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {selectedElement.symbol}
                </Text>
                <Stack gap={4}>
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Atomic Number
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {selectedElement.atomicNumber}
                  </Text>
                </Stack>
              </Stack>

              {selectedElement.atomicWeight && (
                <Stack gap={4}>
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Atomic Weight
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {selectedElement.atomicWeight}
                  </Text>
                </Stack>
              )}

              {selectedElement.category && (
                <Stack gap={4}>
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Category
                  </Text>
                  <Badge
                    variant={getCategoryVariant(selectedElement.category)}
                    pill
                    size="md"
                  >
                    {selectedElement.category}
                  </Badge>
                </Stack>
              )}

              <Divider margin={12} />

              <Stack gap={8} justify="end">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Badge,
  Box,
  Input,
  Button,
  Avatar,
} from '@ggui-ai/design/primitives';

interface ChatMessage {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: ChatMessage[];
  onSend?: (payload: { text: string; timestamp: string }) => void;
}

interface MessageGroup {
  sender: string;
  messages: ChatMessage[];
  isCurrentUser: boolean;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  onSend,
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const messageGroups = useMemo(() => {
    const groups: MessageGroup[] = [];
    messages.forEach((msg) => {
      const sender = msg.sender || 'Unknown';
      const isCurrentUser = sender === currentUser;
      if (groups.length === 0 || groups[groups.length - 1].sender !== sender) {
        groups.push({ sender, messages: [msg], isCurrentUser });
      } else {
        groups[groups.length - 1].messages.push(msg);
      }
    });
    return groups;
  }, [messages, currentUser]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  const formatTimestamp = (isoString?: string): string => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString('en-US', {
        hour: 'numeric',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  const handleSend = useCallback(() => {
    const trimmedText = inputValue.trim();
    if (trimmedText && onSend) {
      onSend({
        text: trimmedText,
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  }, [inputValue, onSend]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const isInputEmpty = inputValue.trim() === '';

  return (
    <Card
      shadow="md"
      border={true}
      radius="lg"
      padding={0}
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
      }}
    >
      <Box
        paddingX={16}
        paddingY={12}
        background="var(--ggui-color-surface, #fafafa)"
        style={{
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          flex: '0 0 auto',
        }}
      >
        <Stack
          direction="horizontal"
          gap={8}
          justify="between"
          align="center"
        >
          <Text
            variant="label"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {title}
          </Text>
          {participantCount !== undefined && (
            <Badge variant="primary" size="sm" pill={true}>
              {participantCount} participant{participantCount !== 1 ? 's' : ''}
            </Badge>
          )}
        </Stack>
      </Box>

      <Stack
        direction="vertical"
        gap={8}
        style={{
          flex: 1,
          overflow: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          background: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        {messageGroups.length === 0 ? (
          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
            style={{ margin: 'auto', opacity: 0.6 }}
          >
            No messages yet. Start the conversation!
          </Text>
        ) : (
          messageGroups.map((group, groupIdx) => (
            <Stack
              key={`group-${groupIdx}`}
              direction="horizontal"
              gap={8}
              justify={group.isCurrentUser ? 'end' : 'start'}
              align="end"
            >
              {!group.isCurrentUser && (
                <Avatar
                  name={group.sender}
                  size="sm"
                  shape="circle"
                  style={{ flex: '0 0 auto' }}
                />
              )}

              <Stack
                direction="vertical"
                gap={4}
                style={{
                  maxWidth: '60%',
                  flex: group.isCurrentUser ? '0 1 auto' : undefined,
                }}
              >
                {!group.isCurrentUser && (
                  <Text
                    variant="bodySmall"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {group.sender}
                  </Text>
                )}

                {group.messages.map((msg, msgIdx) => (
                  <Stack
                    key={`msg-${groupIdx}-${msgIdx}`}
                    direction="vertical"
                    gap={2}
                  >
                    <Box
                      padding={12}
                      background={
                        group.isCurrentUser
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      style={{
                        wordWrap: 'break-word',
                        overflowWrap: 'break-word',
                      }}
                    >
                      <Text
                        variant="body"
                        color={
                          group.isCurrentUser
                            ? 'white'
                            : 'var(--ggui-color-onSurface, #18181b)'
                        }
                      >
                        {msg.text || ''}
                      </Text>
                    </Box>

                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      style={{
                        textAlign: group.isCurrentUser ? 'right' : 'left',
                        fontSize: 'var(--ggui-font-size-xs, 12px)',
                      }}
                    >
                      {formatTimestamp(msg.timestamp)}
                    </Text>
                  </Stack>
                ))}
              </Stack>

              {group.isCurrentUser && <div style={{ flex: '0 0 40px' }} />}
            </Stack>
          ))
        )}

        <div ref={messagesEndRef} />
      </Stack>

      <Box
        paddingX={16}
        paddingY={12}
        background="var(--ggui-color-surface, #fafafa)"
        style={{
          borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          flex: '0 0 auto',
        }}
      >
        <Stack direction="horizontal" gap={8} align="center">
          <Input
            label="Compose message"
            value={inputValue}
            onChange={setInputValue}
            placeholder="Type a message..."
            type="text"
            size="md"
          />
          <Button
            variant="primary"
            size="sm"
            onClick={handleSend}
            disabled={isInputEmpty}
            data-action="sendMessage"
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Box,
  Spinner,
} from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({ stocks = [], lastUpdated }: Props) {
  const [displayStocks, setDisplayStocks] = useState<Stock[]>(stocks);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'error'>('connecting');
  const [lastUpdateTime, setLastUpdateTime] = useState<string | undefined>(lastUpdated);

  // Listen for live agent data events via Stream Contract
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { stocks: newStocks, timestamp } = customEvent.detail || {};

      if (Array.isArray(newStocks)) {
        setDisplayStocks(newStocks);
        setConnectionStatus('connected');
        if (timestamp) {
          setLastUpdateTime(timestamp);
        }
      }
    };

    // Set initial status based on props
    setConnectionStatus(stocks.length > 0 ? 'connected' : 'connecting');
    setDisplayStocks(stocks);

    // Register event listener for ggui:agent-data stream
    try {
      const handler = (evt: Event) => handleAgentData(evt);
      const addListenerFn = (typeof document !== 'undefined' ? document : null)?.addEventListener 
        || (typeof globalThis !== 'undefined' ? (globalThis as any).addEventListener : null);

      if (addListenerFn && typeof addListenerFn === 'function') {
        addListenerFn.call(
          typeof document !== 'undefined' ? document : globalThis,
          'ggui:agent-data',
          handler
        );

        return () => {
          const removeListenerFn = (typeof document !== 'undefined' ? document : null)?.removeEventListener
            || (typeof globalThis !== 'undefined' ? (globalThis as any).removeEventListener : null);
          if (removeListenerFn && typeof removeListenerFn === 'function') {
            removeListenerFn.call(
              typeof document !== 'undefined' ? document : globalThis,
              'ggui:agent-data',
              handler
            );
          }
        };
      }
    } catch {
      // Gracefully handle environments without event listeners
    }

    return undefined;
  }, [stocks]);

  // Format timestamp
  const formatTimestamp = (iso?: string) => {
    if (!iso) return 'N/A';
    try {
      const date = new Date(iso);
      return date.toLocaleString();
    } catch {
      return iso;
    }
  };

  // Render status indicator
  const getStatusColor = () => {
    switch (connectionStatus) {
      case 'connected':
        return 'var(--ggui-color-success-500, #22c55e)';
      case 'connecting':
        return 'var(--ggui-color-warning-500, #f59e0b)';
      case 'error':
        return 'var(--ggui-color-error-500, #ef4444)';
      default:
        return 'var(--ggui-color-neutral-400, #9ca3af)';
    }
  };

  const getStatusText = () => {
    switch (connectionStatus) {
      case 'connected':
        return '● Live';
      case 'connecting':
        return 'Connecting...';
      case 'error':
        return '✕ Error';
      default:
        return 'Initializing...';
    }
  };

  return (
    <Container maxWidth="2xl" padding={24} center>
      <Stack direction="vertical" gap={24} align="stretch">
        {/* Header Section */}
        <Stack direction="vertical" gap={8} align="start">
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>
          <Stack direction="horizontal" gap={12} align="center">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formatTimestamp(lastUpdateTime)}
            </Text>
            {connectionStatus === 'connecting' && (
              <Spinner size={16} color="var(--ggui-color-warning-500, #f59e0b)" />
            )}
            <Text
              variant="caption"
              color={getStatusColor()}
              weight="medium"
              as="span"
              style={{ marginLeft: 'auto' }}
            >
              {getStatusText()}
            </Text>
          </Stack>
        </Stack>

        {/* Stock Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
            width: '100%',
          }}
        >
          {displayStocks.map((stock, index) => {
            const symbol = stock.symbol || 'N/A';
            const name = stock.name || 'Unknown Company';
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;

            const isPositive = change >= 0;
            const arrow = isPositive ? '▲' : '▼';
            const priceText = `$${price.toFixed(2)}`;
            const changeText = `${isPositive ? '+' : ''}${change.toFixed(2)}`;
            const percentText = `${isPositive ? '+' : ''}${changePercent.toFixed(2)}%`;

            const textColor = isPositive
              ? 'var(--ggui-color-success-500, #22c55e)'
              : 'var(--ggui-color-error-500, #ef4444)';

            const borderColor = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';

            return (
              <Card
                key={`${symbol}-${index}`}
                padding={20}
                shadow="sm"
                radius="lg"
                border={true}
                style={{
                  borderColor: borderColor,
                  borderWidth: '1px',
                }}
              >
                <Stack direction="vertical" gap={12} align="stretch">
                  {/* Ticker Symbol */}
                  <Text
                    variant="label"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {symbol}
                  </Text>

                  {/* Company Name */}
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    truncate
                  >
                    {name}
                  </Text>

                  {/* Price */}
                  <Text
                    size="xl"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {priceText}
                  </Text>

                  {/* Change Section */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text
                      size="lg"
                      weight="medium"
                      color={textColor}
                      as="span"
                    >
                      {arrow}
                    </Text>
                    <Text
                      size="lg"
                      weight="medium"
                      color={textColor}
                      as="span"
                    >
                      {changeText}
                    </Text>
                    <Text
                      size="sm"
                      weight="medium"
                      color={textColor}
                      as="span"
                    >
                      {percentText}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>

        {/* Empty State */}
        {displayStocks.length === 0 && connectionStatus !== 'connecting' && (
          <Box
            padding={40}
            borderRadius={12}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          >
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
            >
              No stocks available. Waiting for live data...
            </Text>
          </Box>
        )}

        {/* Loading State */}
        {displayStocks.length === 0 && connectionStatus === 'connecting' && (
          <Box
            padding={40}
            borderRadius={12}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          >
            <Stack direction="vertical" gap={16} align="center" justify="center">
              <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Connecting to live market data...
              </Text>
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Container,
  Divider,
  Spacer,
  Select,
  Toggle,
  Heading,
  Box,
} from '@ggui-ai/design/primitives';

interface Profile {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profile: Profile) => void;
}

export default function OnboardingWizard(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [profile, setProfile] = useState<Profile>({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0] || '👤',
    role: props.initialProfile?.role || '',
    emailNotifications: props.initialProfile?.emailNotifications !== false,
    theme: props.initialProfile?.theme || 'light',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!profile.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!profile.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(profile.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateStep2 = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!profile.role) {
      newErrors.role = 'Please select a role';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) {
      return;
    }
    if (currentStep === 2 && !validateStep2()) {
      return;
    }
    setErrors({});
    if (currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    setErrors({});
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    if (props.onComplete) {
      props.onComplete(profile);
    }
  };

  const roleSelectOptions = props.roleOptions.map((role) => ({
    value: role.toLowerCase().replace(/\s+/g, '-'),
    label: role,
  }));

  const progressPercent = ((currentStep - 1) / 2) * 100;
  const isStep1Valid = profile.name.trim() && profile.email.trim() && validateEmail(profile.email);
  const isStep2Valid = !!profile.role;

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={32}>
        {/* Step Indicator and Progress Bar */}
        <Stack gap={16}>
          <Stack direction="horizontal" align="center" gap={16}>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              Step {currentStep} of 3
            </Heading>
            <Spacer size="flex" />
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {currentStep === 1 && 'Profile Setup'}
              {currentStep === 2 && 'Preferences'}
              {currentStep === 3 && 'Review & Confirm'}
            </Text>
          </Stack>

          {/* Progress Bar */}
          <Box
            padding={0}
            background="var(--ggui-color-neutral-200, #e5e7eb)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              height: '8px',
              overflow: 'hidden',
            }}
          >
            <div
              style={{
                height: '100%',
                width: `${progressPercent}%`,
                backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
                transition: 'width 0.3s ease-in-out',
              }}
            />
          </Box>
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={20}>
              <Input
                label="Name"
                placeholder="Enter your name"
                value={profile.name}
                onChange={(value) => setProfile({ ...profile, name: value })}
                error={errors.name}
                required
                size="md"
              />

              <Input
                label="Email"
                placeholder="you@example.com"
                type="email"
                value={profile.email}
                onChange={(value) => setProfile({ ...profile, email: value })}
                error={errors.email}
                required
                size="md"
              />

              <Stack gap={8}>
                <Text
                  as="label"
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Choose Avatar
                </Text>
                <Stack direction="horizontal" gap={12} align="center" wrap>
                  {props.avatarOptions.map((emoji) => (
                    <button
                      key={emoji}
                      onClick={() => setProfile({ ...profile, avatar: emoji })}
                      style={{
                        fontSize: '32px',
                        padding: 'var(--ggui-spacing-2, 8px)',
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                        border:
                          profile.avatar === emoji
                            ? '3px solid var(--ggui-color-primary-600, #0284c7)'
                            : '2px solid var(--ggui-color-outline, #d4d4d8)',
                        backgroundColor:
