}

function getConditionEmoji(condition: string): string {
  const lower = condition.toLowerCase();
  if (lower.includes('sunny') || lower === 'clear') return '☀️';
  if (lower.includes('partly cloudy') || lower.includes('partly sunny')) return '⛅';
  if (lower.includes('cloudy') || lower.includes('overcast')) return '☁️';
  if (lower.includes('thunder') || lower.includes('storm')) return '⛈️';
  if (lower.includes('rain') || lower.includes('drizzle') || lower.includes('shower')) return '🌧️';
  if (lower.includes('snow') || lower.includes('sleet')) return '🌨️';
  if (lower.includes('wind')) return '🌬️';
  if (lower.includes('fog') || lower.includes('mist') || lower.includes('haze')) return '🌫️';
  return '🌤️';
}

