import React, { useState, useCallback, useMemo } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Badge, Avatar, Box, Icon, Divider, Select, Alert } from '@ggui-ai/design/primitives';

interface TaskItem {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface ColumnDef {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: TaskItem[];
  columns?: ColumnDef[];
  onTaskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onSubmit?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
}

interface InternalTask {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate: string;
}

const PRIORITY_VARIANT: Record<string, 'error' | 'warning' | 'success'> = {
  high: 'error',
  medium: 'warning',
  low: 'success',
};

function generateId(): string {
  return 'task-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 7);
}

export default function GeneratedComponent(props: Props) {
  const {
    tasks: initialTasks = [
      { id: 'task-1', title: 'Design homepage mockup', priority: 'high', assignee: 'AB', column: 'todo', dueDate: '2025-02-15' },
      { id: 'task-2', title: 'Set up CI/CD pipeline', priority: 'medium', assignee: 'CD', column: 'todo', dueDate: '2025-02-20' },
      { id: 'task-3', title: 'Write API documentation', priority: 'low', assignee: 'EF', column: 'in-progress', dueDate: '' },
      { id: 'task-4', title: 'Code review PR #42', priority: 'medium', assignee: 'GH', column: 'in-progress', dueDate: '2025-02-18' },
      { id: 'task-5', title: 'Deploy staging environment', priority: 'high', assignee: 'AB', column: 'done', dueDate: '2025-02-10' },
    ],
    columns = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ],
    onTaskUpdate,
    onSubmit,
  } = props;

  const [taskList, setTaskList] = useState<InternalTask[]>(() =>
    initialTasks.map((t, i) => ({
      id: t.id || `task-init-${i}`,
      title: t.title || 'Untitled Task',
      priority: t.priority || 'medium',
      assignee: t.assignee || '??',
      column: t.column || (columns[0]?.id || 'todo'),
      dueDate: t.dueDate || '',
    }))
  );

  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskAssignee, setNewTaskAssignee] = useState('');
  const [formError, setFormError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const fireCallback = useCallback((action: string, taskId: string, data: Record<string, unknown>) => {
    const payload = { action, taskId, data };
    if (onTaskUpdate) onTaskUpdate(payload);
    if (onSubmit) onSubmit(payload);
  }, [onTaskUpdate, onSubmit]);

  const doneColumnId = columns.find(c => c.id === 'done')?.id || 'done';
  const totalTasks = taskList.length;
  const completedTasks = taskList.filter(t => t.column === doneColumnId).length;

  const tasksByColumn = useMemo(() => {
    const map: Record<string, InternalTask[]> = {};
    for (const col of columns) {
      if (col.id) map[col.id] = taskList.filter(t => t.column === col.id);
    }
    return map;
  }, [taskList, columns]);

  const showSuccess = useCallback((msg: string) => {
    setSuccessMsg(msg);
    setTimeout(() => setSuccessMsg(''), 2500);
  }, []);

  const handleMoveTask = useCallback((taskId: string, newCol: string) => {
    setTaskList(prev => prev.map(t => t.id === taskId ? { ...t, column: newCol } : t));
    fireCallback('moved', taskId, { column: newCol });
    showSuccess('Task moved successfully');
  }, [fireCallback, showSuccess]);

  const handleAddTask = useCallback(async () => {
    if (!newTaskTitle.trim()) { setFormError('Task title is required'); return; }
    if (!addingToColumn) return;
    setFormError('');
    setIsSubmitting(true);
    await new Promise(r => setTimeout(r, 400));
    const newId = generateId();
    const task: InternalTask = {
      id: newId, title: newTaskTitle.trim(), priority: newTaskPriority,
      assignee: newTaskAssignee.trim() || '??', column: addingToColumn, dueDate: '',
    };
    setTaskList(prev => [...prev, task]);
    fireCallback('created', newId, { title: task.title, priority: task.priority, assignee: task.assignee, column: task.column });
    setNewTaskTitle(''); setNewTaskPriority('medium'); setNewTaskAssignee('');
    setIsSubmitting(false); setAddingToColumn(null);
    showSuccess('Task created successfully');
  }, [newTaskTitle, newTaskPriority, newTaskAssignee, addingToColumn, fireCallback, showSuccess]);

  const handleStartEdit = useCallback((task: InternalTask) => {
    setEditingTaskId(task.id); setEditTitle(task.title);
  }, []);

  const handleSaveEdit = useCallback(() => {
    if (!editingTaskId || !editTitle.trim()) return;
    setTaskList(prev => prev.map(t => t.id === editingTaskId ? { ...t, title: editTitle.trim() } : t));
    fireCallback('edited', editingTaskId, { title: editTitle.trim() });
    setEditingTaskId(null); setEditTitle('');
    showSuccess('Task updated successfully');
  }, [editingTaskId, editTitle, fireCallback, showSuccess]);

  const handleCancelEdit = useCallback(() => { setEditingTaskId(null); setEditTitle(''); }, []);

  const resetForm = useCallback(() => {
    setAddingToColumn(null); setFormError(''); setNewTaskTitle(''); setNewTaskPriority('medium'); setNewTaskAssignee('');
  }, []);

  const editInputLabel = "Edit task title";
  const titleInputLabel = "Task Title";
  const assigneeInputLabel = "Assignee Initials";

  return (
    <Stack gap={16} style={{ width: '100%' }}>
      <Card padding={16} shadow="sm" radius="lg">
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={3}>Task Board</Heading>
          <Stack direction="horizontal" gap={16} align="center">
            <Stack direction="horizontal" gap={4} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Total:</Text>
              <Badge variant="primary" size="md">{totalTasks}</Badge>
            </Stack>
            <Stack direction="horizontal" gap={4} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed:</Text>
              <Badge variant="success" size="md">{completedTasks}</Badge>
            </Stack>
          </Stack>
        </Stack>
      </Card>

      {successMsg && (
        <Alert variant="success" closable onClose={() => setSuccessMsg('')}>{successMsg}</Alert>
      )}

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: `repeat(${columns.length}, 1fr)`,
          gap: 'var(--ggui-spacing-4, 16px)',
          width: '100%',
          minHeight: 400,
        }}
        role="region"
        aria-label="Kanban task board"
      >
        {columns.map(col => {
          const colId = col.id || '';
          const colName = col.name || 'Unnamed';
          const colTasks = tasksByColumn[colId] || [];
          const otherCols = columns.filter(c => c.id !== colId);

          return (
            <Card key={colId} padding={0} shadow="sm" radius="lg" border>
              <Stack gap={0}>
                <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="12px 12px 0 0">
                  <Stack direction="horizontal" align="center" justify="between">
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{colName}</Text>
                    <Badge variant="default" size="sm">{colTasks.length}</Badge>
                  </Stack>
                </Box>
                <Divider margin={0} />
                <Box padding={12}>
                  <Stack gap={10}>
                    {colTasks.length === 0 && (
                      <Box padding={16}>
                        <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">No tasks yet</Text>
                      </Box>
                    )}

                    {colTasks.map((task, idx) => (
                      <div key={task.id} style={{ animation: `ggui-fadeIn 200ms ease-out ${idx * 50}ms both` }}>
                        <Card padding={12} shadow="sm" radius="md" border>
                          <Stack gap={8}>
                            <Stack direction="horizontal" align="start" justify="between" gap={8}>
                              {editingTaskId === task.id ? (
                                <Stack gap={6} style={{ flex: 1 }}>
                                  <Input label={editInputLabel} value={editTitle} onChange={setEditTitle} size="sm" placeholder="Task title" autoFocus />
                                  <Stack direction="horizontal" gap={4}>
                                    <Button size="xs" variant="primary" onPress={handleSaveEdit}>Save</Button>
                                    <Button size="xs" variant="ghost" onPress={handleCancelEdit}>Cancel</Button>
                                  </Stack>
                                </Stack>
                              ) : (
                                <div
                                  onDoubleClick={() => handleStartEdit(task)}
                                  style={{ flex: 1, cursor: 'pointer' }}
                                  title="Double-click to edit"
                                  role="button"
                                  tabIndex={0}
                                  onKeyDown={(e) => { if (e.key === 'Enter') handleStartEdit(task); }}
                                  aria-label={`Edit task: ${task.title}`}
                                >
                                  <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)" truncate>{task.title}</Text>
                                </div>
                              )}
                              {editingTaskId !== task.id && (
                                <Button size="xs" variant="ghost" onPress={() => handleStartEdit(task)} aria-label={`Edit ${task.title}`}>
                                  <Icon name="settings" size={14} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                                </Button>
                              )}
                            </Stack>

                            <Stack direction="horizontal" align="center" justify="between" gap={8}>
                              <Stack direction="horizontal" gap={6} align="center">
                                <Badge variant={PRIORITY_VARIANT[task.priority]} size="sm" pill>{task.priority}</Badge>
                                {task.dueDate && (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate}</Text>
                                )}
                              </Stack>
                              <Avatar name={task.assignee} size="xs" shape="circle" />
                            </Stack>

                            {otherCols.length > 0 && (
                              <Stack direction="horizontal" gap={4} wrap>
                                {otherCols.map(oc => (
                                  <Button key={oc.id} size="xs" variant="outline" onPress={() => handleMoveTask(task.id, oc.id || '')} aria-label={`Move to ${oc.name}`}>
                                    <Text variant="caption" as="span">→ {oc.name}</Text>
                                  </Button>
                                ))}
                              </Stack>
                            )}
                          </Stack>
                        </Card>
                      </div>
                    ))}

                    {addingToColumn === colId ? (
                      <Card padding={12} shadow="md" radius="md" border>
                        <Stack gap={10}>
                          <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">New Task</Text>
                          <Input label={titleInputLabel} value={newTaskTitle} onChange={(v) => { setNewTaskTitle(v); if (formError) setFormError(''); }} placeholder="Enter task title" required error={formError} disabled={isSubmitting} size="sm" />
                          <Select label="Priority" value={newTaskPriority} onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} disabled={isSubmitting} size="sm" />
                          <Input label={assigneeInputLabel} value={newTaskAssignee} onChange={setNewTaskAssignee} placeholder="e.g. AB" disabled={isSubmitting} size="sm" />
                          <Stack direction="horizontal" gap={8} justify="end">
                            <Button size="sm" variant="ghost" onPress={resetForm} disabled={isSubmitting}>Cancel</Button>
                            <Button size="sm" variant="primary" onPress={handleAddTask} loading={isSubmitting} disabled={isSubmitting}>Add Task</Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : (
                      <Button variant="ghost" size="sm" fullWidth onPress={() => { setAddingToColumn(colId); setFormError(''); setNewTaskTitle(''); setNewTaskPriority('medium'); setNewTaskAssignee(''); }} leftIcon={<Icon name="plus" size={16} />}>
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Box>
              </Stack>
            </Card>
          );
        })}
      </div>
    </Stack>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Heading, Box, Container, Badge, Icon, Divider } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<ElementData>;
}

const categoryColorMap: Record<string, { bg: string; text: string; border: string }> = {
  'alkali-metal': {
    bg: 'var(--ggui-color-error-100, #fee2e2)',
    text: 'var(--ggui-color-error-700, #b91c1c)',
    border: 'var(--ggui-color-error-200, #fecaca)',
  },
  'alkaline-earth-metal': {
    bg: 'var(--ggui-color-warning-100, #fef3c7)',
    text: 'var(--ggui-color-warning-700, #b45309)',
    border: 'var(--ggui-color-warning-200, #fde68a)',
  },
  'transition-metal': {
    bg: 'var(--ggui-color-primary-100, #e0f2fe)',
    text: 'var(--ggui-color-primary-700, #0369a1)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
  },
  'post-transition-metal': {
    bg: 'var(--ggui-color-info-100, #cffafe)',
    text: 'var(--ggui-color-info-700, #0e7490)',
    border: 'var(--ggui-color-info-200, #a5f3fc)',
  },
  'metalloid': {
    bg: 'var(--ggui-color-success-100, #dcfce7)',
    text: 'var(--ggui-color-success-700, #15803d)',
    border: 'var(--ggui-color-success-200, #bbf7d0)',
  },
  'nonmetal': {
    bg: 'var(--ggui-color-primary-50, #f0f9ff)',
    text: 'var(--ggui-color-primary-800, #075985)',
    border: 'var(--ggui-color-primary-300, #7dd3fc)',
  },
  'halogen': {
    bg: 'var(--ggui-color-warning-50, #fffbeb)',
    text: 'var(--ggui-color-warning-800, #92400e)',
    border: 'var(--ggui-color-warning-300, #fcd34d)',
  },
  'noble-gas': {
    bg: 'var(--ggui-color-container, #ede9fe)',
    text: 'var(--ggui-color-onContainer, #4c1d95)',
    border: 'var(--ggui-color-primary-400, #38bdf8)',
  },
  'lanthanide': {
    bg: 'var(--ggui-color-success-50, #f0fdf4)',
    text: 'var(--ggui-color-success-800, #166534)',
    border: 'var(--ggui-color-success-300, #86efac)',
  },
  'actinide': {
    bg: 'var(--ggui-color-error-50, #fef2f2)',
    text: 'var(--ggui-color-error-800, #991b1b)',
    border: 'var(--ggui-color-error-300, #fca5a5)',
  },
};

const defaultColors = {
  bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
  border: 'var(--ggui-color-outline, #d4d4d8)',
};

function getCategoryColors(category?: string) {
  if (!category) return defaultColors;
  return categoryColorMap[category] || defaultColors;
}

function formatCategoryLabel(category: string): string {
  return category
    .split('-')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const [hoveredElement, setHoveredElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!search.trim()) return elements;
    const query = search.toLowerCase().trim();
    return elements.filter(
      (el) =>
        (el.name && el.name.toLowerCase().includes(query)) ||
        (el.symbol && el.symbol.toLowerCase().includes(query))
    );
  }, [elements, search]);

  const filteredSet = useMemo(() => {
    return new Set(filteredElements.map((el) => el.atomicNumber));
  }, [filteredElements]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2} align="center">Periodic Table of Elements</Heading>
          <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Click an element to view its details. Search by name or symbol.
          </Text>
        </Stack>

        <Box padding={0}>
          <SearchField
            value={search}
            onChange={setSearch}
            placeholder="Search by name or symbol..."
            size="md"
          />
        </Box>

        {/* Periodic Table Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 3px)',
            overflowX: 'auto',
            minWidth: 0,
          }}
          role="grid"
          aria-label="Periodic Table of Elements"
        >
          {elements.map((el) => {
            if (!el.row || !el.col) return null;
            const colors = getCategoryColors(el.category);
            const isFiltered = search.trim() !== '' && !filteredSet.has(el.atomicNumber);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const isHovered = hoveredElement?.atomicNumber === el.atomicNumber;

            return (
              <div
                key={el.atomicNumber ?? `${el.row}-${el.col}`}
                role="gridcell"
                tabIndex={0}
                aria-label={`${el.name || 'Unknown'}, atomic number ${el.atomicNumber || 'unknown'}, ${el.category ? formatCategoryLabel(el.category) : 'unknown category'}`}
                onClick={() => setSelectedElement(el)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    setSelectedElement(el);
                  }
                }}
                onMouseEnter={() => setHoveredElement(el)}
                onMouseLeave={() => setHoveredElement(null)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: colors.bg,
                  border: `1.5px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : isHovered ? 'var(--ggui-color-primary-400, #38bdf8)' : colors.border}`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  padding: 'var(--ggui-spacing-1, 3px) var(--ggui-spacing-1, 4px)',
                  cursor: 'pointer',
                  position: 'relative',
                  minWidth: 0,
                  minHeight: 52,
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  opacity: isFiltered ? 0.2 : 1,
                  transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                  boxShadow: isSelected
                    ? '0 0 0 2px var(--ggui-color-primary-600, #0284c7)'
                    : isHovered
                    ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                    : 'none',
                  transform: isHovered && !isFiltered ? 'scale(1.08)' : 'scale(1)',
                  zIndex: isHovered ? 10 : 1,
                  outline: 'none',
                }}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: 2,
                    left: 3,
                    fontSize: 'var(--ggui-font-size-xs, 10px)',
                    lineHeight: 1,
                    color: colors.text,
                    fontWeight: 'var(--ggui-font-weight-normal, 400)' as unknown as number,
                    opacity: 0.8,
                  }}
                >
                  {el.atomicNumber}
                </span>
                <span
                  style={{
                    fontSize: 'var(--ggui-font-size-base, 16px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)' as unknown as number,
                    color: colors.text,
                    lineHeight: 1.2,
                    marginTop: 'var(--ggui-spacing-1, 6px)',
                  }}
                >
                  {el.symbol}
                </span>
                <span
                  style={{
                    fontSize: 'var(--ggui-font-size-xs, 8px)',
                    color: colors.text,
                    opacity: 0.7,
                    lineHeight: 1,
                    marginTop: 1,
                    textAlign: 'center',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap',
                    maxWidth: '100%',
                  }}
                >
                  {el.name}
                </span>
              </div>
            );
          })}
        </div>

        {/* Legend */}
        <Card padding={16} shadow="sm" radius="lg">
          <Stack gap={8}>
            <Text variant="label" weight="semibold">Legend</Text>
            <div
              style={{
                display: 'flex',
                flexWrap: 'wrap',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {categories.map((cat) => {
                const colors = getCategoryColors(cat);
                return (
                  <div
                    key={cat}
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-1, 4px)',
                      padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: colors.bg,
                      border: `1px solid ${colors.border}`,
                    }}
                  >
                    <span
                      style={{
                        width: 10,
                        height: 10,
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        backgroundColor: colors.text,
                        flexShrink: 0,
                      }}
                    />
                    <Text variant="caption" color={colors.text} as="span">
                      {formatCategoryLabel(cat)}
                    </Text>
                  </div>
                );
              })}
            </div>
          </Stack>
        </Card>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
            <Stack gap={16}>
              <Stack direction="horizontal" gap={16} align="center" justify="between">
                <Stack direction="horizontal" gap={12} align="center">
                  <div
                    style={{
                      width: 64,
                      height: 64,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      backgroundColor: getCategoryColors(selectedElement.category).bg,
                      border: `2px solid ${getCategoryColors(selectedElement.category).border}`,
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    }}
                  >
                    <span
                      style={{
                        fontSize: 'var(--ggui-font-size-2xl, 24px)',
                        fontWeight: 'var(--ggui-font-weight-bold, 700)' as unknown as number,
                        color: getCategoryColors(selectedElement.category).text,
                      }}
                    >
                      {selectedElement.symbol}
                    </span>
                  </div>
                  <Stack gap={2}>
                    <Heading level={3}>{selectedElement.name || 'Unknown'}</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Element {selectedElement.atomicNumber}
                    </Text>
                  </Stack>
                </Stack>
                <button
                  onClick={() => setSelectedElement(null)}
                  aria-label="Close detail panel"
                  style={{
                    background: 'none',
                    border: 'none',
                    cursor: 'pointer',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Icon name="x" size={20} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                </button>
              </Stack>

              <Divider margin={0} />

              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}
              >
                <Stack gap={2}>
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Symbol</Text>
                  <Text variant="bodyLarge" weight="semibold">{selectedElement.symbol || '—'}</Text>
                </Stack>
                <Stack gap={2}>
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                  <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicNumber ?? '—'}</Text>
                </Stack>
                <Stack gap={2}>
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {selectedElement.atomicWeight != null ? selectedElement.atomicWeight.toFixed(4) : '—'}
                  </Text>
                </Stack>
                <Stack gap={2}>
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                  <div>
                    <Badge
                      variant={
                        selectedElement.category?.includes('metal') ? 'primary' :
                        selectedElement.category === 'noble-gas' ? 'info' :
                        selectedElement.category === 'halogen' ? 'warning' :
                        selectedElement.category === 'nonmetal' ? 'secondary' :
                        selectedElement.category === 'metalloid' ? 'success' :
                        'default'
                      }
                      size="lg"
                    >
                      {selectedElement.category ? formatCategoryLabel(selectedElement.category) : '—'}
                    </Badge>
                  </div>
                </Stack>
              </div>
            </Stack>
          </Card>
        )}

        {/* Hover info bar */}
        {hoveredElement && !selectedElement && (
          <Box
            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack direction="horizontal" gap={16} align="center">
              <Text variant="label" weight="semibold" as="span">
                {hoveredElement.symbol}
              </Text>
              <Text variant="bodySmall" as="span">
                {hoveredElement.name}
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                #{hoveredElement.atomicNumber}
              </Text>
              {hoveredElement.category && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                  {formatCategoryLabel(hoveredElement.category)}
                </Text>
              )}
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Stack, Text, Heading, Button, Input, Badge, Spacer } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

function formatTimestamp(iso?: string): string {
  if (!iso) return '';
  try {
    const d = new Date(iso);
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

function groupMessages(msgs: Message[]): Array<{ sender: string; items: Message[] }> {
  const groups: Array<{ sender: string; items: Message[] }> = [];
  for (const msg of msgs) {
    const sender = msg.sender || 'Unknown';
    const last = groups[groups.length - 1];
    if (last && last.sender === sender) {
      last.items.push(msg);
    } else {
      groups.push({ sender, items: [msg] });
    }
  }
  return groups;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'Me',
    participantCount = 2,
    messages = [],
  } = props;

  const [allMessages, setAllMessages] = useState<Message[]>(messages);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setAllMessages(messages);
  }, [messages]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [allMessages]);

  // Stream Contract: ggui:agent-data listener for incoming messages
  useEffect(() => {
    const onAgentData = (event: Event) => {
      const ce = event as CustomEvent;
      if (ce.detail) {
        setAllMessages((prev) => [...prev, ce.detail as Message]);
      }
    };
    const w = typeof globalThis !== 'undefined' ? globalThis : null;
    if (w && 'addEventListener' in w) {
      (w as EventTarget).addEventListener('ggui:agent-data', onAgentData);
      return () => (w as EventTarget).removeEventListener('ggui:agent-data', onAgentData);
    }
  }, []);

  const fireAction = useCallback((action: string, payload: Record<string, unknown>) => {
    const w = typeof globalThis !== 'undefined' ? globalThis : null;
    if (w && 'dispatchEvent' in w) {
      (w as EventTarget).dispatchEvent(
        new CustomEvent('ggui:action', { detail: { action, payload } })
      );
    }
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const ts = new Date().toISOString();
    setAllMessages((prev) => [...prev, { sender: currentUser, text: trimmed, timestamp: ts }]);
    fireAction('sendMessage', { text: trimmed, timestamp: ts });
    setInputValue('');
  }, [inputValue, currentUser, fireAction]);

  const onKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  const grouped = groupMessages(allMessages);

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      height: '100%',
      minHeight: '400px',
      maxHeight: '700px',
      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      overflow: 'hidden',
      background: 'var(--ggui-color-surface, #fafafa)',
