      {/* Header */}
      <div style={{
        padding: 'var(--ggui-spacing-4, 16px)',
        borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        flexShrink: 0,
      }}>
        <Stack direction="horizontal" align="center" gap={12}>
          <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Heading>
          <Spacer size="flex" />
          <Badge variant="primary" size="sm" pill>
            {participantCount} participant{participantCount !== 1 ? 's' : ''}
          </Badge>
        </Stack>
      </div>

      {/* Messages */}
      <div
        role="log"
        aria-label="Chat messages"
        aria-live="polite"
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        {allMessages.length === 0 && (
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flex: 1 }}>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
              No messages yet. Start the conversation!
            </Text>
          </div>
        )}
        {grouped.map((group, gi) => {
          const own = group.sender === currentUser;
          return (
            <div key={`g-${gi}-${group.sender}`} style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: own ? 'flex-end' : 'flex-start',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}>
              <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                {group.sender}
              </Text>
              {group.items.map((msg, mi) => (
                <div key={`m-${gi}-${mi}`} style={{
                  maxWidth: '75%',
                  padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                  borderRadius: own
                    ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px)'
                    : 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px)',
                  background: own
                    ? 'var(--ggui-color-primary-600, #0284c7)'
                    : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  color: own
                    ? 'var(--ggui-color-neutral-50, #f9fafb)'
                    : 'var(--ggui-color-onSurface, #18181b)',
                  transition: 'background-color 200ms ease-in-out',
                }}>
                  <div style={{
                    fontSize: 'var(--ggui-font-size-sm, 14px)',
                    lineHeight: 1.5,
                    wordBreak: 'break-word',
                  }}>
                    {msg.text || ''}
                  </div>
                  <div style={{
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    marginTop: 'var(--ggui-spacing-1, 4px)',
                    opacity: 0.7,
                    textAlign: 'right',
                  }}>
                    {formatTimestamp(msg.timestamp)}
                  </div>
                </div>
              ))}
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Input area */}
      <div style={{
        padding: 'var(--ggui-spacing-4, 16px)',
        borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        flexShrink: 0,
      }}>
        <div
          style={{ display: 'flex', gap: 'var(--ggui-spacing-2, 8px)', alignItems: 'flex-end' }}
          onKeyDown={onKeyDown}
        >
          <div style={{ flex: 1 }}>
            <Input label="Message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} />
          </div>
          <Button
            variant="primary"
            size="md"
            disabled={inputValue.trim().length === 0}
            onClick={handleSend}
            aria-label="Send message"
            rightIcon={
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                <line x1="22" y1="2" x2="11" y2="13" />
                <polygon points="22 2 15 22 11 13 2 9 22 2" />
              </svg>
            }
          >
            Send
          </Button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Card, Text, Heading, Spinner, Badge, Divider } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface StockEntry {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks */
  stocks: StockEntry[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

function StockCard({ stock }: { stock: StockEntry }) {
  const change = stock.change ?? 0;
  const changePercent = stock.changePercent ?? 0;
  const isPositive = change >= 0;

  const changeColor = isPositive
    ? 'var(--ggui-color-success-600, #16a34a)'
    : 'var(--ggui-color-error-600, #dc2626)';

  const borderColor = isPositive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : 'var(--ggui-color-error-500, #ef4444)';

  const arrow = isPositive ? '▲' : '▼';

  const formattedPrice = (stock.price ?? 0).toFixed(2);
  const formattedChange = (change >= 0 ? '+' : '') + change.toFixed(2);
  const formattedPercent = (changePercent >= 0 ? '+' : '') + changePercent.toFixed(2) + '%';

  return (
    <Card padding={20} shadow="sm" radius="lg" border={false}>
      <div
        style={{
          borderLeft: `var(--ggui-spacing-1, 4px) solid ${borderColor}`,
          paddingLeft: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        <Stack gap={12}>
          <Stack direction="horizontal" align="center" justify="between">
            <Text as="span" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {stock.symbol ?? '---'}
            </Text>
            <Badge variant={isPositive ? 'success' : 'error'} size="sm" pill>
              <span style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                {arrow} {formattedPercent}
              </span>
            </Badge>
          </Stack>

          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
            {stock.name ?? 'Unknown Company'}
          </Text>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack direction="horizontal" align="end" justify="between">
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Price
              </Text>
              <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" as="span">
                ${formattedPrice}
              </Text>
            </Stack>
            <Stack gap={2} align="end">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Change
              </Text>
              <Text as="span" weight="semibold" variant="bodySmall" color={changeColor}>
                {formattedChange}
              </Text>
            </Stack>
          </Stack>
        </Stack>
      </div>
    </Card>
  );
}

function formatTimestamp(iso?: string): string {
  if (!iso) return 'N/A';
  try {
    const date = new Date(iso);
    return date.toLocaleString(undefined, {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  } catch {
    return iso;
  }
}

function getEventTarget(): EventTarget | null {
  if (typeof globalThis !== 'undefined') return globalThis as unknown as EventTarget;
  return null;
}

export default function GeneratedComponent(props: Props) {
  const {
    stocks: initialStocks = [],
    lastUpdated: initialLastUpdated,
  } = props;

  const [stocks, setStocks] = useState<StockEntry[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'idle'>('connecting');

  useEffect(() => {
    setStocks(initialStocks);
  }, [initialStocks]);

  useEffect(() => {
    setLastUpdated(initialLastUpdated);
  }, [initialLastUpdated]);

  // Stream Contract: listen for ggui:agent-data events
  useEffect(() => {
    const target = getEventTarget();
    if (!target) return;

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data) {
        if (data.stocks && Array.isArray(data.stocks)) {
          setStocks(data.stocks);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
        setConnectionStatus('connected');
      }
    };

    const timeout = setTimeout(() => {
      setConnectionStatus((prev) => (prev === 'connecting' ? 'idle' : prev));
    }, 3000);

    target.addEventListener('ggui:agent-data', handleAgentData);

    return () => {
      target.removeEventListener('ggui:agent-data', handleAgentData);
      clearTimeout(timeout);
    };
  }, []);

  const isLoading = stocks.length === 0 && connectionStatus === 'connecting';

  const statusBadgeVariant = connectionStatus === 'connected'
    ? 'success'
    : connectionStatus === 'connecting'
    ? 'warning'
    : 'default';

  const statusLabel = connectionStatus === 'connected'
    ? 'Live'
    : connectionStatus === 'connecting'
    ? 'Connecting…'
    : 'Idle';

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Header */}
        <Card padding={24} shadow="md" radius="lg" border={false}>
          <Stack direction="horizontal" align="center" justify="between" wrap>
            <Stack direction="horizontal" align="center" gap={12}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>
              <Badge variant={statusBadgeVariant} size="sm" pill>
                {statusLabel}
              </Badge>
            </Stack>

            <Stack direction="horizontal" align="center" gap={8}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                Last Updated:
              </Text>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface, #18181b)" as="span">
                {formatTimestamp(lastUpdated)}
              </Text>
            </Stack>
          </Stack>
        </Card>

        {/* Loading State */}
        {isLoading && (
          <Card padding={48} shadow="sm" radius="lg">
            <Stack align="center" gap={16}>
              <Spinner size={36} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                Connecting to market data stream…
              </Text>
            </Stack>
          </Card>
        )}

        {/* Empty state */}
        {!isLoading && stocks.length === 0 && (
          <Card padding={48} shadow="sm" radius="lg">
            <Stack align="center" gap={12}>
              <Text size="2xl" as="span" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                📊
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                No stock data available. Waiting for market data…
              </Text>
            </Stack>
          </Card>
        )}

        {/* Stock Cards Grid */}
        {stocks.length > 0 && (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={20}>
            {stocks.map((stock, index) => (
              <StockCard key={stock.symbol ?? `stock-${index}`} stock={stock} />
            ))}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useCallback, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Box,
  Divider,
  Badge,
  Spacer,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface InitialProfile {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  emailNotifications?: boolean;
  theme?: string;
}

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: InitialProfile;
  onComplete?: (data: ProfileData) => void;
}

const STEP_LABELS = ['Profile Setup', 'Preferences', 'Review & Confirm'];

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

export default function GeneratedComponent(props: Props) {
  const initialProfile = props.initialProfile ?? {};
  const avatarOptions = props.avatarOptions;
  const roleOptions = props.roleOptions;
  const onComplete = props.onComplete;

  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(0);
  const [animDir, setAnimDir] = useState<'forward' | 'back'>('forward');

  const [name, setName] = useState(initialProfile.name ?? '');
  const [email, setEmail] = useState(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(
    initialProfile.avatar ?? (avatarOptions.length > 0 ? avatarOptions[0] : '')
  );

  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);

  const [role, setRole] = useState(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(initialProfile.theme ?? 'light');

  const nameError = nameTouched && !name.trim() ? 'Name is required' : undefined;
  const emailError = emailTouched
    ? !email.trim()
      ? 'Email is required'
      : !isValidEmail(email)
        ? 'Please enter a valid email address'
        : undefined
    : undefined;

  const step1Valid =
    name.trim().length > 0 &&
    email.trim().length > 0 &&
    isValidEmail(email) &&
    avatar.length > 0;

  const canProceed = currentStep === 0 ? step1Valid : true;
  const progressValue = ((currentStep + 1) / STEP_LABELS.length) * 100;

  const handleNext = useCallback(() => {
    if (currentStep === 0) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!step1Valid) return;
    }
    if (currentStep < STEP_LABELS.length - 1) {
      setAnimDir('forward');
      setCurrentStep((s) => s + 1);
    }
  }, [currentStep, step1Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 0) {
      setAnimDir('back');
      setCurrentStep((s) => s - 1);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    const data: ProfileData = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    onComplete?.(data);
  }, [name, email, avatar, role, emailNotifications, theme, onComplete]);

  const roleSelectOptions = useMemo(
    () => roleOptions.map((r) => ({ value: r, label: r })),
    [roleOptions]
  );

  const animStyle: React.CSSProperties = motionEnabled
    ? {
        animation:
          animDir === 'forward'
            ? 'ggui-slideInUp 300ms cubic-bezier(0, 0, 0.2, 1) both'
            : 'ggui-fadeIn 250ms cubic-bezier(0, 0, 0.2, 1) both',
      }
    : {};

  const selectedBtnStyle = (isSelected: boolean): React.CSSProperties => ({
    flex: 1,
    padding: 'var(--ggui-spacing-4, 16px)',
    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
    border: isSelected
      ? '2px solid var(--ggui-color-primary-600, #0284c7)'
      : '2px solid var(--ggui-color-outline, #d4d4d8)',
    background: isSelected
      ? 'var(--ggui-color-primary-50, #f0f9ff)'
      : 'var(--ggui-color-surface, #fafafa)',
    cursor: 'pointer',
    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
    display: 'flex',
    flexDirection: 'column' as const,
    alignItems: 'center',
    gap: 'var(--ggui-spacing-2, 8px)',
  });

  const avatarBtnStyle = (isSelected: boolean): React.CSSProperties => ({
    width: 56,
    height: 56,
    fontSize: 28,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
    border: isSelected
      ? '2px solid var(--ggui-color-primary-600, #0284c7)'
      : '2px solid var(--ggui-color-outline, #d4d4d8)',
    background: isSelected
      ? 'var(--ggui-color-primary-50, #f0f9ff)'
      : 'var(--ggui-color-surface, #fafafa)',
    cursor: 'pointer',
    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
    transform: isSelected ? 'scale(1.1)' : 'scale(1)',
    boxShadow: isSelected
      ? '0 0 0 3px var(--ggui-color-primary-200, #bae6fd)'
      : 'none',
    padding: 0,
  });

  const renderStep1 = () => (
    <Stack gap={20}>
      <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={(v: string) => { setName(v); if (!nameTouched) setNameTouched(true); }} error={nameError} required />
      <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={(v: string) => { setEmail(v); if (!emailTouched) setEmailTouched(true); }} error={emailError} required />
      <Stack gap={8}>
        <Text variant="label" as="label">Choose your avatar</Text>
        <Stack direction="horizontal" gap={12} wrap>
          {avatarOptions.map((opt) => (
            <button
              key={opt}
              type="button"
              onClick={() => setAvatar(opt)}
              aria-label={`Select avatar ${opt}`}
              aria-pressed={avatar === opt}
              style={avatarBtnStyle(avatar === opt)}
            >
              {opt}
            </button>
          ))}
        </Stack>
      </Stack>
    </Stack>
  );

  const renderStep2 = () => (
    <Stack gap={20}>
      <Select
        label="Role"
        value={role}
        onChange={setRole}
        options={roleSelectOptions}
        placeholder="Select your role"
      />
      <Divider margin={4} />
      <Toggle
        label="Email notifications"
        checked={emailNotifications}
        onChange={setEmailNotifications}
      />
      <Divider margin={4} />
      <Stack gap={8}>
        <Text variant="label" as="label">Theme preference</Text>
        <Stack direction="horizontal" gap={12} align="center">
          <button
            type="button"
            onClick={() => setTheme('light')}
            aria-label="Select light theme"
            aria-pressed={theme === 'light'}
            style={selectedBtnStyle(theme === 'light')}
          >
            <span style={{ fontSize: 24 }}>☀️</span>
            <Text variant="bodySmall" weight={theme === 'light' ? 'semibold' : 'normal'} color={theme === 'light' ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'} as="span">Light</Text>
          </button>
          <button
            type="button"
            onClick={() => setTheme('dark')}
            aria-label="Select dark theme"
            aria-pressed={theme === 'dark'}
            style={selectedBtnStyle(theme === 'dark')}
          >
            <span style={{ fontSize: 24 }}>🌙</span>
            <Text variant="bodySmall" weight={theme === 'dark' ? 'semibold' : 'normal'} color={theme === 'dark' ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'} as="span">Dark</Text>
          </button>
        </Stack>
      </Stack>
    </Stack>
  );

  const renderStep3 = () => (
    <Stack gap={16}>
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        Please review your settings before completing setup.
      </Text>

      <Card padding={16} shadow="none" border radius="md">
        <Stack gap={12}>
          <Text variant="overline">Profile</Text>
          <Stack direction="horizontal" align="center" gap={16}>
            <div
              style={{
                width: 48,
                height: 48,
                fontSize: 28,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                background: 'var(--ggui-color-primary-50, #f0f9ff)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                flexShrink: 0,
              }}
              aria-hidden="true"
            >
              {avatar}
            </div>
            <Stack gap={2}>
              <Text variant="body" weight="semibold">{name}</Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{email}</Text>
            </Stack>
          </Stack>
        </Stack>
      </Card>

      <Card padding={16} shadow="none" border radius="md">
        <Stack gap={12}>
          <Text variant="overline">Preferences</Text>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
              <Text variant="bodySmall" weight="medium">{role || 'Not selected'}</Text>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
              <Badge variant={emailNotifications ? 'success' : 'default'} size="sm">
                {emailNotifications ? 'On' : 'Off'}
              </Badge>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
              <Stack direction="horizontal" align="center" gap={4}>
                <Text as="span" variant="bodySmall">{theme === 'light' ? '☀️' : '🌙'}</Text>
                <Text variant="bodySmall" weight="medium" as="span">{theme === 'light' ? 'Light' : 'Dark'}</Text>
              </Stack>
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <>
      <MotionKeyframes />
      <Card shadow="md" padding={0} radius="xl">
        <Stack gap={0}>
          <Box
            padding="var(--ggui-spacing-6, 24px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px) 0 0"
          >
            <Stack gap={16}>
              <Stack direction="horizontal" align="center" justify="between">
                <Heading level={4}>{STEP_LABELS[currentStep]}</Heading>
                <Badge variant="primary" size="md">
                  Step {currentStep + 1} of {STEP_LABELS.length}
                </Badge>
              </Stack>
              <Stack gap={8}>
                <Progress value={progressValue} size="sm" />
                <Stack direction="horizontal" justify="between">
                  {STEP_LABELS.map((stepLabel, i) => (
                    <Text
                      key={stepLabel}
                      variant="caption"
                      weight={i === currentStep ? 'semibold' : 'normal'}
                      color={
                        i < currentStep
                          ? 'var(--ggui-color-success-600, #16a34a)'
                          : i === currentStep
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      as="span"
                    >
                      {i < currentStep ? '✓ ' : ''}{stepLabel}
                    </Text>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          </Box>

          <Box padding="var(--ggui-spacing-6, 24px)">
            <div key={currentStep} style={animStyle}>
              {currentStep === 0 && renderStep1()}
              {currentStep === 1 && renderStep2()}
              {currentStep === 2 && renderStep3()}
            </div>
          </Box>

          <Divider margin={0} />
          <Box padding="var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)">
            <Stack direction="horizontal" justify="between" align="center">
              {currentStep > 0 ? (
                <Button variant="ghost" onClick={handleBack} aria-label="Go back to previous step">
                  ← Go Back
                </Button>
              ) : (
                <Spacer size={1} />
              )}
              {currentStep < STEP_LABELS.length - 1 ? (
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={!canProceed}
                  aria-label={`Continue to ${STEP_LABELS[currentStep + 1]}`}
                >
                  Next →
                </Button>
              ) : (
                <Button variant="primary" onClick={handleComplete} aria-label="Complete onboarding setup">
                  Complete Setup ✓
                </Button>
              )}
            </Stack>
          </Box>
        </Stack>
      </Card>
    </>
  );
}

