import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Button, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onSubmit?: (payload: { title: string; priority: 'low' | 'medium' | 'high' }) => Promise<unknown> | unknown;
}

type Task = { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };

export default function GeneratedComponent({
  tasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  taskUpdate = () => undefined,
  onSubmit = async () => undefined,
}: Props) {
  const normalized = useMemo<Task[]>(
    () =>
      tasks.map((t, i) => ({
        id: t.id || `task-${i + 1}`,
        title: t.title || `Task ${i + 1}`,
        priority: t.priority || 'medium',
        assignee: t.assignee || '--',
        column: t.column || 'todo',
        dueDate: t.dueDate,
      })),
    [tasks]
  );

  const [boardTasks, setBoardTasks] = useState<Task[]>(normalized);
  const [addOpen, setAddOpen] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState<string>('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [formError, setFormError] = useState<string>('');
  const [formSuccess, setFormSuccess] = useState<string>('');
  const [submitting, setSubmitting] = useState<boolean>(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  const totalTasks = boardTasks.length;
  const completedCount = boardTasks.filter((t) => t.column === 'done').length;

  const priorityColor = (p: Task['priority']) =>
    p === 'high'
      ? 'var(--ggui-color-error-600, #dc2626)'
      : p === 'medium'
      ? 'var(--ggui-color-warning-600, #d97706)'
      : 'var(--ggui-color-success-600, #16a34a)';

  const moveTask = (taskId: string, colId: string) => {
    setBoardTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: colId } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: colId } });
  };

  const saveEdit = (taskId: string) => {
    const value = editValue.trim();
    if (!value) return;
    setBoardTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: value } : t)));
    taskUpdate({ action: 'edit', taskId, data: { title: value } });
    setEditingId(null);
    setEditValue('');
  };

  const addTask = async (columnId: string) => {
    setFormError('');
    setFormSuccess('');
    if (!newTitle.trim()) {
      setFormError('Title is required');
      return;
    }
    try {
      setSubmitting(true);
      await onSubmit({ title: newTitle.trim(), priority: newPriority });
      const newTask: Task = {
        id: `task-${Date.now()}`,
        title: newTitle.trim(),
        priority: newPriority,
        assignee: '--',
        column: 'todo',
      };
      setBoardTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: newTask });
      setFormSuccess('Task created successfully');
      setNewTitle('');
      setNewPriority('medium');
      setAddOpen(null);
    } catch {
      setFormError('Failed to create task');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Stack gap="var(--ggui-spacing-4, 16px)">
      <Card
        padding="var(--ggui-spacing-4, 16px)"
        shadow="sm"
        border
        radius="lg"
      >
        <Stack direction="horizontal" justify="between" align="center">
          <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            Total Tasks: {totalTasks}
          </Text>
          <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Completed: {completedCount}
          </Text>
        </Stack>
      </Card>

      <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
        {columns.map((col) => {
          const colId = col.id || '';
          const items = boardTasks.filter((t) => t.column === colId);
          return (
            <Card
              key={colId}
              padding="var(--ggui-spacing-4, 16px)"
              shadow="sm"
              border
              radius="lg"
            >
              <Stack gap="var(--ggui-spacing-3, 12px)">
                <Stack direction="horizontal" justify="between" align="center">
                  <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {col.name || 'Column'}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {items.length}
                  </Text>
                </Stack>

                <Stack gap="var(--ggui-spacing-2, 8px)">
                  {items.map((task) => (
                    <Card key={task.id} padding="var(--ggui-spacing-3, 12px)" shadow="none" border radius="md">
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        {editingId === task.id ? (
                          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                            <Input
                              label="Edit title"
                              value={editValue}
                              onChange={setEditValue}
                              placeholder="Task title"
                            />
                            <Button size="sm" onClick={() => saveEdit(task.id)} aria-label="Save title">
                              Save
                            </Button>
                          </Stack>
                        ) : (
                          <Stack direction="horizontal" justify="between" align="center">
                            <Text
                              weight="medium"
                              onDoubleClick={() => {
                                setEditingId(task.id);
                                setEditValue(task.title);
                              }}
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {task.title}
                            </Text>
                            <Button
                              size="xs"
                              variant="ghost"
                              onClick={() => {
                                setEditingId(task.id);
                                setEditValue(task.title);
                              }}
                              aria-label={`Edit ${task.title}`}
                            >
                              Edit
                            </Button>
                          </Stack>
                        )}

                        <Text
                          variant="caption"
                          color={priorityColor(task.priority)}
                        >
                          {task.priority.toUpperCase()}
                        </Text>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Card
                            padding="var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)"
                            border
                            radius="full"
                            shadow="none"
                          >
                            <Text variant="caption">{task.assignee}</Text>
                          </Card>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                          </Text>
                        </Stack>

                        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                          {columns
                            .filter((c) => c.id && c.id !== task.column)
                            .map((target) => (
                              <Button
                                key={`${task.id}-${target.id}`}
                                size="xs"
                                variant="outline"
                                onClick={() => moveTask(task.id, target.id || '')}
                                aria-label={`Move ${task.title} to ${target.name}`}
                              >
                                Move to {target.name}
                              </Button>
                            ))}
                        </Stack>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addOpen === colId ? (
                  <Card padding="var(--ggui-spacing-3, 12px)" border radius="md" shadow="none">
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Input
                        label="Task Title"
                        value={newTitle}
                        onChange={setNewTitle}
                        placeholder="Enter task title"
                        required
                        error={formError}
                        disabled={submitting}
                      />
                      <Input
                        label="Priority (low/medium/high)"
                        value={newPriority}
                        onChange={(v) => {
                          const val = (v || '').toLowerCase();
                          if (val === 'low' || val === 'medium' || val === 'high') {
                            setNewPriority(val);
                          }
                        }}
                        helperText="Type low, medium, or high"
                        disabled={submitting}
                      />
                      {formSuccess ? (
                        <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">
                          {formSuccess}
                        </Text>
                      ) : null}
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                        <Button
                          variant="primary"
                          size="sm"
                          loading={submitting}
                          disabled={submitting}
                          onClick={() => addTask(colId)}
                          aria-label="Submit new task"
                        >
                          Submit
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => {
                            setAddOpen(null);
                            setFormError('');
                            setFormSuccess('');
                          }}
                          disabled={submitting}
                        >
                          Cancel
                        </Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : null}

                <Button
                  variant="secondary"
                  size="sm"
                  onClick={() => {
                    setAddOpen(colId);
                    setFormError('');
                    setFormSuccess('');
                  }}
                  aria-label={`Add task in ${col.name}`}
                >
                  Add Task
                </Button>
              </Stack>
            </Card>
          );
        })}
      </Stack>
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedIndex, setSelectedIndex] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add((el.category ?? 'unknown').toLowerCase()));
    return Array.from(set);
  }, [elements]);

  const selectedElement =
    selectedIndex !== null ? filteredElements[selectedIndex] : undefined;

  return (
    <Card
      padding={16}
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol"
          aria-label="Search elements by name or symbol"
        />

        <div
          role="grid"
          aria-label="Periodic table grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surface, #fafafa)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            padding: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {filteredElements.map((el, index) => {
            const category = (el.category ?? 'unknown').toLowerCase();
            const cellColor =
              categoryColorMap[category] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
            const isSelected = selectedIndex === index;

            return (
              <Button
                key={`${el.atomicNumber ?? index}-${el.symbol ?? 'x'}`}
                variant="ghost"
                size="sm"
                onClick={() => setSelectedIndex(index)}
                aria-label={`Select element ${el.name ?? 'unknown'} (${el.symbol ?? ''})`}
                style={{
                  gridColumn: `${el.col ?? 1}`,
                  gridRow: `${el.row ?? 1}`,
                  minHeight: 56,
                  position: 'relative',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  border: `1px solid ${
                    isSelected
                      ? 'var(--ggui-color-onSurface, #18181b)'
                      : 'var(--ggui-color-outline, #d4d4d8)'
                  }`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  color: 'var(--ggui-color-onSurface, #18181b)',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
                  transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                  outline: `2px solid transparent`,
                  outlineOffset: '2px',
                }}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: 4,
                    left: 6,
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    lineHeight: 1,
                  }}
                >
                  {el.atomicNumber ?? ''}
                </span>
                <span
                  style={{
                    fontSize: 'var(--ggui-font-size-lg, 18px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: cellColor,
                    textAlign: 'center',
                    width: '100%',
                    lineHeight: 1.1,
                  }}
                >
                  {el.symbol ?? '?'}
                </span>
              </Button>
            );
          })}
        </div>

        <Card
          padding={12}
          shadow="none"
          border
          radius="md"
        >
          <Stack gap={6}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Name:</strong> {selectedElement.name ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Symbol:</strong> {selectedElement.symbol ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Category:</strong> {selectedElement.category ?? '—'}
                </Text>
              </>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding={12} shadow="none" border radius="md">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((cat) => {
                const color =
                  categoryColorMap[cat] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
                return (
                  <Stack
                    key={cat}
                    direction="horizontal"
                    align="center"
                    gap={6}
                    style={{
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      padding: '4px 8px',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <span
                      aria-hidden="true"
                      style={{
                        width: 10,
                        height: 10,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: color,
                        display: 'inline-block',
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                      {cat}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const messageListRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, [allMessages]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{
        message?: { sender?: string; text?: string; timestamp?: string };
      }>;
      const incoming = customEvent?.detail?.message;
      if (incoming) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  const formatTimestamp = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Card
      padding={0}
      radius="lg"
      border
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
        minHeight: '420px',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        gap={8}
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
          {title}
        </Text>
        <Badge variant="primary" size="sm" pill>
          {participantCount}
        </Badge>
      </Stack>

      <Stack
        ref={messageListRef as unknown as React.RefObject<HTMLDivElement>}
        gap={12}
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          background: 'var(--ggui-color-surface, #fafafa)',
        }}
        aria-label="Message list"
      >
        {groupedMessages.map((group, groupIndex) => {
          const isOwnGroup = (group.sender || '') === currentUser;
          return (
            <Stack
              key={`${group.sender || 'unknown'}-${groupIndex}`}
              align={isOwnGroup ? 'end' : 'start'}
              gap={6}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align={isOwnGroup ? 'right' : 'left'}
              >
                {group.sender || 'Unknown'}
              </Text>

              <Stack align={isOwnGroup ? 'end' : 'start'} gap={6}>
                {group.items.map((item, itemIndex) => (
                  <Card
                    key={`${groupIndex}-${itemIndex}-${item.timestamp || ''}`}
                    padding="10px 12px"
                    radius="md"
                    border
                    shadow="none"
                    style={{
                      maxWidth: '78%',
                      background: isOwnGroup
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderColor: isOwnGroup
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                    }}
                  >
                    <Stack gap={4}>
                      <Text
                        variant="bodySmall"
                        color={
                          isOwnGroup
                            ? 'var(--ggui-color-surface, #fafafa)'
                            : 'var(--ggui-color-onSurface, #18181b)'
                        }
                      >
                        {item.text || ''}
                      </Text>
                      <Text
                        variant="caption"
                        align="right"
                        color={
                          isOwnGroup
                            ? 'var(--ggui-color-surface, #fafafa)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                        }
                      >
                        {formatTimestamp(item.timestamp)}
                      </Text>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            </Stack>
          );
        })}
      </Stack>

      <Stack
        direction="horizontal"
        gap={8}
        align="end"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          background: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <div style={{ flex: 1 }}>
          <Input
            label="Message"
            placeholder="Type a message..."
            value={draft}
            onChange={setDraft}
            aria-label="Compose message"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
          />
        </div>
        <Button
          variant="primary"
          size="md"
          onClick={handleSend}
          disabled={!draft.trim()}
          aria-label="Send message"
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string>(lastUpdated || '');
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(stocks.length === 0);

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated || '');
    setIsLoading(stocks.length === 0);
  }, [stocks, lastUpdated]);

  // Stream Contract: listen for agent data updates
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
        loading?: boolean;
      }>;

      const payload = customEvent.detail || {};
      setIsConnecting(false);

      if (typeof payload.loading === 'boolean') {
        setIsLoading(payload.loading);
      }

      if (Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
        setIsLoading(false);
      }

      if (typeof payload.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    const timer = window.setTimeout(() => setIsConnecting(false), 1500);

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData);
      window.clearTimeout(timer);
    };
  }, []);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack
      gap={16}
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Stack direction="horizontal" justify="between" align="center" wrap>
        <Text
          as="div"
          size="2xl"
          weight="bold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          Market Watch
        </Text>
        <Text
          variant="bodySmall"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          aria-live="polite"
        >
          Last Updated: {formattedLastUpdated}
        </Text>
      </Stack>

      {isConnecting && (
        <Card
          padding={16}
          border
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack direction="horizontal" gap={8} align="center">
            <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Connecting to live market feed...
            </Text>
          </Stack>
        </Card>
      )}

      {isLoading ? (
        <Card
          padding={20}
          border
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack align="center" gap={10}>
            <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Loading stock prices...
            </Text>
          </Stack>
        </Card>
      ) : (
        <div
          aria-label="Stock ticker grid"
          style={{
            display: 'grid',
            gap: 'var(--ggui-spacing-4, 16px)',
            gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
          }}
        >
          {liveStocks.map((stock, index) => {
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const positive = change >= 0;
            const trendColor = positive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = positive ? '▲' : '▼';

            return (
              <Card
                key={`${stock.symbol || 'stock'}-${index}`}
                padding={16}
                radius="lg"
                border
                shadow="sm"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: trendColor,
                  transition:
                    'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                }}
              >
                <Stack gap={8}>
                  <Text
                    as="div"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    aria-label={`Ticker symbol ${stock.symbol || 'N/A'}`}
                  >
                    {stock.symbol || '—'}
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    truncate
                  >
                    {stock.name || 'Unknown Company'}
                  </Text>
                  <Text
                    as="div"
                    size="xl"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" color={trendColor}>
                      {change >= 0 ? '+' : ''}
                      {change.toFixed(2)}
                    </Text>
                    <Text variant="label" color={trendColor} aria-live="polite">
                      {arrow} {changePercent >= 0 ? '+' : ''}
                      {changePercent.toFixed(2)}%
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      )}
    </Stack>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  MotionKeyframes,
  useMotion,
  Container,
  Card,
  Stack,
  Box,
  Heading,
  Text,
  Progress,
  Input,
  Select,
  Toggle,
  Button,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action Contract: called on final completion with collected data */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? false
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean; role: boolean }>({
    name: false,
    email: false,
    role: false,
  });
  const [submitAttempted, setSubmitAttempted] = useState<{ step1: boolean; step2: boolean }>({
    step1: false,
    step2: false,
  });

  useEffect(() => {
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(props.initialProfile?.avatar ?? props.avatarOptions[0] ?? '');
    setRole(props.initialProfile?.role ?? '');
    setEmailNotifications(props.initialProfile?.emailNotifications ?? false);
    setTheme(props.initialProfile?.theme ?? 'light');
  }, [props.initialProfile, props.avatarOptions]);

  useEffect(() => {
    if (avatar && !props.avatarOptions.includes(avatar)) {
      setAvatar(props.avatarOptions[0] ?? '');
    }
  }, [props.avatarOptions, avatar]);

  useEffect(() => {
    if (role && !props.roleOptions.includes(role)) {
      setRole('');
    }
  }, [props.roleOptions, role]);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailFormatValid = emailRegex.test(email.trim());
  const avatarValid = avatar.trim().length > 0 && props.avatarOptions.includes(avatar);
  const roleValid = role.trim().length > 0 && props.roleOptions.includes(role);
  const themeValid = theme === 'light' || theme === 'dark';

  const nameError =
    (touched.name || submitAttempted.step1) && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError =
    (touched.email || submitAttempted.step1) && email.trim().length === 0
      ? 'Email is required.'
      : (touched.email || submitAttempted.step1) && !isEmailFormatValid
      ? 'Please enter a valid email address.'
      : '';

  const roleError =
    (touched.role || submitAttempted.step2) && !roleValid ? 'Role is required.' : '';

  const isStep1Valid = name.trim().length > 0 && isEmailFormatValid && avatarValid;
  const isStep2Valid = roleValid && themeValid;
  const isAllValid = isStep1Valid && isStep2Valid;

  const progressValue = (currentStep / 3) * 100;

  const roleSelectOptions = useMemo(
    () => props.roleOptions.map((r) => ({ value: r, label: r })),
    [props.roleOptions]
  );

  const stepAnimationStyle = motionEnabled
    ? { animation: 'ggui-slideInUp 200ms ease-out' }
    : undefined;

  const goNext = () => {
    if (currentStep === 1) {
      setSubmitAttempted((prev) => ({ ...prev, step1: true }));
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!isStep1Valid) return;
      setCurrentStep(2);
      return;
    }
    if (currentStep === 2) {
      setSubmitAttempted((prev) => ({ ...prev, step2: true }));
      setTouched((prev) => ({ ...prev, role: true }));
      if (!isStep2Valid) return;
      setCurrentStep(3);
    }
  };

  const goBack = () => {
    setCurrentStep((prev) => Math.max(1, prev - 1));
  };

  const handleComplete = () => {
    if (!isAllValid) return;
    props.onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Box
      background="var(--ggui-color-surface, #fafafa)"
      padding="var(--ggui-spacing-6, 24px)"
      style={{ minHeight: '100%' }}
    >
      <MotionKeyframes />
      <Container maxWidth="md" padding="var(--ggui-spacing-2, 8px)">
        <Card padding={24} shadow="md" radius="lg" border>
          <Stack gap={20}>
            <Stack gap={8}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Onboarding Wizard
              </Heading>
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                as="div"
                aria-live="polite"
              >
                Step {currentStep} of 3
              </Text>
              <Progress value={progressValue} max={100} size="md" variant="default" showLabel={false} />
            </Stack>

            {currentStep === 1 && (
              <Box style={stepAnimationStyle}>
                <Stack gap={12}>
                  <Input
                    size="md"
                    label="Name"
                    required
                    value={name}
                    onChange={setName}
                    onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                    error={nameError || undefined}
                    aria-label="Name"
                  />
                  <Input
                    size="md"
                    label="Email"
                    type="email"
                    required
                    value={email}
                    onChange={setEmail}
                    onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                    error={emailError || undefined}
                    aria-label="Email"
                  />
                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      Avatar
                    </Text>
                    <Stack direction="horizontal" wrap gap={8}>
                      {props.avatarOptions.map((emoji) => (
                        <Button
                          key={emoji}
                          size="md"
                          variant={avatar === emoji ? 'primary' : 'outline'}
                          onClick={() => setAvatar(emoji)}
                          aria-label={`Select avatar ${emoji}`}
                        >
                          {emoji}
                        </Button>
                      ))}
                    </Stack>
                    {props.avatarOptions.length === 0 && (
                      <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">
                        No avatar options available.
                      </Text>
                    )}
                    {submitAttempted.step1 && !avatarValid && props.avatarOptions.length > 0 && (
                      <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">
                        Please select an avatar.
                      </Text>
                    )}
                  </Stack>
                </Stack>
              </Box>
            )}

            {currentStep === 2 && (
              <Box style={stepAnimationStyle}>
                <Stack gap={12}>
                  <Select
                    size="md"
                    label="Role"
                    required
                    placeholder="Select a role"
                    value={role}
                    onChange={setRole}
                    onBlur={() => setTouched((prev) => ({ ...prev, role: true }))}
                    options={roleSelectOptions}
                    error={roleError || undefined}
                    helperText={props.roleOptions.length === 0 ? 'No roles available.' : undefined}
                    aria-label="Role"
                  />
                  <Toggle
                    size="md"
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Toggle
                    size="md"
                    label="Dark theme"
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              </Box>
            )}

            {currentStep === 3 && (
              <Box style={stepAnimationStyle}>
                <Stack gap={12}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                    Review & Confirm
                  </Heading>
                  <Card
                    padding="var(--ggui-spacing-4, 16px)"
                    shadow="none"
                    radius="md"
                    border
                    style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
                  >
                    <Stack gap={10}>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{name || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{email || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{avatar || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{role || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Email Notifications
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                          {emailNotifications ? 'On' : 'Off'}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                          {theme === 'dark' ? 'Dark' : 'Light'}
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>

                  <Stack direction="horizontal" justify="between" align="center">
                    <Button variant="ghost" size="md" onClick={() => setCurrentStep(2)}>
                      Go Back
                    </Button>
                    <Button
                      variant="primary"
                      size="md"
                      onClick={handleComplete}
                      disabled={!isAllValid}
                      aria-label="Complete Setup and submit onboarding profile"
                    >
                      Complete Setup
                    </Button>
                  </Stack>
                </Stack>
              </Box>
            )}

            {currentStep < 3 && (
              <>
                <Divider color="var(--ggui-color-outline, #d4d4d8)" margin={0} />
                <Stack direction="horizontal" justify="between" align="center">
                  <Button variant="ghost" size="md" onClick={goBack} disabled={currentStep === 1}>
                    Back
                  </Button>
                  <Button
                    variant="primary"
                    size="md"
                    onClick={goNext}
                    disabled={(currentStep === 1 && !isStep1Valid) || (currentStep === 2 && !isStep2Valid)}
                  >
                    Next
                  </Button>
                </Stack>
              </>
            )}
          </Stack>
        </Card>
      </Container>
    </Box>
  );
}

export const __GGUI_META__ = {
  category: 'Forms',
  description:
    'A reusable, accessible 3-step onboarding wizard with profile setup, preferences, validation, progress indicator, animated step transitions, and final completion callback.',
};

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
