import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Alert,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks?: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns?: Array<{ id?: string; name?: string }>;
  /** Action Contract: Task Updated */
  taskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  /** Interaction submit callback */
  onSubmit?: (payload: { title: string; priority: 'low' | 'medium' | 'high'; column: string }) => Promise<void> | void;
}

type TaskItem = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

const priorityOptions = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

export default function GeneratedComponent(props: Props) {
  const columns = props.columns ?? [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ];

  const [localTasks, setLocalTasks] = useState<TaskItem[]>(
    (props.tasks ?? []).map((t, idx) => ({
      id: t.id ?? `task-${idx + 1}`,
      title: t.title ?? `Untitled Task ${idx + 1}`,
      priority: t.priority ?? 'medium',
      assignee: t.assignee ?? 'NA',
      column: t.column ?? (columns[0]?.id ?? 'todo'),
      dueDate: t.dueDate,
    }))
  );

  const [addingColumn, setAddingColumn] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newError, setNewError] = useState('');
  const [submitState, setSubmitState] = useState<{ loading: boolean; success: string; error: string }>({
    loading: false,
    success: '',
    error: '',
  });

  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [editError, setEditError] = useState('');

  const totalTasks = localTasks.length;
  const completedCount = localTasks.filter((t) => {
    const doneColumn = columns.find((c) => (c.name ?? '').toLowerCase() === 'done')?.id ?? 'done';
    return t.column === doneColumn;
  }).length;

  const byColumn = useMemo(() => {
    const map: Record<string, TaskItem[]> = {};
    columns.forEach((c) => {
      map[c.id ?? ''] = [];
    });
    localTasks.forEach((t) => {
      if (!map[t.column]) map[t.column] = [];
      map[t.column].push(t);
    });
    return map;
  }, [columns, localTasks]);

  const priorityVariant = (p: TaskItem['priority']) => {
    if (p === 'high') return 'error';
    if (p === 'medium') return 'warning';
    return 'success';
  };

  const moveTask = (taskId: string, toColumn: string) => {
    setLocalTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
    );
    props.taskUpdate?.({ action: 'move', taskId, data: { column: toColumn } });
  };

  const saveEditTask = (taskId: string) => {
    if (!editingTitle.trim()) {
      setEditError('Title is required.');
      return;
    }
    setLocalTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle.trim() } : t))
    );
    props.taskUpdate?.({ action: 'edit', taskId, data: { title: editingTitle.trim() } });
    setEditingTaskId(null);
    setEditingTitle('');
    setEditError('');
  };

  const handleCreate = async (columnId: string) => {
    if (!newTitle.trim()) {
      setNewError('Task title is required.');
      return;
    }
    setNewError('');
    setSubmitState({ loading: true, success: '', error: '' });

    const newTask: TaskItem = {
      id: `task-${Date.now()}`,
      title: newTitle.trim(),
      priority: newPriority,
      assignee: 'NA',
      column: columns.find((c) => c.name?.toLowerCase() === 'to do')?.id ?? columns[0]?.id ?? 'todo',
    };

    try {
      if (props.onSubmit) {
        await props.onSubmit({
          title: newTask.title,
          priority: newTask.priority,
          column: newTask.column,
        });
      }
      setLocalTasks((prev) => [newTask, ...prev]);
      props.taskUpdate?.({ action: 'create', taskId: newTask.id, data: newTask });
      setSubmitState({ loading: false, success: 'Task created successfully.', error: '' });
      setNewTitle('');
      setNewPriority('medium');
      setAddingColumn(null);
    } catch {
      setSubmitState({ loading: false, success: '', error: 'Failed to create task. Please try again.' });
    }
  };

  return (
    <Card
      padding={16}
      shadow="sm"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Card
          padding={12}
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Total Tasks: {totalTasks}
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Completed: {completedCount}
            </Text>
          </Stack>
        </Card>

        {submitState.success ? <Alert variant="success">{submitState.success}</Alert> : null}
        {submitState.error ? <Alert variant="error">{submitState.error}</Alert> : null}

        <Stack direction="horizontal" gap={16} align="start" wrap>
          {columns.map((col) => {
            const columnId = col.id ?? '';
            const columnTasks = byColumn[columnId] ?? [];
            return (
              <Card
                key={columnId}
                padding={12}
                shadow="sm"
                radius="md"
                style={{
                  minWidth: 280,
                  flex: 1,
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Stack gap={12}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {col.name ?? 'Column'}
                    </Text>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Stack>

                  <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                  <Stack gap={10}>
                    {columnTasks.map((task) => (
                      <Card
                        key={task.id}
                        padding={10}
                        shadow="none"
                        radius="md"
                        style={{
                          background: 'var(--ggui-color-surface, #fafafa)',
                          borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                          transition: 'box-shadow 200ms ease, transform 200ms ease',
                        }}
                      >
                        <Stack gap={8}>
                          {editingTaskId === task.id ? (
                            <Stack gap={6}>
                              <Input
                                label="Task title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                error={editError}
                                required
                              />
                              <Stack direction="horizontal" gap={8} justify="end">
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => {
                                    setEditingTaskId(null);
                                    setEditingTitle('');
                                    setEditError('');
                                  }}
                                >
                                  Cancel
                                </Button>
                                <Button variant="primary" size="sm" onClick={() => saveEditTask(task.id)}>
                                  Save
                                </Button>
                              </Stack>
                            </Stack>
                          ) : (
                            <Stack direction="horizontal" justify="between" align="center">
                              <Text
                                variant="body"
                                color="var(--ggui-color-onSurface, #18181b)"
                                as="div"
                                truncate
                              >
                                {task.title}
                              </Text>
                              <Button
                                variant="ghost"
                                size="xs"
                                aria-label={`Edit ${task.title}`}
                                onClick={() => {
                                  setEditingTaskId(task.id);
                                  setEditingTitle(task.title);
                                  setEditError('');
                                }}
                              >
                                Edit
                              </Button>
                            </Stack>
                          )}

                          <Stack direction="horizontal" justify="between" align="center" wrap gap={8}>
                            <Badge variant={priorityVariant(task.priority)} size="sm">
                              {task.priority}
                            </Badge>
                            <Avatar name={task.assignee} size="xs" />
                          </Stack>

                          {task.dueDate ? (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              Due: {task.dueDate}
                            </Text>
                          ) : null}

                          <Select
                            label="Move task"
                            value={task.column}
                            onChange={(value) => moveTask(task.id, value)}
                            options={columns
                              .filter((c) => (c.id ?? '') !== task.column)
                              .map((c) => ({ value: c.id ?? '', label: c.name ?? '' }))}
                            placeholder="Move to..."
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {addingColumn === columnId ? (
                    <Card
                      padding={10}
                      shadow="none"
                      radius="md"
                      style={{
                        background: 'var(--ggui-color-surface, #fafafa)',
                        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      }}
                    >
                      <Stack gap={8}>
                        <Input
                          label="Task title"
                          value={newTitle}
                          onChange={setNewTitle}
                          required
                          error={newError}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newPriority}
                          onChange={(value) => setNewPriority(value as 'low' | 'medium' | 'high')}
                          options={priorityOptions}
                        />
                        <Stack direction="horizontal" justify="end" gap={8}>
                          <Button
                            variant="ghost"
                            size="sm"
                            disabled={submitState.loading}
                            onClick={() => {
                              setAddingColumn(null);
                              setNewTitle('');
                              setNewPriority('medium');
                              setNewError('');
                            }}
                          >
                            Cancel
                          </Button>
                          <Button
                            variant="primary"
                            size="sm"
                            loading={submitState.loading}
                            disabled={submitState.loading || !newTitle.trim()}
                            onClick={() => handleCreate(columnId)}
                          >
                            Submit
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : (
                    <Box>
                      <Button
                        variant="outline"
                        size="sm"
                        fullWidth
                        onClick={() => {
                          setAddingColumn(columnId);
                          setSubmitState({ loading: false, success: '', error: '' });
                        }}
                      >
                        Add Task
                      </Button>
                    </Box>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Badge,
  Box,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const normalizeCategory = (category?: string): string =>
  (category ?? 'unknown').trim().toLowerCase();

const getCategoryColor = (category?: string): string => {
  const c = normalizeCategory(category);
  if (c.includes('alkali metal')) return 'var(--ggui-color-error-500, #ef4444)';
  if (c.includes('alkaline earth metal')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (c.includes('transition metal')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (c.includes('post-transition metal')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (c.includes('metalloid')) return 'var(--ggui-color-success-500, #22c55e)';
  if (c.includes('nonmetal')) return 'var(--ggui-color-success-600, #16a34a)';
  if (c.includes('halogen')) return 'var(--ggui-color-warning-600, #d97706)';
  if (c.includes('noble gas')) return 'var(--ggui-color-primary-600, #0284c7)';
  if (c.includes('lanthanide')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  if (c.includes('actinide')) return 'var(--ggui-color-primary-700, #0369a1)';
  return 'var(--ggui-color-neutral-300, #d1d5db)';
};

const getBadgeVariant = (category?: string): 'primary' | 'success' | 'warning' | 'error' | 'info' | 'default' => {
  const c = normalizeCategory(category);
  if (c.includes('alkali metal')) return 'error';
  if (c.includes('alkaline earth metal') || c.includes('halogen')) return 'warning';
  if (c.includes('metalloid') || c.includes('nonmetal')) return 'success';
  if (c.includes('transition metal') || c.includes('noble gas') || c.includes('actinide')) return 'primary';
  if (c.includes('post-transition metal') || c.includes('lanthanide')) return 'info';
  return 'default';
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((element) => {
      const name = (element.name ?? '').toLowerCase();
      const symbol = (element.symbol ?? '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const placedElements = useMemo(
    () => filteredElements.filter((e) => typeof e.row === 'number' && typeof e.col === 'number'),
    [filteredElements]
  );

  const unplacedElements = useMemo(
    () => filteredElements.filter((e) => typeof e.row !== 'number' || typeof e.col !== 'number'),
    [filteredElements]
  );

  const selectedElement = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber) || null,
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const seen = new Set<string>();
    elements.forEach((e) => seen.add(normalizeCategory(e.category)));
    return Array.from(seen);
  }, [elements]);

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const stillExists = elements.some((e) => e.atomicNumber === selectedAtomicNumber);
    if (!stillExists) setSelectedAtomicNumber(null);
  }, [elements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding={16}>
      <Stack gap={16}>
        <Stack gap={6}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            Interactive Periodic Table
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Search by element name or symbol, then select an element to inspect details.
          </Text>
        </Stack>

        <Input
          label="Search elements"
          type="search"
          size="md"
          value={query}
          onChange={setQuery}
          placeholder="e.g. Hydrogen or H"
        />

        <Card padding={12} shadow="sm" border radius="lg">
          <Box style={{ overflowX: 'auto' }}>
            <Box
              role="grid"
              aria-label="Periodic table of elements"
              style={{
                minWidth: '900px',
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {placedElements.map((element, index) => {
                const atomicNumber = element.atomicNumber ?? null;
                const symbol = element.symbol ?? '?';
                const name = element.name ?? 'Unknown';
                const category = element.category ?? 'unknown';
                const isSelected = atomicNumber !== null && atomicNumber === selectedAtomicNumber;
                const bg = getCategoryColor(category);
                const isDarkText =
                  normalizeCategory(category).includes('actinide') ||
                  normalizeCategory(category).includes('noble gas');
                const textColor = isDarkText
                  ? 'var(--ggui-color-surface, #fafafa)'
                  : 'var(--ggui-color-onSurface, #18181b)';

                return (
                  <Card
                    key={`${atomicNumber ?? 'na'}-${symbol}-${index}`}
                    role="gridcell"
                    aria-selected={isSelected}
                    aria-label={`${name} (${symbol}), atomic number ${atomicNumber ?? 'unknown'}`}
                    tabIndex={0}
                    onClick={() => setSelectedAtomicNumber(atomicNumber)}
                    onKeyDown={(e: React.KeyboardEvent<HTMLDivElement>) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault();
                        setSelectedAtomicNumber(atomicNumber);
                      }
                    }}
                    padding={6}
                    border
                    radius="md"
                    shadow={isSelected ? 'md' : 'sm'}
                    style={{
                      gridColumn: element.col,
                      gridRow: element.row,
                      cursor: 'pointer',
                      minHeight: '78px',
                      position: 'relative',
                      background: bg,
                      color: textColor,
                      outline: isSelected
                        ? '2px solid var(--ggui-color-onSurface, #18181b)'
                        : '1px solid var(--ggui-color-outline, #d4d4d8)',
                      outlineOffset: isSelected ? '1px' : '0px',
                      transition:
                        'background-color 200ms ease-out, transform 200ms ease-out, box-shadow 200ms ease-out',
                    }}
                  >
                    <Box style={{ position: 'absolute', top: '4px', left: '6px' }}>
                      <Text variant="caption" color={textColor}>
                        {atomicNumber ?? '—'}
                      </Text>
                    </Box>
                    <Stack justify="center" align="center" style={{ height: '100%' }}>
                      <Text size="2xl" weight="bold" color={textColor} align="center">
                        {symbol}
                      </Text>
                      <Text variant="caption" color={textColor} truncate>
                        {name}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Box>

          {unplacedElements.length > 0 && (
            <Stack gap={8} style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Unplaced
              </Text>
              <Stack direction="horizontal" wrap gap={8}>
                {unplacedElements.map((element, index) => {
                  const atomicNumber = element.atomicNumber ?? null;
                  const symbol = element.symbol ?? '?';
                  const name = element.name ?? 'Unknown';
                  const category = element.category ?? 'unknown';
                  const isSelected = atomicNumber !== null && atomicNumber === selectedAtomicNumber;

                  return (
                    <Card
                      key={`unplaced-${atomicNumber ?? 'na'}-${symbol}-${index}`}
                      role="gridcell"
                      aria-selected={isSelected}
                      tabIndex={0}
                      onClick={() => setSelectedAtomicNumber(atomicNumber)}
                      onKeyDown={(e: React.KeyboardEvent<HTMLDivElement>) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.preventDefault();
                          setSelectedAtomicNumber(atomicNumber);
                        }
                      }}
                      padding={8}
                      border
                      radius="md"
                      shadow={isSelected ? 'md' : 'sm'}
                      style={{
                        cursor: 'pointer',
                        minWidth: '92px',
                        background: getCategoryColor(category),
                        transition:
                          'background-color 200ms ease-out, transform 200ms ease-out, box-shadow 200ms ease-out',
                      }}
                    >
                      <Text variant="caption">{atomicNumber ?? '—'}</Text>
                      <Text size="xl" weight="bold">
                        {symbol}
                      </Text>
                      <Text variant="caption" truncate>
                        {name}
                      </Text>
                    </Card>
                  );
                })}
              </Stack>
            </Stack>
          )}
        </Card>

        <Divider margin={4} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Card
          padding={16}
          shadow="sm"
          border
          radius="lg"
          aria-live="polite"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          }}
        >
          <Stack gap={8}>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Heading>
            {selectedElement ? (
              <Stack gap={4}>
                <Stack direction="horizontal" align="center" gap={8}>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {selectedElement.name ?? 'Unknown'} ({selectedElement.symbol ?? '?'})
                  </Text>
                  <Badge variant={getBadgeVariant(selectedElement.category)} size="sm">
                    {selectedElement.category ?? 'unknown'}
                  </Badge>
                </Stack>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Atomic Number: {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Atomic Weight: {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Category: {selectedElement.category ?? 'unknown'}
                </Text>
              </Stack>
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view its details.
              </Text>
            )}
          </Stack>
        </Card>

        <Divider margin={4} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Card padding={16} shadow="sm" border radius="lg">
          <Stack gap={10}>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Heading>
            <Stack direction="horizontal" wrap gap={10}>
              {categories.map((category) => (
                <Stack key={category} direction="horizontal" align="center" gap={6}>
                  <Box
                    style={{
                      width: '14px',
                      height: '14px',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    }}
                    aria-hidden
                  />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {category}
                  </Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action callback for sending messages */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      const prev = groups[groups.length - 1];
      if (prev && prev.sender === msg.sender) {
        prev.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (payload && (payload.text || payload.sender || payload.timestamp)) {
        setStreamMessages((prev) => [...prev, payload]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  return (
    <Card
      padding={0}
      border
      radius="lg"
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
        minHeight: '420px',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Badge variant="primary" size="sm" pill>
            {participantCount}
          </Badge>
        </Stack>

        <Stack
          gap={8}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          ref={listRef}
          aria-label="Message list"
          role="log"
          aria-live="polite"
        >
          {groupedMessages.map((group, groupIndex) => {
            const isMine = (group.sender || '') === currentUser;
            return (
              <Stack key={`group-${groupIndex}`} gap={6} align={isMine ? 'end' : 'start'}>
                {group.items.map((message, messageIndex) => (
                  <Stack
                    key={`msg-${groupIndex}-${messageIndex}-${message.timestamp || ''}`}
                    gap={4}
                    style={{
                      maxWidth: '80%',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      background: isMine
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isMine ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                      alignSelf: isMine ? 'flex-end' : 'flex-start',
                      animation: 'ggui-fadeIn 200ms ease-out',
                    }}
                  >
                    <Text
                      variant="caption"
                      color={
                        isMine
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                    >
                      {message.sender || 'Unknown'}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color={isMine ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {message.text || ''}
                    </Text>
                    <Text
                      variant="caption"
                      align="right"
                      color={
                        isMine
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                    >
                      {formatTime(message.timestamp)}
                    </Text>
                  </Stack>
                ))}
              </Stack>
            );
          })}
        </Stack>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type a message..."
              value={draft}
              onChange={setDraft}
              aria-label="Compose message"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Box,
  Card,
  Container,
  Heading,
  MotionKeyframes,
  Spinner,
  Stack,
  Text,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type StreamStatus = 'connecting' | 'live' | 'loading' | 'disconnected' | 'error';

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const { motionEnabled } = useMotion();

  const [displayedStocks, setDisplayedStocks] = useState<Props['stocks']>(stocks);
  const [displayedLastUpdated, setDisplayedLastUpdated] = useState<string | undefined>(lastUpdated);
  const [streamStatus, setStreamStatus] = useState<StreamStatus>('connecting');
  const [statusMessage, setStatusMessage] = useState<string>('Connecting to live market feed…');
  const [viewportWidth, setViewportWidth] = useState<number>(
    typeof window !== 'undefined' ? window.innerWidth : 1024
  );

  useEffect(() => {
    setDisplayedStocks(stocks);
    if (lastUpdated) {
      setDisplayedLastUpdated(lastUpdated);
    }
  }, [stocks, lastUpdated]);

  useEffect(() => {
    setStreamStatus('connecting');
    setStatusMessage('Connecting to live market feed…');

    const handler: EventListener = (event) => {
      try {
        const customEvent = event as CustomEvent<{
          stocks?: Props['stocks'];
          lastUpdated?: string;
          loading?: boolean;
          status?: StreamStatus;
        }>;

        const detail = customEvent?.detail;
        if (!detail || typeof detail !== 'object') {
          setStreamStatus('error');
          setStatusMessage('Live feed update failed');
          return;
        }

        if (detail.loading === true) {
          setStreamStatus('loading');
          setStatusMessage('Fetching latest market prices…');
        }

        if (Array.isArray(detail.stocks)) {
          setDisplayedStocks(detail.stocks);
          setStreamStatus('live');
          setStatusMessage('Live updates active');
        }

        if (typeof detail.lastUpdated === 'string') {
          setDisplayedLastUpdated(detail.lastUpdated);
        }

        if (detail.status) {
          if (detail.status === 'error') {
            setStreamStatus('error');
            setStatusMessage('Live feed update failed');
          } else if (detail.status === 'disconnected') {
            setStreamStatus('disconnected');
            setStatusMessage('Live feed disconnected. Showing last known prices.');
          } else if (detail.status === 'loading') {
            setStreamStatus('loading');
            setStatusMessage('Fetching latest market prices…');
          } else if (detail.status === 'connecting') {
            setStreamStatus('connecting');
            setStatusMessage('Connecting to live market feed…');
          } else if (detail.status === 'live') {
            setStreamStatus('live');
            setStatusMessage('Live updates active');
          }
        }
      } catch {
        setStreamStatus('error');
        setStatusMessage('Live feed update failed');
      }
    };

    window.addEventListener('ggui:agent-data', handler);

    return () => {
      window.removeEventListener('ggui:agent-data', handler);
      setStreamStatus('disconnected');
      setStatusMessage('Live feed disconnected. Showing last known prices.');
    };
  }, []);

  useEffect(() => {
    const onResize = () => setViewportWidth(window.innerWidth);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  const isDesktop = viewportWidth >= 1024;
  const columns = isDesktop ? 3 : 1;

  const alertVariant = useMemo<'info' | 'warning' | 'error' | null>(() => {
    if (streamStatus === 'connecting' || streamStatus === 'loading') return 'info';
    if (streamStatus === 'disconnected') return 'warning';
    if (streamStatus === 'error') return 'error';
    return null;
  }, [streamStatus]);

  const formatSigned = (value?: number) => {
    const num = Number.isFinite(Number(value)) ? Number(value) : 0;
    const abs = Math.abs(num).toFixed(2);
    return num >= 0 ? `+${abs}` : `-${abs}`;
  };

  return (
    <Container
      maxWidth="xl"
      padding="var(--ggui-spacing-6, 24px)"
    >
      <MotionKeyframes />
      <Stack
        gap="var(--ggui-spacing-6, 24px)"
      >
        <Box
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          padding="var(--ggui-spacing-4, 16px)"
          margin={0}
        >
          <Stack gap="var(--ggui-spacing-6, 24px)">
            <Stack
              direction="horizontal"
              justify="between"
              align="center"
              wrap
              gap="var(--ggui-spacing-2, 8px)"
            >
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>

              <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                {(streamStatus === 'connecting' || streamStatus === 'loading') && (
                  <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                )}
                <Text
                  variant="bodySmall"
                  as="span"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  <Text as="span" variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Last Updated:
                  </Text>{' '}
                  {displayedLastUpdated ?? '—'}
                </Text>
                <Text
                  as="span"
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  aria-live="polite"
                >
                  {statusMessage}
                </Text>
              </Stack>
            </Stack>

            {alertVariant && (
              <Alert variant={alertVariant} title="Live Feed Status">
                {statusMessage}
              </Alert>
            )}

            <Box
              role="list"
              aria-label="Stock ticker dashboard"
              style={{
                display: 'grid',
                gap: 'var(--ggui-spacing-4, 16px)',
                gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))`,
              }}
            >
              {displayedStocks.map((stock, index) => {
                const changeValue = Number.isFinite(Number(stock.change)) ? Number(stock.change) : 0;
                const changePercentValue = Number.isFinite(Number(stock.changePercent))
                  ? Number(stock.changePercent)
                  : 0;

                const isPositive = changeValue > 0 || changePercentValue > 0;
                const isNegative = changeValue < 0 || changePercentValue < 0;

                const stateColor = isPositive
                  ? 'var(--ggui-color-success-600, #16a34a)'
                  : isNegative
                  ? 'var(--ggui-color-error-600, #dc2626)'
                  : 'var(--ggui-color-onSurfaceVariant, #52525b)';

                const borderColor = isPositive
                  ? 'var(--ggui-color-success-600, #16a34a)'
                  : isNegative
                  ? 'var(--ggui-color-error-600, #dc2626)'
                  : 'var(--ggui-color-outline, #d4d4d8)';

                const arrow = changePercentValue > 0 ? '▲' : changePercentValue < 0 ? '▼' : '•';
                const price = Number.isFinite(Number(stock.price)) ? Number(stock.price) : 0;

                const symbol = stock.symbol ?? '—';
                const name = stock.name ?? 'Unknown Company';

                return (
                  <Card
                    key={`${stock.symbol ?? 'stock'}-${index}`}
                    role="listitem"
                    aria-label={`${symbol} ${name}, price ${price.toFixed(2)}, change ${formatSigned(
                      changeValue
                    )}, ${formatSigned(changePercentValue)} percent`}
                    padding={16}
                    shadow="sm"
                    radius="lg"
                    border
                    style={{
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderColor,
                      transition:
                        motionEnabled
                          ? 'border-color 200ms ease-in-out, color 200ms ease-in-out'
                          : 'none',
                      animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text
                        variant="body"
                        size="2xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {symbol}
                      </Text>

                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {name}
                      </Text>

                      <Text
                        variant="bodyLarge"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {price.toFixed(2)}
                      </Text>

                      <Stack
                        direction="horizontal"
                        align="center"
                        gap="var(--ggui-spacing-2, 8px)"
                      >
                        <Text variant="label" color={stateColor}>
                          {formatSigned(changeValue)}
                        </Text>
                        <Text variant="label" color={stateColor}>
                          {arrow} {formatSigned(changePercentValue)}%
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Box,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  MotionKeyframes,
  Progress,
  Select,
  Stack,
  Text,
  Toggle,
  Alert,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action Contract: called on final submit */
  onComplete?: (payload: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [avatar, setAvatar] = useState<string>('');
  const [role, setRole] = useState<string>('');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(true);
  const [theme, setTheme] = useState<string>('light');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });
  const [submitAttempted, setSubmitAttempted] = useState<boolean>(false);

  useEffect(() => {
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? '');
    setRole(props.initialProfile?.role ?? props.roleOptions?.[0] ?? '');
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(
      props.initialProfile?.theme === 'dark' || props.initialProfile?.theme === 'light'
        ? props.initialProfile.theme
        : 'light'
    );
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailIsValid = emailRegex.test(email.trim());
  const avatarIsValid =
    avatar.trim().length > 0 &&
    (props.avatarOptions.length === 0 || props.avatarOptions.includes(avatar));
  const step1Valid = name.trim().length > 0 && emailIsValid && avatarIsValid;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canGoNext = currentStep === 1 ? step1Valid : currentStep === 2 ? step2Valid : true;

  const stepLabel = useMemo(() => {
    if (currentStep === 1) return 'Profile Setup';
    if (currentStep === 2) return 'Preferences';
    return 'Review & Confirm';
  }, [currentStep]);

  const progressValue = (currentStep / 3) * 100;

  const showNameError = (touched.name || submitAttempted) && name.trim().length === 0;
  const showEmailError = (touched.email || submitAttempted) && !emailIsValid;

  const handleBack = () => {
    if (currentStep === 2) setCurrentStep(1);
    if (currentStep === 3) setCurrentStep(2);
  };

  const handleNext = () => {
    setSubmitAttempted(true);
    setTouched((prev) => ({ ...prev, name: true, email: true }));

    if (currentStep === 1 && step1Valid) setCurrentStep(2);
    if (currentStep === 2 && step2Valid) setCurrentStep(3);
  };

  const handleComplete = () => {
    setSubmitAttempted(true);
    setTouched((prev) => ({ ...prev, name: true, email: true }));

    const fullyValid = step1Valid && step2Valid;
    if (!fullyValid) return;

    props.onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar: avatar.trim(),
      role: role.trim(),
      emailNotifications,
      theme,
    });
  };

  return (
    <Container maxWidth="md" padding={24}>
      <MotionKeyframes />
      <Card shadow="md" radius="lg" border padding={24}>
        <Stack gap={16}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            Onboarding Setup
          </Heading>

          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Step {currentStep} of 3
              </Text>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                as="span"
              >
                <span aria-live="polite">{stepLabel}</span>
              </Text>
            </Stack>
            <Progress value={progressValue} max={100} size="sm" variant="default" />
          </Stack>

          <Box
            padding={4}
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={
              motionEnabled
                ? { animation: 'ggui-fadeIn 200ms ease-out' }
                : { animation: 'none' }
            }
          >
            {currentStep === 1 && (
              <Stack gap={12}>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Heading>

                <Input
                  label="Name"
                  required
                  value={name}
                  onChange={setName}
                  onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                  error={showNameError ? 'Name is required.' : undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  required
                  value={email}
                  onChange={setEmail}
                  onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                  error={showEmailError ? 'Please enter a valid email address.' : undefined}
                />

                <Box
                  padding={12}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                >
                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      Avatar selection
                    </Text>
                    <Stack direction="horizontal" wrap gap={8}>
                      {props.avatarOptions.map((emoji, index) => {
                        const selected = avatar === emoji;
                        return (
                          <Button
                            key={`${emoji}-${index}`}
                            variant={selected ? 'primary' : 'outline'}
                            size="md"
                            aria-pressed={selected}
                            aria-label={`Select avatar ${emoji}`}
                            onClick={() => setAvatar(emoji)}
                          >
                            {emoji}
                          </Button>
                        );
                      })}
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={12}>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Heading>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  placeholder="Select a role"
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />

                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={12}>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Heading>

                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your profile details before completing setup.
                </Text>

                <Box
                  padding={12}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                >
                  <Stack gap={8}>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Name</Text>
                      <Text variant="bodySmall">{name || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Email</Text>
                      <Text variant="bodySmall">{email || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Avatar</Text>
                      <Text variant="bodySmall">{avatar || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Role</Text>
                      <Text variant="bodySmall">{role || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Email Notifications</Text>
                      <Text variant="bodySmall">{emailNotifications ? 'On' : 'Off'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Theme</Text>
                      <Text variant="bodySmall">{theme === 'dark' ? 'Dark' : 'Light'}</Text>
                    </Stack>
                  </Stack>
                </Box>

                {submitAttempted && !(step1Valid && step2Valid) && (
                  <Alert variant="error" title="Validation required">
                    Please go back and complete all required fields correctly.
                  </Alert>
                )}

                <Stack direction="horizontal" gap={8}>
                  <Button variant="ghost" onClick={() => setCurrentStep(2)}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete}>
                    Complete Setup
                  </Button>
                </Stack>
              </Stack>
            )}
          </Box>

          <Divider color="var(--ggui-color-outline, #d4d4d8)" />

          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Button variant="secondary" onClick={handleBack} disabled={currentStep === 1}>
              Back
            </Button>

            {currentStep < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

