  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const normalized = condition.trim().toLowerCase();

  if (normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('rain') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('partly') && normalized.includes('cloud')) return '⛅';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';

  return '🌤️';
}

function formatTemperature(value?: number): string {
  return typeof value === 'number' ? `${value}°` : '--';
}

