export const __GGUI_META__ = {
  category: 'display',
  description: 'A reusable weather card showing current temperature, condition, humidity, wind speed, and a forecast strip.',
};

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Avatar,
  Badge,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Icon,
  Input,
  Select,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onTaskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onSubmit?: (payload: { title: string; priority: 'low' | 'medium' | 'high' }) => Promise<unknown> | unknown;
}

type Priority = 'low' | 'medium' | 'high';

type BoardTask = {
  id: string;
  title: string;
  priority: Priority;
  assignee: string;
  column: string;
  dueDate?: string;
};

const priorityVariantMap: Record<Priority, 'success' | 'warning' | 'error'> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};

export default function GeneratedComponent(props: Props) {
  const initialTasks = useMemo<BoardTask[]>(
    () =>
      props.tasks.map((task, index) => ({
        id: task.id || `task-${index + 1}`,
        title: task.title || `Untitled Task ${index + 1}`,
        priority: task.priority || 'medium',
        assignee: task.assignee || '',
        column: task.column || props.columns[0]?.id || 'todo',
        dueDate: task.dueDate,
      })),
    [props.tasks, props.columns]
  );

  const [boardTasks, setBoardTasks] = useState<BoardTask[]>(initialTasks);
  const [openAddColumn, setOpenAddColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');
  const [createError, setCreateError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  useEffect(() => {
    setBoardTasks(initialTasks);
  }, [initialTasks]);

  const doneColumnId =
    props.columns.find((column) => column.id === 'done' || column.name?.toLowerCase() === 'done')?.id || 'done';

  const totalTasks = boardTasks.length;
  const completedCount = boardTasks.filter((task) => task.column === doneColumnId).length;

  const emitTaskUpdate = (action: string, taskId: string, data: Record<string, unknown>) => {
    const payload = { action, taskId, data };
    props.taskUpdate?.(payload);
    props.onTaskUpdate?.(payload);
  };

  const startEditing = (task: BoardTask) => {
    setEditingTaskId(task.id);
    setEditingTaskTitle(task.title);
    setFeedback(null);
  };

  const cancelEditing = () => {
    setEditingTaskId(null);
    setEditingTaskTitle('');
  };

  const saveTaskTitle = (taskId: string) => {
    const nextTitle = editingTaskTitle.trim();
    if (!nextTitle) {
      setFeedback({ type: 'error', message: 'Task title cannot be empty.' });
      return;
    }

    setBoardTasks((current) =>
      current.map((task) => {
        if (task.id !== taskId) return task;
        const updatedTask = { ...task, title: nextTitle };
        emitTaskUpdate('edit', taskId, updatedTask);
        return updatedTask;
      })
    );

    setEditingTaskId(null);
    setEditingTaskTitle('');
    setFeedback({ type: 'success', message: 'Task updated.' });
  };

  const moveTask = (taskId: string, nextColumnId: string) => {
    if (!nextColumnId) return;

    setBoardTasks((current) =>
      current.map((task) => {
        if (task.id !== taskId) return task;
        const updatedTask = { ...task, column: nextColumnId };
        emitTaskUpdate('move', taskId, updatedTask);
        return updatedTask;
      })
    );

    setFeedback({ type: 'success', message: 'Task moved.' });
  };

  const resetCreateForm = () => {
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setCreateError('');
    setOpenAddColumn(null);
  };

  const createTask = async (requestedColumnId: string) => {
    const trimmedTitle = newTaskTitle.trim();

    if (!trimmedTitle) {
      setCreateError('A task title is required.');
      return;
    }

    setCreateError('');
    setFeedback(null);
    setSubmitting(true);

    try {
      await props.onSubmit?.({ title: trimmedTitle, priority: newTaskPriority });

      const todoColumnId =
        props.columns.find((column) => column.id === 'todo' || column.name?.toLowerCase() === 'to do')?.id ||
        requestedColumnId;

      const createdTask: BoardTask = {
        id: `task-${Date.now()}`,
        title: trimmedTitle,
        priority: newTaskPriority,
        assignee: '',
        column: todoColumnId,
      };

      setBoardTasks((current) => [...current, createdTask]);
      emitTaskUpdate('create', createdTask.id, createdTask);
      resetCreateForm();
      setFeedback({ type: 'success', message: 'Task created.' });
    } catch {
      setFeedback({ type: 'error', message: 'Unable to create task. Please try again.' });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card padding="var(--ggui-spacing-4, 16px)" radius="lg" shadow="sm" border>
          <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4, 16px)">
            <Stack gap={4}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Task Board
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Total tasks and completed progress across your kanban workflow.
              </Text>
            </Stack>

            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
              <Card padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" radius="md" shadow="none" border>
                <Stack gap={2}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Total Tasks
                  </Text>
                  <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {totalTasks}
                  </Text>
                </Stack>
              </Card>

              <Card padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" radius="md" shadow="none" border>
                <Stack gap={2}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Completed
                  </Text>
                  <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {completedCount}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          </Stack>
        </Card>

        {feedback ? (
          <Alert variant={feedback.type} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        ) : null}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="start" wrap>
          {props.columns.map((column) => {
            const columnId = column.id || '';
            const columnName = column.name || 'Column';
            const tasksInColumn = boardTasks.filter((task) => task.column === columnId);

            return (
              <Card key={columnId || columnName} padding="var(--ggui-spacing-4, 16px)" radius="lg" shadow="sm" border>
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                      {columnName}
                    </Text>
                    <Badge variant="secondary" size="sm">
                      {tasksInColumn.length}
                    </Badge>
                  </Stack>

                  <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

                  <Stack gap="12px">
                    {tasksInColumn.map((task) => {
                      const moveOptions = props.columns
                        .filter((item) => item.id && item.id !== task.column)
                        .map((item) => ({
                          value: item.id || '',
                          label: item.name || 'Column',
                        }));

                      return (
                        <Card key={task.id} padding="12px" radius="md" shadow="none" border>
                          <Stack gap="12px">
                            <Stack direction="horizontal" justify="between" align="start" gap="var(--ggui-spacing-2, 8px)">
                              <Stack gap={4}>
                                {editingTaskId === task.id ? (
                                  <Stack gap="var(--ggui-spacing-2, 8px)">
                                    <Input
                                      label="Edit task title"
                                      value={editingTaskTitle}
                                      onChange={setEditingTaskTitle}
                                      disabled={submitting}
                                      autoFocus
                                      aria-label={`Edit title for ${task.title}`}
                                    />
                                    <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                                      <Button size="sm" onClick={() => saveTaskTitle(task.id)}>
                                        Save
                                      </Button>
                                      <Button size="sm" variant="ghost" onClick={cancelEditing}>
                                        Cancel
                                      </Button>
                                    </Stack>
                                  </Stack>
                                ) : (
                                  <>
                                    <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                                      {task.title}
                                    </Text>
                                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                      Use Edit to rename this task
                                    </Text>
                                  </>
                                )}
                              </Stack>

                              {editingTaskId !== task.id ? (
                                <Button
                                  size="xs"
                                  variant="ghost"
                                  onClick={() => startEditing(task)}
                                  onDoubleClick={() => startEditing(task)}
                                  aria-label={`Edit ${task.title}`}
                                >
                                  Edit
                                </Button>
                              ) : null}
                            </Stack>

                            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" wrap>
                              <Badge variant={priorityVariantMap[task.priority]} size="sm">
                                {task.priority}
                              </Badge>

                              {task.assignee ? (
                                <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                                  <Avatar name={task.assignee} size="sm" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                    {task.assignee}
                                  </Text>
                                </Stack>
                              ) : (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  Unassigned
                                </Text>
                              )}
                            </Stack>

                            {task.dueDate ? (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                Due: {task.dueDate}
                              </Text>
                            ) : null}

                            <Select
                              label="Move task"
                              value=""
                              onChange={(value) => moveTask(task.id, value)}
                              options={moveOptions}
                              placeholder="Move to..."
                              aria-label={`Move ${task.title}`}
                            />
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {openAddColumn === columnId ? (
                    <Card padding="12px" radius="md" shadow="none" border>
                      <Stack gap="12px">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={(value) => {
                            setNewTaskTitle(value);
                            if (createError) setCreateError('');
                          }}
                          placeholder="Enter task title"
                          error={createError}
                          required
                          disabled={submitting}
                        />

                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(value) => setNewTaskPriority(value as Priority)}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          disabled={submitting}
                        />

                        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                          <Button
                            variant="primary"
                            size="sm"
                            loading={submitting}
                            disabled={submitting || !newTaskTitle.trim()}
                            onClick={() => createTask(columnId)}
                          >
                            Submit
                          </Button>

                          <Button variant="ghost" size="sm" disabled={submitting} onClick={resetCreateForm}>
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : null}

                  <Button
                    variant="outline"
                    size="sm"
                    fullWidth
                    leftIcon={<Icon name="plus" size={16} />}
                    onClick={() => {
                      setOpenAddColumn(columnId);
                      setFeedback(null);
                      setCreateError('');
                    }}
                  >
                    Add Task
                  </Button>
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

