import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Box, Button, Card, Divider, Heading, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message — Called when user sends a message. Payload: { text, timestamp } */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type MessageItem = { sender?: string; text?: string; timestamp?: string };
type MessageGroup = { sender?: string; items: MessageItem[] };

function formatTimestamp(timestamp?: string): string {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

function isMeaningfulMessage(item: MessageItem): boolean {
  const hasText = (item.text ?? '').trim().length > 0;
  const hasSender = (item.sender ?? '').trim().length > 0;
  const hasTimestamp = Boolean(formatTimestamp(item.timestamp));
  return hasText || hasSender || hasTimestamp;
}

function normalizeIncoming(detail: unknown): MessageItem[] {
  const values = Array.isArray(detail) ? detail : [detail];

  return values
    .map((entry) => {
      if (!entry || typeof entry !== 'object') return null;

      const candidate = entry as {
        sender?: unknown;
        text?: unknown;
        timestamp?: unknown;
        message?: unknown;
        messages?: unknown;
      };

      if (Array.isArray(candidate.messages)) {
        return normalizeIncoming(candidate.messages);
      }

      const text =
        typeof candidate.text === 'string'
          ? candidate.text
          : typeof candidate.message === 'string'
            ? candidate.message
            : undefined;

      return {
        sender: typeof candidate.sender === 'string' ? candidate.sender : undefined,
        text,
        timestamp:
          typeof candidate.timestamp === 'string'
            ? candidate.timestamp
            : new Date().toISOString(),
      } satisfies MessageItem;
    })
    .flat()
    .filter((item): item is MessageItem => Boolean(item && isMeaningfulMessage(item)));
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [streamedMessages, setStreamedMessages] = useState<MessageItem[]>([]);
  const viewportRef = useRef<HTMLDivElement | null>(null);
  const didMountRef = useRef(false);

  const renderedMessages = useMemo(
    () => [...messages, ...streamedMessages].filter(isMeaningfulMessage),
    [messages, streamedMessages]
  );

  const groupedMessages = useMemo<MessageGroup[]>(() => {
    return renderedMessages.reduce<MessageGroup[]>((groups, item) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === item.sender) {
        lastGroup.items.push(item);
        return groups;
      }
      groups.push({ sender: item.sender, items: [item] });
      return groups;
    }, []);
  }, [renderedMessages]);

  const scrollToBottom = (behavior: ScrollBehavior) => {
    if (!viewportRef.current) return;
    viewportRef.current.scrollTo({
      top: viewportRef.current.scrollHeight,
      behavior,
    });
  };

  useEffect(() => {
    scrollToBottom('auto');
    didMountRef.current = true;
  }, []);

  useEffect(() => {
    if (!didMountRef.current) return;
    scrollToBottom('smooth');
  }, [groupedMessages.length, renderedMessages.length]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const incoming = normalizeIncoming(customEvent.detail);
      if (incoming.length > 0) {
        setStreamedMessages((prev) => [...prev, ...incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;

    const payload = {
      text,
      timestamp: new Date().toISOString(),
    };

    sendMessage?.(payload);
    setDraft('');
    requestAnimationFrame(() => scrollToBottom('smooth'));
  };

  return (
    <section aria-label={title || 'Chat'}>
      <Card padding={0} shadow="sm" radius="lg" border={true}>
        <Box
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="vertical" gap={0}>
            <Box padding="var(--ggui-spacing-4, 16px)">
              <Stack direction="horizontal" justify="between" align="center" gap={8}>
                <Stack gap={4}>
                  <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">
                    {title || 'Chat'}
                  </Heading>
                </Stack>

                {typeof participantCount === 'number' ? (
                  <Badge
                    variant="primary"
                    size="sm"
                    pill={true}
                    aria-label={`${participantCount} participants`}
                  >
                    {participantCount}
                  </Badge>
                ) : null}
              </Stack>
            </Box>

            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

            <Box
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surface, #fafafa)"
            >
              <div
                ref={viewportRef}
                role="log"
                aria-live="polite"
                aria-relevant="additions text"
                aria-atomic="false"
                style={{
                  minHeight: '280px',
                  maxHeight: '480px',
                  overflowY: 'auto',
                  paddingRight: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {groupedMessages.length === 0 ? (
                  <Stack
                    direction="vertical"
                    justify="center"
                    align="center"
                    gap={8}
                    style={{ minHeight: '248px' }}
                  >
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      No messages yet
                    </Text>
                  </Stack>
                ) : (
                  <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)">
                    {groupedMessages.map((group, groupIndex) => {
                      const isCurrentUserGroup = (group.sender ?? '') === currentUser;
                      const senderLabel = (group.sender ?? '').trim() || 'Unknown';

                      return (
                        <Box key={`${group.sender ?? 'unknown'}-${groupIndex}`}>
                          <Stack
                            direction="vertical"
                            gap="var(--ggui-spacing-2, 8px)"
                            align={isCurrentUserGroup ? 'end' : 'start'}
                          >
                            {!isCurrentUserGroup ? (
                              <Stack direction="horizontal" align="center" gap={8}>
                                <Text
                                  variant="label"
                                  color="var(--ggui-color-onSurface, #18181b)"
                                >
                                  {senderLabel}
                                </Text>
                              </Stack>
                            ) : null}

                            <Stack
                              direction="vertical"
                              gap="var(--ggui-spacing-2, 8px)"
                              align={isCurrentUserGroup ? 'end' : 'start'}
                            >
                              {group.items.map((item, itemIndex) => {
                                const text = item.text?.trim() ?? '';
                                if (!text) return null;

                                const formattedTime = formatTimestamp(item.timestamp);

                                return (
                                  <Box
                                    key={`${groupIndex}-${itemIndex}-${item.timestamp ?? ''}-${text}`}
                                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                                    background={
                                      isCurrentUserGroup
                                        ? 'var(--ggui-color-primary-600, #0284c7)'
                                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                                    }
                                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                                  >
                                    <Stack direction="vertical" gap={4}>
                                      <Text
                                        variant="bodySmall"
                                        color={
                                          isCurrentUserGroup
                                            ? 'var(--ggui-color-surface, #fafafa)'
                                            : 'var(--ggui-color-onSurface, #18181b)'
                                        }
                                      >
                                        {text}
                                      </Text>

                                      {formattedTime ? (
                                        <Text
                                          variant="caption"
                                          color={
                                            isCurrentUserGroup
                                              ? 'var(--ggui-color-surface, #fafafa)'
                                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                          }
                                        >
                                          {formattedTime}
                                        </Text>
                                      ) : null}
                                    </Stack>
                                  </Box>
                                );
                              })}
                            </Stack>
                          </Stack>
                        </Box>
                      );
                    })}
                  </Stack>
                )}
              </div>
            </Box>

            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

            <Box
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surface, #fafafa)"
            >
              <Stack direction="vertical" gap={4}>
                <Text
                  as="label"
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Message
                </Text>

                <Stack direction="horizontal" gap={8} align="end">
                  <Box style={{ flex: 1 }}>
                    <Input
                      label="Message"
                      value={draft}
                      onChange={setDraft}
                      size="md"
                      placeholder="Type a message..."
                      aria-label="Type a message"
                      onKeyDown={(event) => {
                        if (event.key === 'Enter') {
                          event.preventDefault();
                          handleSend();
                        }
                      }}
                    />
                  </Box>

                  <Button
                    variant="primary"
                    size="md"
                    disabled={draft.trim().length === 0}
                    onClick={handleSend}
                    aria-label="Send message"
                  >
                    Send
                  </Button>
                </Stack>
              </Stack>
            </Box>
          </Stack>
        </Box>
      </Card>
    </section>
  );
}

