  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type ConnectionState = 'connecting' | 'live';

function formatNumber(value?: number): string {
  return typeof value === 'number' && Number.isFinite(value) ? value.toFixed(2) : '0.00';
}

function formatTimestamp(value?: string): string {
  if (!value) return '—';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString();
}

function StockCard({
  symbol = '—',
  name = 'Unknown Company',
  price = 0,
  change = 0,
  changePercent = 0,
  motionEnabled,
}: {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
  motionEnabled: boolean;
}) {
  const isPositive = change >= 0;
  const trendColor = isPositive
    ? 'var(--ggui-color-success-600, #16a34a)'
    : 'var(--ggui-color-error-600, #dc2626)';
  const trendBorderColor = isPositive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : 'var(--ggui-color-error-500, #ef4444)';
  const arrow = isPositive ? '▲' : '▼';
