export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const connectingTimer = window.setTimeout(() => {
      setConnectionState('live');
    }, 900);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Props | Partial<Props>>;
      const detail = customEvent.detail;
      if (!detail || typeof detail !== 'object') return;

      if (Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
      }
      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      }
      setConnectionState('live');
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => {
      window.clearTimeout(connectingTimer);
      window.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  const hasStocks = liveStocks.length > 0;
  const statusLabel = useMemo(() => {
    if (connectionState === 'connecting') return 'Connecting to live market feed';
    return 'Live market feed connected';
  }, [connectionState]);

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" shadow="sm" border>
            <Stack
              direction="horizontal"
              justify="between"
              align="center"
              wrap
              gap="var(--ggui-spacing-4, 16px)"
            >
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  Market Watch
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated: {formatTimestamp(liveLastUpdated)}
                </Text>
              </Stack>

              <Box
                paddingX="var(--ggui-spacing-3, 12px)"
                paddingY="var(--ggui-spacing-2, 8px)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                  {connectionState === 'connecting' ? (
                    <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                  ) : (
                    <Text as="span" color="var(--ggui-color-success-600, #16a34a)">
                      ●
                    </Text>
                  )}
                  <Text
                    as="span"
                    variant="label"
                    color="var(--ggui-color-onSurface, #18181b)"
                    aria-live="polite"
                  >
                    {statusLabel}
                  </Text>
                </Stack>
              </Box>
            </Stack>
          </Card>

          {!hasStocks ? (
            <Card padding="var(--ggui-spacing-8, 32px)" radius="lg" shadow="sm" border>
              <Stack gap="var(--ggui-spacing-3, 12px)" align="center">
                {connectionState === 'connecting' && (
                  <Spinner size={28} color="var(--ggui-color-primary-600, #0284c7)" />
                )}
                <Text
                  variant="bodyLarge"
                  weight="medium"
                  color="var(--ggui-color-onSurface, #18181b)"
                  align="center"
                >
                  {connectionState === 'connecting' ? 'Loading live stock prices…' : 'No stock data available'}
                </Text>
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  {connectionState === 'connecting'
                    ? 'Waiting for the agent to broadcast market updates.'
                    : 'The dashboard will populate automatically when stock data is received.'}
                </Text>
              </Stack>
            </Card>
          ) : (
            <Box
              background="var(--ggui-color-surface, #fafafa)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <div
                role="region"
                aria-label="Stock ticker dashboard"
                style={{
                  animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
                }}
              >
                <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
                  {liveStocks.map((stock, index) => {
                    const key = `${stock.symbol ?? stock.name ?? 'stock'}-${index}`;
                    return (
                      <div
                        key={key}
                        style={{
                          animation: motionEnabled
                            ? `ggui-slideInUp 300ms ease-out ${index * 40}ms both`
                            : 'none',
                        }}
                      >
                        <StockCard
                          symbol={stock.symbol}
                          name={stock.name}
                          price={stock.price}
                          change={stock.change}
                          changePercent={stock.changePercent}
                          motionEnabled={motionEnabled}
                        />
                      </div>
                    );
                  })}
                </CardGrid>
              </div>
            </Box>
          )}
        </Stack>
      </Container>
    </>
  );
}

