import React, { useMemo, useState } from 'react';
import {
  Button,
  Card,
  Container,
  Input,
  Progress,
  Select,
  Stack,
  Text,
  Toggle,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile,
    avatarOptions = ['😀', '🚀', '🎨', '🧠'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    onComplete,
  } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [direction, setDirection] = useState<'forward' | 'backward'>('forward');
  const [name, setName] = useState(initialProfile?.name ?? '');
  const [email, setEmail] = useState(initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState(initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const totalSteps = 3;
  const progressValue = (currentStep / totalSteps) * 100;

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email
    ? !email.trim()
      ? 'Email is required.'
      : !isValidEmail(email)
        ? 'Enter a valid email address.'
        : ''
    : '';
  const avatarError = touched.avatar && !avatar ? 'Please choose an avatar.' : '';
  const roleError = touched.role && !role ? 'Please select a role.' : '';

  const isStepOneValid = Boolean(name.trim() && email.trim() && isValidEmail(email) && avatar);
  const isStepTwoValid = Boolean(role);
  const canProceed = currentStep === 1 ? isStepOneValid : currentStep === 2 ? isStepTwoValid : true;

  const summaryItems = useMemo(
    () => [
      { label: 'Name', value: name || '—' },
      { label: 'Email', value: email || '—' },
      { label: 'Avatar', value: avatar || '—' },
      { label: 'Role', value: role || '—' },
      { label: 'Email Notifications', value: emailNotifications ? 'On' : 'Off' },
      { label: 'Theme', value: theme === 'dark' ? 'Dark' : 'Light' },
    ],
    [name, email, avatar, role, emailNotifications, theme]
  );

  const goNext = () => {
    if (currentStep === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true, avatar: true }));
      if (!isStepOneValid) return;
    }
    if (currentStep === 2) {
      setTouched((prev) => ({ ...prev, role: true }));
      if (!isStepTwoValid) return;
    }
    setDirection('forward');
    setCurrentStep((prev) => Math.min(totalSteps, prev + 1));
  };

  const goBack = () => {
    setDirection('backward');
    setCurrentStep((prev) => Math.max(1, prev - 1));
  };

  const handleComplete = () => {
    setTouched((prev) => ({ ...prev, name: true, email: true, avatar: true, role: true }));
    if (!isStepOneValid || !isStepTwoValid) return;

    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card
        padding="var(--ggui-spacing-6, 24px)"
        shadow="md"
        radius="xl"
        border
      >
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Stack direction="horizontal" justify="between" align="center">
              <Stack gap={4}>
                <Text variant="overline" color="var(--ggui-color-primary-700, #0369a1)">
                  Onboarding
                </Text>
                <Text
                  variant="bodyLarge"
                  weight="semibold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  Step {currentStep} of {totalSteps}
                </Text>
              </Stack>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {Math.round(progressValue)}% complete
              </Text>
            </Stack>

            <Progress value={progressValue} max={100} size="md" variant="default" />

            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
              {[
                { step: 1, title: 'Profile Setup' },
                { step: 2, title: 'Preferences' },
                { step: 3, title: 'Review & Confirm' },
              ].map((item) => {
                const active = item.step === currentStep;
                const complete = item.step < currentStep;

                return (
                  <Card
                    key={item.step}
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                    radius="lg"
                    shadow="none"
                    border
                  >
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                      <Text
                        as="span"
                        variant="label"
                        color={
                          active || complete
                            ? 'var(--ggui-color-primary-700, #0369a1)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                        }
                      >
                        {complete ? '✓' : item.step}
                      </Text>
                      <Text
                        as="span"
                        variant="bodySmall"
                        weight={active ? 'semibold' : 'medium'}
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {item.title}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Stack>
          </Stack>

          <div
            aria-live="polite"
            style={{
              animation: `${direction === 'forward' ? 'ggui-slideInUp' : 'ggui-fadeIn'} 200ms ease-out`,
            }}
          >
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={nameError}
                  helperText="This will be displayed on your profile."
                  onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                  aria-label="Name"
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={emailError}
                  helperText="We'll use this to keep your account up to date."
                  onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                  aria-label="Email"
                />

                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text as="label" variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose an avatar
                  </Text>

                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                    {avatarOptions.map((option) => {
                      const selected = option === avatar;

                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'secondary'}
                          size="lg"
                          onClick={() => {
                            setAvatar(option);
                            setTouched((prev) => ({ ...prev, avatar: true }));
                          }}
                          aria-pressed={selected}
                          aria-label={`Select avatar ${option}`}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>

                  {avatarError ? (
                    <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">
                      {avatarError}
                    </Text>
                  ) : (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Pick the emoji that best matches your profile.
                    </Text>
                  )}
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={(value) => {
                    setRole(value);
                    setTouched((prev) => ({ ...prev, role: true }));
                  }}
                  options={roleOptions.map((option) => ({ value: option, label: option }))}
                  placeholder="Select your role"
                  required
                  error={roleError}
                  helperText="This helps tailor your workspace."
                  aria-label="Role"
                />

                <Card
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="none"
                  radius="lg"
                  border
                >
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Toggle
                      label="Email notifications"
                      checked={emailNotifications}
                      onChange={setEmailNotifications}
                      size="md"
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Receive helpful onboarding and product updates by email.
                    </Text>
                  </Stack>
                </Card>

                <Card
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="none"
                  radius="lg"
                  border
                >
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Toggle
                      label="Dark theme"
                      checked={theme === 'dark'}
                      onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                      size="md"
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Choose the appearance mode you prefer.
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Double-check your details before completing setup.
                </Text>

                <Stack gap="var(--ggui-spacing-2, 8px)">
                  {summaryItems.map((item) => (
                    <Card
                      key={item.label}
                      padding="12px 16px"
                      shadow="none"
                      radius="lg"
                      border
                    >
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {item.label}
                        </Text>
                        <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                          {item.value}
                        </Text>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              </Stack>
            )}
          </div>

          <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4, 16px)">
            <Button
              variant="ghost"
              size="md"
              onClick={goBack}
              disabled={currentStep === 1}
              aria-label="Go back"
            >
              Go Back
            </Button>

            {currentStep < totalSteps ? (
              <Button
                variant="primary"
                size="md"
                onClick={goNext}
                disabled={!canProceed}
                aria-label="Next step"
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                size="md"
                onClick={handleComplete}
                aria-label="Complete setup"
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>

      {`__GGUI_META__={"category":"forms","description":"A 3-step onboarding wizard with profile setup, preferences, validation, progress tracking, and final review before completion."}`}
    </Container>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Avatar,
  Badge,
  Box,
  Button,
