} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: {
    action: string;
    taskId: string;
    data: {
      id: string;
      title: string;
      priority: 'low' | 'medium' | 'high';
      assignee?: string;
      column: string;
      dueDate?: string;
    };
  }) => void | Promise<void>;
  onTaskUpdate?: (payload: {
    action: string;
    taskId: string;
    data: {
      id: string;
      title: string;
      priority: 'low' | 'medium' | 'high';
      assignee?: string;
      column: string;
      dueDate?: string;
    };
  }) => void | Promise<void>;
  onSubmit?: (payload: {
    title: string;
    priority: 'low' | 'medium' | 'high';
    column: string;
  }) => void | Promise<void>;
}

type Priority = 'low' | 'medium' | 'high';

type TaskItem = {
  id: string;
  title: string;
  priority: Priority;
  assignee?: string;
  column: string;
  dueDate?: string;
};

const priorityBadgeVariant: Record<Priority, 'success' | 'warning' | 'error'> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};

const normalizeTask = (
  task: Props['tasks'][number],
  fallbackColumn: string,
  index: number,
): TaskItem => ({
  id: task.id || `task-${index + 1}`,
  title: task.title || 'Untitled Task',
  priority: task.priority || 'medium',
  assignee: task.assignee || '',
  column: task.column || fallbackColumn,
  dueDate: task.dueDate || '',
});

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const defaultColumnId = props.columns[0]?.id || 'todo';

  const [boardTasks, setBoardTasks] = useState<TaskItem[]>(() =>
    props.tasks.map((task, index) => normalizeTask(task, defaultColumnId, index)),
  );
  const [openAddColumn, setOpenAddColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [editError, setEditError] = useState('');
  const [createError, setCreateError] = useState('');
  const [submitError, setSubmitError] = useState('');
  const [submitSuccess, setSubmitSuccess] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    setBoardTasks(props.tasks.map((task, index) => normalizeTask(task, defaultColumnId, index)));
  }, [props.tasks, defaultColumnId]);

  const totalTasks = boardTasks.length;

  const completedCount = useMemo(() => {
    const doneColumnIds = props.columns
      .filter(
        (column) =>
          (column.name || '').toLowerCase() === 'done' || (column.id || '').toLowerCase() === 'done',
      )
      .map((column) => column.id || '');

    return boardTasks.filter((task) => doneColumnIds.includes(task.column)).length;
  }, [boardTasks, props.columns]);

  const columnOptions = props.columns.map((column, index) => ({
    value: column.id || `column-${index + 1}`,
    label: column.name || `Column ${index + 1}`,
  }));

  const emitTaskUpdate = async (payload: {
    action: string;
    taskId: string;
    data: TaskItem;
  }) => {
    if (props.taskUpdate) {
      await props.taskUpdate(payload);
    }
    if (props.onTaskUpdate) {
      await props.onTaskUpdate(payload);
    }
  };

  const handleMoveTask = async (taskId: string, nextColumn: string) => {
    const task = boardTasks.find((item) => item.id === taskId);
    if (!task || !nextColumn || task.column === nextColumn) return;

    const updatedTask: TaskItem = { ...task, column: nextColumn };
    setBoardTasks((current) => current.map((item) => (item.id === taskId ? updatedTask : item)));
    await emitTaskUpdate({ action: 'move', taskId, data: updatedTask });
  };

  const startEditing = (task: TaskItem) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
    setEditError('');
  };

  const cancelEditing = () => {
    setEditingTaskId(null);
    setEditingTitle('');
    setEditError('');
  };

  const saveEditing = async (task: TaskItem) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) {
      setEditError('Task title is required.');
      return;
    }

    const updatedTask: TaskItem = { ...task, title: trimmed };
    setBoardTasks((current) => current.map((item) => (item.id === task.id ? updatedTask : item)));
    setEditingTaskId(null);
    setEditingTitle('');
    setEditError('');
    await emitTaskUpdate({ action: 'edit', taskId: task.id, data: updatedTask });
  };

  const handleCreateTask = async () => {
    const trimmed = newTaskTitle.trim();

    if (!trimmed) {
      setCreateError('Please enter a task title.');
      setSubmitSuccess('');
      return;
    }

    setCreateError('');
    setSubmitError('');
    setSubmitSuccess('');
    setIsSubmitting(true);

    const createdTask: TaskItem = {
      id: `task-${Date.now()}`,
      title: trimmed,
      priority: newTaskPriority,
      assignee: '',
      column: defaultColumnId,
      dueDate: '',
    };

    try {
      if (props.onSubmit) {
        await props.onSubmit({
          title: trimmed,
          priority: newTaskPriority,
          column: defaultColumnId,
        });
      }

      setBoardTasks((current) => [...current, createdTask]);
      await emitTaskUpdate({
        action: 'create',
        taskId: createdTask.id,
        data: createdTask,
      });

      setSubmitSuccess('Task created successfully.');
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setOpenAddColumn(null);
    } catch (error) {
      setSubmitError(error instanceof Error ? error.message : 'Unable to create task.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card
          padding="var(--ggui-spacing-4, 16px)"
          shadow="sm"
          radius="lg"
          border
        >
          <Stack
            direction="horizontal"
            justify="between"
            align="center"
            wrap
            gap="var(--ggui-spacing-4, 16px)"
          >
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Task board
              </Text>
              <Text
                variant="bodyLarge"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                Kanban Overview
              </Text>
            </Stack>

            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
              <Card
                padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                shadow="none"
                radius="md"
                border
              >
                <Stack gap={2}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Total Tasks
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {totalTasks}
                  </Text>
                </Stack>
              </Card>

              <Card
                padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                shadow="none"
                radius="md"
                border
              >
                <Stack gap={2}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Completed
                  </Text>
                  <Text
                    variant="body"
                    weight="semibold"
                    color="var(--ggui-color-success-600, #16a34a)"
                  >
                    {completedCount}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          </Stack>
        </Card>

        {submitSuccess ? (
          <Alert variant="success" title="Success">
            {submitSuccess}
          </Alert>
        ) : null}

        {submitError ? (
          <Alert variant="error" title="Error">
            {submitError}
          </Alert>
        ) : null}

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-4, 16px)"
          wrap
          align="start"
        >
          {props.columns.map((column, columnIndex) => {
            const columnId = column.id || `column-${columnIndex + 1}`;
            const columnName = column.name || `Column ${columnIndex + 1}`;
            const tasksInColumn = boardTasks.filter((task) => task.column === columnId);
            const isAddOpen = openAddColumn === columnId;

            return (
              <Box
                key={columnId}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                padding="var(--ggui-spacing-2, 8px)"
              >
                <Card
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="sm"
                  radius="lg"
                  border
                >
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text
                        variant="label"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {columnName}
                      </Text>
                      <Badge variant="secondary" size="sm">
                        {tasksInColumn.length}
                      </Badge>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-3, 12px)">
                      {tasksInColumn.map((task) => (
                        <Card
                          key={task.id}
                          padding="var(--ggui-spacing-3, 12px)"
                          shadow="sm"
                          radius="md"
                          border
                        >
                          <Stack gap="var(--ggui-spacing-3, 12px)">
                            <Stack
                              direction="horizontal"
                              justify="between"
                              align="start"
                              gap="var(--ggui-spacing-2, 8px)"
                            >
                              <Box padding={0}>
                                {editingTaskId === task.id ? (
                                  <Stack gap="var(--ggui-spacing-2, 8px)">
                                    <Input
                                      label="Edit task title"
                                      value={editingTitle}
                                      onChange={setEditingTitle}
                                      error={editError}
                                      placeholder={task.title}
                                      autoFocus
                                      disabled={isSubmitting}
                                      aria-label={`Edit title for ${task.title}`}
                                    />
                                    <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                                      <Button
                                        size="sm"
                                        variant="primary"
                                        onClick={() => saveEditing(task)}
                                        aria-label={`Save ${task.title}`}
                                      >
                                        Save
                                      </Button>
                                      <Button
                                        size="sm"
                                        variant="ghost"
                                        onClick={cancelEditing}
                                        aria-label={`Cancel editing ${task.title}`}
                                      >
                                        Cancel
                                      </Button>
                                    </Stack>
                                  </Stack>
                                ) : (
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    onDoubleClick={() => startEditing(task)}
                                    aria-label={`Task ${task.title}. Double click to edit`}
                                  >
                                    <Text
                                      variant="body"
                                      weight="medium"
                                      color="var(--ggui-color-onSurface, #18181b)"
                                    >
                                      {task.title}
                                    </Text>
                                  </Button>
                                )}
                              </Box>

                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => startEditing(task)}
                                aria-label={`Edit ${task.title}`}
                                leftIcon={<Icon name="settings" size={14} />}
                              >
                                Edit
                              </Button>
                            </Stack>

                            <Stack
                              direction="horizontal"
                              justify="between"
                              align="center"
                              wrap
                              gap="var(--ggui-spacing-2, 8px)"
                            >
                              <Badge variant={priorityBadgeVariant[task.priority]} size="sm">
                                {task.priority}
                              </Badge>

                              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                                <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                                <Text
                                  variant="caption"
                                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                                >
                                  {task.assignee || 'Unassigned'}
                                </Text>
                              </Stack>
                            </Stack>

                            <Stack
                              direction="horizontal"
                              justify="between"
                              align="center"
                              wrap
                              gap="var(--ggui-spacing-2, 8px)"
                            >
                              <Text
                                variant="caption"
                                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                              >
                                {task.dueDate ? `Due ${task.dueDate}` : 'No due date'}
                              </Text>

                              <Select
                                label="Move task"
                                value={task.column}
                                onChange={(value) => handleMoveTask(task.id, value)}
                                options={columnOptions}
                                size="sm"
                                aria-label={`Move ${task.title} to another column`}
                              />
                            </Stack>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>

                    {isAddOpen ? (
                      <Card
                        padding="var(--ggui-spacing-3, 12px)"
                        shadow="none"
                        radius="md"
                        border
                      >
                        <Stack gap="var(--ggui-spacing-3, 12px)">
                          <Input
                            label="Task title"
                            value={newTaskTitle}
                            onChange={setNewTaskTitle}
                            placeholder="Enter task title"
                            required
                            error={createError}
                            disabled={isSubmitting}
                            aria-label={`New task title for ${columnName}`}
                          />

                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={(value) => setNewTaskPriority(value as Priority)}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                            disabled={isSubmitting}
                          />

                          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                            <Button
                              variant="primary"
                              size="sm"
                              loading={isSubmitting}
                              onClick={handleCreateTask}
                              aria-label={`Submit new task for ${columnName}`}
                            >
                              Submit
                            </Button>

                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => {
                                setOpenAddColumn(null);
                                setCreateError('');
                              }}
                              disabled={isSubmitting}
                              aria-label={`Cancel adding task in ${columnName}`}
                            >
                              Cancel
                            </Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : null}

                    <Button
                      variant="outline"
                      size="sm"
                      fullWidth
                      onClick={() => {
                        setOpenAddColumn(columnId);
                        setSubmitError('');
                        setSubmitSuccess('');
                        setCreateError('');
                      }}
                      leftIcon={<Icon name="plus" size={16} />}
                      aria-label={`Add task to ${columnName}`}
                    >
                      Add Task
                    </Button>
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

export const __GGUI_META__ = {
