import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Box, Heading, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

type ElementItem = Props['elements'][number];

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  metalloid: 'var(--ggui-color-success-100, #dcfce7)',
  nonmetal: 'var(--ggui-color-info-100, #cffafe)',
  halogen: 'var(--ggui-color-warning-100, #fef3c7)',
  'noble gas': 'var(--ggui-color-primary-50, #f0f9ff)',
  lanthanide: 'var(--ggui-color-container, #ede9fe)',
  actinide: 'var(--ggui-color-primary-200, #bae6fd)',
  unknown: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
};

function normalizeCategory(category?: string): string {
  return (category || 'unknown').trim().toLowerCase();
}

function getCategoryColor(category?: string): string {
  return categoryColorMap[normalizeCategory(category)] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
}

function formatCategory(category?: string): string {
  const value = category || 'Unknown';
  return value
    .split(/[-\s]+/)
    .map((part) => (part ? part.charAt(0).toUpperCase() + part.slice(1) : part))
    .join(' ');
}

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [query, setQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(elements[0]?.atomicNumber);

  const filteredElements = useMemo(() => {
    const search = query.trim().toLowerCase();
    if (!search) return elements;
    return elements.filter((item) => {
      const name = (item.name || '').toLowerCase();
      const symbol = (item.symbol || '').toLowerCase();
      return name.includes(search) || symbol.includes(search);
    });
  }, [elements, query]);

  const selectedElement = useMemo(() => {
    const inFiltered = filteredElements.find((item) => item.atomicNumber === selectedAtomicNumber);
    return inFiltered || filteredElements[0] || elements.find((item) => item.atomicNumber === selectedAtomicNumber) || elements[0];
  }, [elements, filteredElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const unique = new Map<string, string>();
    elements.forEach((item) => {
      const key = normalizeCategory(item.category);
      if (!unique.has(key)) {
        unique.set(key, formatCategory(item.category));
      }
    });
    if (!unique.size) {
      unique.set('unknown', 'Unknown');
    }
    return Array.from(unique.entries()).map(([key, label]) => ({ key, label }));
  }, [elements]);

  return (
    <Card padding={24} shadow="md" radius="xl" border>
      <Stack gap={20}>
        <Stack gap={6}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            Periodic Table of Elements
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Search by element name or symbol, then select a cell to inspect its details.
          </Text>
        </Stack>

        <Stack gap={6}>
          <Text as="label" variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Search elements
          </Text>
          <Input
            label="Search elements"
            type="search"
            value={query}
            onChange={setQuery}
            placeholder="Search by name or symbol"
            helperText="Filters the periodic table case-insensitively."
            aria-label="Search elements by name or symbol"
          />
        </Stack>

        <Box
          padding={16}
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
              gap: 'var(--ggui-spacing-2, 8px)',
              alignItems: 'stretch',
            }}
          >
            {filteredElements.map((item: ElementItem) => {
              const isSelected = item.atomicNumber === selectedElement?.atomicNumber;
              return (
                <button
                  key={`${item.atomicNumber ?? item.symbol ?? item.name}`}
                  type="button"
                  role="gridcell"
                  aria-label={`${item.name || 'Unknown'} (${item.symbol || '?'})`}
                  aria-pressed={isSelected}
                  onClick={() => setSelectedAtomicNumber(item.atomicNumber)}
                  style={{
                    gridColumn: item.col,
                    gridRow: item.row,
                    minHeight: '84px',
                    position: 'relative',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    background: getCategoryColor(item.category),
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    cursor: 'pointer',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                    outlineOffset: '2px',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    }}
                  >
                    {item.atomicNumber ?? '—'}
                  </span>

                  <span
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      height: '100%',
                      fontSize: 'var(--ggui-font-size-2xl, 24px)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      textAlign: 'center',
                    }}
                  >
                    {item.symbol || '?'}
                  </span>
                </button>
              );
            })}
          </div>
        </Box>

        <Stack gap={10}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Legend
          </Text>
          <Stack direction="horizontal" gap={8} wrap>
            {categories.map((category) => (
              <Badge key={category.key} variant="default" size="md">
                <span
                  style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  <span
                    aria-hidden="true"
                    style={{
                      width: '10px',
                      height: '10px',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: getCategoryColor(category.key),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    }}
                  />
                  {category.label}
                </span>
              </Badge>
            ))}
          </Stack>
        </Stack>

        <Card padding={20} radius="lg" border shadow="sm">
          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Element Details
            </Text>

            {selectedElement ? (
              <Stack gap={10}>
                <Stack direction="horizontal" gap={12} align="center" wrap>
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {selectedElement.name || 'Unknown Element'}
                  </Heading>
                  <Badge variant="primary" size="lg">
                    {selectedElement.symbol || '?'}
                  </Badge>
                </Stack>

                <Stack direction="horizontal" gap={8} wrap>
                  <Badge variant="secondary">Atomic Number: {selectedElement.atomicNumber ?? '—'}</Badge>
                  <Badge variant="info">Atomic Weight: {selectedElement.atomicWeight ?? '—'}</Badge>
                  <Badge variant="success">{formatCategory(selectedElement.category)}</Badge>
                </Stack>

                <Stack gap={4}>
                  <Text variant="body">
                    <Text as="span" weight="semibold">Name:</Text> {selectedElement.name || '—'}
                  </Text>
                  <Text variant="body">
                    <Text as="span" weight="semibold">Symbol:</Text> {selectedElement.symbol || '—'}
                  </Text>
                  <Text variant="body">
                    <Text as="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber ?? '—'}
                  </Text>
                  <Text variant="body">
                    <Text as="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight ?? '—'}
                  </Text>
                  <Text variant="body">
                    <Text as="span" weight="semibold">Category:</Text> {formatCategory(selectedElement.category)}
                  </Text>
                </Stack>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No element matches the current search.
              </Text>
            )}
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

export const __GGUI_META__ = {
