import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Button, Card, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type MessageItem = { sender?: string; text?: string; timestamp?: string };
type MessageGroup = { sender?: string; items: MessageItem[]; isCurrentUser: boolean };

const formatTimestamp = (timestamp?: string): string => {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return timestamp;
  return date.toLocaleTimeString([], {
    hour: 'numeric',
    minute: '2-digit',
  });
};

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
  } = props;

  const [draft, setDraft] = useState('');
  const messageListRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const node = messageListRef.current;
    if (node) {
      node.scrollTop = node.scrollHeight;
    }
  }, []);

  useEffect(() => {
    const node = messageListRef.current;
    if (node) {
      node.scrollTop = node.scrollHeight;
    }
  }, [messages]);

  const groupedMessages = useMemo<MessageGroup[]>(() => {
    return messages.reduce<MessageGroup[]>((groups, message) => {
      const sender = message.sender || '';
      const isCurrentUser = sender === currentUser;
      const previousGroup = groups[groups.length - 1];

      if (previousGroup && (previousGroup.sender || '') === sender) {
        previousGroup.items.push(message);
        return groups;
      }

      groups.push({
        sender: message.sender,
        items: [message],
        isCurrentUser,
      });

      return groups;
    }, []);
  }, [messages, currentUser]);

  const canSend = draft.trim().length > 0;

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;

    const payload = {
      text,
      timestamp: new Date().toISOString(),
    };

    sendMessage?.(payload);
    setDraft('');
  };

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      radius="lg"
      shadow="sm"
      border
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-2, 8px)">
          <Text
            variant="label"
            size="lg"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>

          {typeof participantCount === 'number' ? (
            <Badge variant="primary" size="sm">
              {participantCount}
            </Badge>
          ) : null}
        </Stack>

        <div
