import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Heading, Spinner, Box, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type StreamPayload = {
  stocks?: Props['stocks'];
  lastUpdated?: string;
  loading?: boolean;
  connecting?: boolean;
};

type StockItem = Props['stocks'][number];

const formatNumber = (value?: number) => {
  const safeValue = typeof value === 'number' ? value : 0;
  return safeValue.toFixed(2);
};

const formatTimestamp = (value?: string) => {
  if (!value) return '—';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString();
};

const getChangeMeta = (change?: number) => {
  const positive = (change ?? 0) >= 0;
  return {
    color: positive
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)',
    accentSurface: positive
      ? 'var(--ggui-color-success-100, #dcfce7)'
      : 'var(--ggui-color-error-100, #fee2e2)',
    borderColor: positive
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)',
    arrow: positive ? '▲' : '▼',
    sign: positive ? '+' : '',
  };
};

function StockCard(item: StockItem) {
  const { symbol = '—', name = '—', price, change, changePercent } = item;
  const meta = getChangeMeta(change);

  return (
    <Card padding="var(--ggui-spacing-4, 16px)" radius="lg" shadow="sm" border>
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack gap="var(--ggui-spacing-1, 4px)">
          <Text as="div" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {symbol}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
            {name}
          </Text>
        </Stack>

        <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          ${formatNumber(price)}
        </Text>

        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-2, 8px)">
          <Text variant="label" color={meta.color}>
            {meta.sign}
            {formatNumber(change)}
          </Text>

          <Box
            padding="var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)"
            background={meta.accentSurface}
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
          >
            <Text as="div" variant="label" color={meta.color}>
              <span aria-hidden="true" style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>
                {meta.arrow}
              </span>
              {meta.sign}
              {formatNumber(changePercent)}%
            </Text>
          </Box>
        </Stack>
      </Stack>
    </Card>
  );
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [connecting, setConnecting] = useState<boolean>(true);
  const [loading, setLoading] = useState<boolean>(false);

  useEffect(() => {
    setLiveStocks(props.stocks);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const readyTimer = window.setTimeout(() => {
      setConnecting(false);
    }, 1200);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamPayload>;
      const detail = customEvent.detail || {};

      if (typeof detail.connecting === 'boolean') {
        setConnecting(detail.connecting);
      } else {
        setConnecting(false);
      }

      if (typeof detail.loading === 'boolean') {
        setLoading(detail.loading);
      }

      if (Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
      }

      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);

    return () => {
      window.clearTimeout(readyTimer);
      window.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  const statusText = useMemo(() => {
    if (connecting) return 'Connecting to live market feed';
    if (loading) return 'Updating live prices';
    return 'Live market data connected';
  }, [connecting, loading]);

  return (
    <>
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4, 16px)">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  Market Watch
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated: {formatTimestamp(liveLastUpdated)}
                </Text>
              </Stack>

              <Card padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" radius="xl" shadow="none" border>
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                  {connecting || loading ? (
                    <Spinner
                      size={18}
                      color={connecting ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-warning-500, #f59e0b)'}
                    />
                  ) : (
                    <Box
                      background="var(--ggui-color-success-500, #22c55e)"
                      borderRadius="var(--ggui-shape-radius-full, 9999px)"
                      padding={0}
                    >
                      <span aria-hidden="true" style={{ width: '10px', height: '10px', display: 'block' }} />
                    </Box>
                  )}
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {statusText}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          </Stack>
        </Card>

        <Box background="transparent" borderRadius={0} padding={0}>
          <div
            role="list"
            aria-label="Stock prices"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {liveStocks.map((stock, index) => {
              const meta = getChangeMeta(stock.change);
              return (
                <Box
                  key={`${stock.symbol ?? 'stock'}-${index}`}
                  margin={0}
                  padding={0}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                >
                  <div
                    role="listitem"
                    aria-label={`${stock.symbol ?? 'Stock'} price card`}
                    style={{
                      border: `1px solid ${meta.borderColor}`,
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      animation: 'ggui-slideInUp 200ms ease-out both',
                    }}
                  >
                    <StockCard
                      symbol={stock.symbol}
                      name={stock.name}
                      price={stock.price}
                      change={stock.change}
                      changePercent={stock.changePercent}
                    />
                  </div>
                </Box>
              );
            })}
          </div>
        </Box>
      </Stack>
    </>
  );
}

const __GGUI_META__ = {
  category: 'dashboard',
  description:
    'A live-updating stock ticker dashboard with responsive stock cards, live connection states, and positive or negative market change indicators.',
};

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Progress,
  RadioGroup,
  Select,
  Toggle,
  Badge,
  MotionKeyframes,
  useMotion,
  Heading,
} from '@ggui-ai/design/primitives';

export interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

type WizardData = {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
};

const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(initialProfile.name ?? '');
  const [email, setEmail] = useState(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(initialProfile.theme ?? 'light');
  const [touched, setTouched] = useState({
    name: false,
    email: false,
    role: false,
  });

  const stepTitles = useMemo(
    () => ['Profile Setup', 'Preferences', 'Review & Confirm'],
    []
  );

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email
    ? !email.trim()
      ? 'Email is required.'
      : !isValidEmail(email)
        ? 'Enter a valid email address.'
        : ''
    : '';
  const roleError = touched.role && !role ? 'Please select a role.' : '';

  const isStepOneValid = Boolean(name.trim() && email.trim() && isValidEmail(email) && avatar);
  const isStepTwoValid = Boolean(role);
  const isCurrentStepValid =
    currentStep === 1 ? isStepOneValid : currentStep === 2 ? isStepTwoValid : true;

  const completionData: WizardData = {
    name: name.trim(),
    email: email.trim(),
    avatar,
    role,
    emailNotifications,
    theme,
  };

  const handleNext = () => {
    if (currentStep === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!isStepOneValid) return;
    }

    if (currentStep === 2) {
      setTouched((prev) => ({ ...prev, role: true }));
      if (!isStepTwoValid) return;
    }

    setCurrentStep((prev) => Math.min(prev + 1, 3));
  };

  const handleBack = () => {
    setCurrentStep((prev) => Math.max(prev - 1, 1));
  };

  const handleComplete = () => {
    setTouched({ name: true, email: true, role: true });
    if (!isStepOneValid || !isStepTwoValid) return;
    onComplete?.(completionData);
  };

  const panelAnimation = motionEnabled ? 'ggui-slideInUp 200ms ease-out' : 'none';

  return (
    <>
      <MotionKeyframes />
      <Card padding={24} shadow="md" radius="xl" border>
        <Stack gap={24}>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center" wrap>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                {stepTitles[currentStep - 1]}
              </Heading>
              <Badge variant="primary" size="md">
                {currentStep}/3
              </Badge>
            </Stack>

            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep} of 3
            </Text>

            <Progress value={currentStep} max={3} size="md" variant="default" />
          </Stack>

          <Card
            padding={20}
            shadow="none"
            radius="lg"
            border
          >
            <Stack gap={16}>
              {currentStep === 1 && (
                <Stack gap={16}>
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurface, #18181b)"
                    as="div"
                  >
                    Profile details
                  </Text>

                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    required
                    error={nameError}
                    placeholder="Enter your name"
                    onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                    aria-label="Name"
                  />

                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    required
                    error={emailError}
                    helperText={!emailError ? 'Use the email address for your account.' : undefined}
                    placeholder="Enter your email"
                    onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                    aria-label="Email"
                  />

                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)" as="div">
                      Choose an avatar
                    </Text>
                    <Stack direction="horizontal" gap={12} wrap>
                      {avatarOptions.map((option) => {
                        const selected = avatar === option;
                        return (
                          <Button
                            key={option}
                            variant={selected ? 'primary' : 'outline'}
                            size="lg"
                            aria-label={`Select avatar ${option}`}
                            aria-pressed={selected}
                            onClick={() => setAvatar(option)}
                          >
                            {option}
                          </Button>
                        );
                      })}
                    </Stack>
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={16}>
                  <div style={{ animation: panelAnimation }}>
                    <Select
                      label="Role"
                      value={role}
                      onChange={setRole}
                      options={roleOptions.map((option) => ({ value: option, label: option }))}
                      placeholder="Select a role"
                      error={roleError}
                      onBlur={() => setTouched((prev) => ({ ...prev, role: true }))}
                    />
                  </div>

                  <div style={{ animation: panelAnimation }}>
                    <Toggle
                      label="Email notifications"
                      checked={emailNotifications}
                      onChange={setEmailNotifications}
                      size="md"
                    />
                  </div>

                  <div style={{ animation: panelAnimation }}>
                    <RadioGroup
                      label="Theme preference"
                      value={theme}
                      onChange={setTheme}
                      direction="horizontal"
                      options={[
                        { value: 'light', label: 'Light', description: 'Bright interface' },
                        { value: 'dark', label: 'Dark', description: 'Dim interface' },
                      ]}
                    />
                  </div>
                </Stack>
              )}

              {currentStep === 3 && (
                <div style={{ animation: panelAnimation }}>
                  <Stack gap={16}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)" as="div">
                      Review your selections
                    </Text>

                    <Card padding={16} shadow="none" radius="lg" border>
                      <Stack gap={12}>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Name
                          </Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                            {completionData.name || '—'}
                          </Text>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Email
                          </Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                            {completionData.email || '—'}
                          </Text>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Avatar
                          </Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                            {completionData.avatar || '—'}
                          </Text>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Role
                          </Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                            {completionData.role || '—'}
                          </Text>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Notifications
                          </Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                            {completionData.emailNotifications ? 'On' : 'Off'}
                          </Text>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Theme
                          </Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                            {completionData.theme || '—'}
                          </Text>
                        </Stack>
                      </Stack>
                    </Card>
                  </Stack>
                </div>
              )}
            </Stack>
          </Card>

          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Button
              variant="ghost"
              size="md"
              onClick={handleBack}
              disabled={currentStep === 1}
              aria-label="Go back"
            >
              Back
            </Button>

            <Stack direction="horizontal" gap={12}>
              {currentStep < 3 ? (
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleNext}
                  disabled={!isCurrentStepValid}
                  aria-label="Next step"
                >
                  Next
                </Button>
              ) : (
                <>
                  <Button
                    variant="outline"
                    size="md"
                    onClick={handleBack}
                    aria-label="Go back to edit"
                  >
                    Go Back
                  </Button>
                  <Button
                    variant="primary"
                    size="md"
                    onClick={handleComplete}
                    aria-label="Complete setup"
                  >
                    Complete Setup
                  </Button>
                </>
              )}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

