import React, { useState, useEffect } from 'react';
import {
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Divider,
  Progress,
  Icon,
} from '@ggui-ai/design/primitives';

/**
 * KanbanBoard Component
 * Implements a Kanban-style task board with 3 columns (To Do, In Progress, Done).
 * Features task creation, editing, and movement between columns with priority coding.
 */

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
}

export default function KanbanBoard(props: Props) {
  const { tasks = [], columns = [] } = props;

  // Action contract callback wired from props
  const onTaskUpdate = (props as any).onTaskUpdate;

  // Local state to manage task interactivity
  const [localTasks, setLocalTasks] = useState<any[]>([]);
  const [activeAddCol, setActiveAddCol] = useState<string | null>(null);
  const [editTaskId, setEditTaskId] = useState<string | null>(null);
  const [isBusy, setIsBusy] = useState(false);

  // Draft state for new tasks
  const [draftTitle, setDraftTitle] = useState('');
  const [draftPriority, setDraftPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync props to internal state
  useEffect(() => {
    setLocalTasks(tasks.map((t, idx) => ({
      id: t.id || `task-${idx}-${Date.now()}`,
      title: t.title || 'Untitled Task',
      priority: t.priority || 'medium',
      assignee: t.assignee || '?',
      column: t.column || (columns[0]?.id || 'todo'),
      dueDate: t.dueDate,
    })));
  }, [tasks, columns]);

  // Derived stats
  const totalTasks = localTasks.length;
  const lastColId = columns[columns.length - 1]?.id;
  const completedCount = localTasks.filter(t => t.column === lastColId).length;
  const progressPercent = totalTasks > 0 ? Math.round((completedCount / totalTasks) * 100) : 0;

  // Interaction handlers
  const notify = (action: 'move' | 'edit' | 'create', taskId?: string, data?: any) => {
    if (onTaskUpdate) {
      onTaskUpdate({ action, taskId, data });
    }
  };

  const handleMove = (tid: string, targetColId: string) => {
    setLocalTasks(prev => prev.map(t => t.id === tid ? { ...t, column: targetColId } : t));
    notify('move', tid, { column: targetColId });
  };

  const handleCreate = (colId: string) => {
    if (!draftTitle.trim()) return;
    setIsBusy(true);

    // Simulate "Collect" interaction with submission state
    setTimeout(() => {
      const newTask = {
        id: `t-${Date.now()}`,
        title: draftTitle,
        priority: draftPriority,
        assignee: 'ME',
        column: colId,
      };

      setLocalTasks(prev => [...prev, newTask]);
      notify('create', undefined, newTask);

      // Reset form
      setDraftTitle('');
      setActiveAddCol(null);
      setIsBusy(false);
    }, 400);
  };

  const handleSaveEdit = (tid: string, newTitle: string) => {
    setLocalTasks(prev => prev.map(t => t.id === tid ? { ...t, title: newTitle } : t));
    setEditTaskId(null);
    notify('edit', tid, { title: newTitle });
  };

  const getPriorityVariant = (p: string) => {
    switch (p) {
      case 'high': return 'error';
      case 'low': return 'info';
      default: return 'warning';
    }
  };

  return (
    <Box padding={24} background="var(--ggui-color-surface)" borderRadius={16}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding={20} radius="lg" shadow="sm">
          <Stack direction="horizontal" justify="between" align="center" wrap gap={32}>
            <Stack direction="horizontal" gap={24} align="center">
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Project Board</Text>
                <Heading level={2}>Dashboard</Heading>
              </Box>
              <Divider orientation="vertical" margin={12} />
              <Stack direction="horizontal" gap={16}>
                <Box>
                  <Text size="xs" weight="bold" color="var(--ggui-color-onSurfaceVariant)">TOTAL</Text>
                  <Text size="2xl" weight="bold">{totalTasks}</Text>
                </Box>
                <Box>
                  <Text size="xs" weight="bold" color="var(--ggui-color-onSurfaceVariant)">DONE</Text>
                  <Text size="2xl" weight="bold">{completedCount}</Text>
                </Box>
              </Stack>
            </Stack>

            <Box style={{ flex: 1, maxWidth: 320 }}>
              <Progress value={completedCount} max={totalTasks || 1} showLabel variant="success" size="lg" />
            </Box>
          </Stack>
        </Card>

        {/* Kanban Board Area */}
        <Stack direction="horizontal" gap={20} align="start" style={{ overflowX: 'auto', paddingBottom: 16 }}>
          {columns.map(column => {
            const columnItems = localTasks.filter(t => t.column === column.id);
            return (
              <Box 
                key={column.id} 
                background="var(--ggui-color-surfaceVariant)" 
                padding={16} 
                borderRadius={12} 
                style={{ minWidth: 340, flex: 1, border: '1px solid var(--ggui-color-outline)' }}
              >
                <Stack gap={16}>
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack direction="horizontal" gap={8} align="center">
                      <Heading level={6}>{column.name || 'Untitled'}</Heading>
                      <Badge variant="secondary" size="sm" pill>{columnItems.length}</Badge>
                    </Stack>
                    <Button 
                      variant="ghost" 
                      size="xs" 
                      onClick={() => { setActiveAddCol(column.id || ''); setDraftTitle(''); }}
                      aria-label="Add new task"
                    >
                      <Icon name="plus" size={16} />
                    </Button>
                  </Stack>

                  {/* Task List */}
                  <Stack gap={12}>
                    {columnItems.map(task => (
                      <Card key={task.id} padding={12} shadow="sm" radius="md">
                        <Stack gap={12}>
                          {editTaskId === task.id ? (
                            <Stack gap={8}>
                              <Input 
                                label="Edit Title"
                                value={task.title} 
                                onChange={val => setLocalTasks(prev => prev.map(t => t.id === task.id ? { ...t, title: val } : t))}
                                autoFocus
                              />
                              <Stack direction="horizontal" gap={8} justify="end">
                                <Button size="xs" variant="ghost" onClick={() => setEditTaskId(null)}>Cancel</Button>
                                <Button size="xs" variant="primary" onClick={() => handleSaveEdit(task.id, task.title)}>Save</Button>
                              </Stack>
                            </Stack>
                          ) : (
                            <Stack direction="horizontal" justify="between" align="start">
                              <div 
                                style={{ flex: 1, cursor: 'text' }} 
                                onDoubleClick={() => setEditTaskId(task.id)}
                              >
                                <Text weight="medium">{task.title}</Text>
                              </div>
                              <Button 
                                variant="ghost" 
                                size="xs" 
                                onClick={() => setEditTaskId(task.id)}
                                aria-label="Quick edit"
                              >
                                <Icon name="settings" size={14} />
                              </Button>
                            </Stack>
                          )}

                          <Stack direction="horizontal" justify="between" align="center">
                            <Stack direction="horizontal" gap={8} align="center">
                              <Badge variant={getPriorityVariant(task.priority)} size="sm">
                                {task.priority}
                              </Badge>
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.dueDate}
                                </Text>
                              )}
                            </Stack>
                            <Avatar name={task.assignee} size="xs" />
                          </Stack>

                          {/* Move Control */}
                          <Select 
                            label="Change Status"
                            size="sm"
                            value={task.column}
                            onChange={(val) => handleMove(task.id, val)}
                            options={columns.map(c => ({ value: c.id || '', label: `Move to ${c.name}` }))}
                          />
                        </Stack>
                      </Card>
                    ))}

                    {/* Task Collection Form (Interaction: Collect) */}
                    {activeAddCol === column.id ? (
                      <Card padding={12} shadow="md" radius="md" border={true} style={{ border: '1px solid var(--ggui-color-primary-300)' }}>
                        <Stack gap={12}>
                          <Input 
                            label="Task Title"
                            placeholder="What needs to be done?"
                            value={draftTitle}
                            onChange={setDraftTitle}
                            disabled={isBusy}
                            required
                          />
                          <Select 
                            label="Set Priority"
                            value={draftPriority}
                            onChange={val => setDraftPriority(val as any)}
                            disabled={isBusy}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Stack direction="horizontal" gap={8} justify="end">
                            <Button size="sm" variant="ghost" onClick={() => setActiveAddCol(null)} disabled={isBusy}>
                              Cancel
                            </Button>
                            <Button size="sm" variant="primary" loading={isBusy} onClick={() => handleCreate(column.id || '')}>
                              Create Task
                            </Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : (
                      <Button 
                        variant="ghost" 
                        fullWidth 
                        size="sm"
                        leftIcon={<Icon name="plus" size={16} />}
                        onClick={() => { setActiveAddCol(column.id || ''); setDraftTitle(''); }}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Box>
  );
}

