/**
 * Maps element categories to design system semantic roles and colors.
 * Uses CSS variables for theme-agnostic styling.
 */
const getCategoryTheme = (category?: string) => {
  const c = category?.toLowerCase() || '';
  if (c.includes('alkali metal')) return { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-700, #b91c1c)', border: 'var(--ggui-color-error-200, #fecaca)', badge: 'error' as const };
  if (c.includes('alkaline earth')) return { bg: 'var(--ggui-color-warning-50, #fffbeb)', text: 'var(--ggui-color-warning-700, #92400e)', border: 'var(--ggui-color-warning-200, #fde68a)', badge: 'warning' as const };
  if (c.includes('transition metal')) return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-neutral-700, #374151)', border: 'var(--ggui-color-neutral-200, #e5e7eb)', badge: 'secondary' as const };
  if (c.includes('lanthanide')) return { bg: 'var(--ggui-color-info-50, #ecfeff)', text: 'var(--ggui-color-info-700, #0e7490)', border: 'var(--ggui-color-info-200, #a5f3fc)', badge: 'info' as const };
  if (c.includes('actinide')) return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-700, #0369a1)', border: 'var(--ggui-color-primary-200, #bae6fd)', badge: 'primary' as const };
  if (c.includes('post-transition')) return { bg: 'var(--ggui-color-success-50, #f0fdf4)', text: 'var(--ggui-color-success-700, #15803d)', border: 'var(--ggui-color-success-200, #bbf7d0)', badge: 'success' as const };
  if (c.includes('metalloid')) return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-800, #075985)', border: 'var(--ggui-color-primary-300, #7dd3fc)', badge: 'primary' as const };
  if (c.includes('noble gas')) return { bg: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-900, #0c4a6e)', border: 'var(--ggui-color-primary-400, #38bdf8)', badge: 'primary' as const };
  if (c.includes('nonmetal')) return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-600, #0284c7)', border: 'var(--ggui-color-primary-100, #e0f2fe)', badge: 'primary' as const };
  return { bg: 'var(--ggui-color-neutral-50, #f9fafb)', text: 'var(--ggui-color-neutral-600, #4b5563)', border: 'var(--ggui-color-neutral-200, #e5e7eb)', badge: 'default' as const };
};

