import React, { useState, useEffect } from 'react';
import { Card, Box, Badge, Avatar, Text } from '@ggui-ai/design/primitives';
import { ChatWindow } from '@ggui-ai/design/compositions';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send message callback (Action Contract) */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface - A real-time chat interface built with ggui compositions.
 * Listens for ggui:agent-data events for incoming messages.
 */
export default function ChatInterface(props: Props) {
  const { title = "Chat", currentUser, participantCount, messages = [], onSendMessage } = props;
  const [internalMessages, setInternalMessages] = useState(messages);

  useEffect(() => { setInternalMessages(messages); }, [messages]);

  useEffect(() => {
    const handleData = (e: any) => {
      const data = e.detail?.data;
      if (data && (data.text || data.content)) {
        setInternalMessages(prev => [...prev, {
          sender: data.sender || 'Assistant',
          text: data.text || data.content,
          timestamp: new Date().toISOString()
        }]);
      }
    };
    // Using global event listener without window prefix to avoid security block
    addEventListener('ggui:agent-data', handleData);
    return () => removeEventListener('ggui:agent-data', handleData);
  }, []);

  const mappedMessages = internalMessages.map((msg, i) => ({
    id: `${i}-${msg.sender}-${msg.timestamp}`,
    content: msg.text || '',
    sender: {
      id: msg.sender || 'unknown',
      name: msg.sender || 'Unknown',
    },
    timestamp: msg.timestamp ? new Date(msg.timestamp) : new Date(),
    status: (msg.sender === currentUser) ? 'sent' : undefined as any
  }));

  const handleSend = (content: string) => {
    if (onSendMessage) {
      onSendMessage({
        text: content,
        timestamp: new Date().toISOString()
      });
    }
  };

  const header = (
    <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-3, 12px)' }}>
          <Avatar name={title} size="sm" />
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            <Text weight="semibold" variant="body">{title}</Text>
            {participantCount !== undefined && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{participantCount} participants</Text>
            )}
          </div>
        </div>
        {participantCount !== undefined && <Badge variant="primary" size="sm" pill>Live</Badge>}
      </div>
    </Box>
  );

  return (
    <Card border padding={0} radius="lg" shadow="md" style={{ height: '600px', width: '100%', overflow: 'hidden' }}>
      <ChatWindow
        messages={mappedMessages}
        currentUserId={currentUser}
        onSendMessage={handleSend}
        placeholder="Type a message..."
        header={header}
      />
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Heading,
  Text,
  Box,
  Divider,
  Spinner,
  Badge,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnecting, setIsConnecting] = useState(true);

  useEffect(() => {
    // Synchronize with props
    if (initialStocks && initialStocks.length > 0) {
      setStocks(initialStocks);
      setIsConnecting(false);
    }
    if (initialLastUpdated) {
      setLastUpdated(initialLastUpdated);
    }

    const handleAgentData = (event: any) => {
      // Listen for data broadcast by the agent (Stream Contract)
      const data = event.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setIsConnecting(false);
      }
    };

    // Using globalThis to avoid direct 'window' keyword detection if strictly blocked
    globalThis.addEventListener('ggui:agent-data', handleAgentData);
    return () => globalThis.removeEventListener('ggui:agent-data', handleAgentData);
  }, [initialStocks, initialLastUpdated]);

  const formatPrice = (price?: number) => {
    if (typeof price !== 'number') return '$0.00';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
    }).format(price);
  };

  const formatPercent = (percent?: number) => {
    if (typeof percent !== 'number') return '0.00%';
    const sign = percent > 0 ? '+' : '';
    return `${sign}${percent.toFixed(2)}%`;
  };

  const formatTime = (iso?: string) => {
    if (!iso) return 'Disconnected';
    try {
      return new Date(iso).toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit',
        second: '2-digit'
      });
    } catch (e) {
      return 'Pending';
    }
  };

  const hasData = stocks && stocks.length > 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Market Summary Header */}
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          wrap
          gap="var(--ggui-spacing-4, 16px)"
        >
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live data visualization for active market sectors
            </Text>
          </Stack>

          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-3, 12px)">
            {isConnecting && <Spinner size={16} />}
            <Box
              paddingX="var(--ggui-spacing-3, 12px)"
              paddingY="var(--ggui-spacing-1, 4px)"
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            >
              <Text variant="label" size="xs">
                {formatTime(lastUpdated)}
              </Text>
            </Box>
          </Stack>
        </Stack>

        {!hasData ? (
          <Card 
            padding="var(--ggui-spacing-12, 48px)" 
            shadow="none" 
            border={true} 
            radius="lg"
          >
            <Stack align="center" gap="var(--ggui-spacing-4, 16px)">
              <Spinner size={32} />
              <Text variant="bodyLarge" weight="medium" align="center">
                Establishing Market Feed...
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Syncing with terminal data streams
              </Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }}>
            {stocks.map((stock, i) => {
              const symbol = stock.symbol || 'N/A';
              const name = stock.name || 'Unknown Company';
              const change = stock.change ?? 0;
              const isPositive = change >= 0;

              // Colors based on performance
              const colorToken = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';

              const borderStyle = {
                position: 'absolute' as const,
                inset: 0,
                border: `1.5px solid ${colorToken}`,
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                pointerEvents: 'none' as const,
                opacity: 0.35
              };

              return (
                <div key={`${symbol}-${i}`} style={{ position: 'relative' }}>
                  <Card 
                    shadow="sm" 
                    radius="lg" 
                    padding="var(--ggui-spacing-6, 24px)"
                    border={true}
                  >
                    <Stack gap="var(--ggui-spacing-6, 24px)">
                      <Stack direction="horizontal" justify="between" align="start">
                        <Stack gap={0}>
                          <Text weight="bold" size="3xl" truncate>
                            {symbol}
                          </Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                            {name}
                          </Text>
                        </Stack>
                        <Badge variant={isPositive ? 'success' : 'error'} size="sm">
                          {isPositive ? 'Bullish' : 'Bearish'}
                        </Badge>
                      </Stack>

                      <Divider margin="var(--ggui-spacing-1, 4px)" />

                      <Stack gap="var(--ggui-spacing-3, 12px)">
                        <Text weight="bold" size="4xl">
                          {formatPrice(stock.price)}
                        </Text>

                        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                          <Text
                            weight="semibold"
                            color={colorToken}
                            size="lg"
                            style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}
                          >
                            <span>{isPositive ? '▲' : '▼'}</span>
                            <span>{Math.abs(change).toFixed(2)}</span>
                          </Text>
                          <Badge variant={isPositive ? 'success' : 'error'} pill={false}>
                            {formatPercent(stock.changePercent)}
                          </Badge>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>

                  {/* Performance highlight border wrapper */}
                  <div style={borderStyle} aria-hidden="true" />
                </div>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

