import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Divider,
  Box,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  /** Action Contract complete callback */
  complete?: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, complete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions[0]) || '',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const isValidEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const step1Valid = formData.name.trim().length > 0 && isValidEmail(formData.email);
  const step2Valid = formData.role !== '';

  const handleFinish = () => complete?.(formData);

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={24}>
        <Stack align="center" gap={8}>
          <Heading level={2}>Step {step} of 3</Heading>
          <div style={{ width: '100%', maxWidth: '300px' }}>
            <Progress value={(step / 3) * 100} size="sm" />
          </div>
        </Stack>

        <Card padding={24} shadow="md">
          {step === 1 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <label htmlFor="name" style={{ fontSize: '14px', fontWeight: 500 }}>Full Name</label>
                <Input label="Full Name" id="name" value={formData.name} onChange={v => setFormData({...formData, name: v})} required />
              </Stack>
              <Stack gap={4}>
                <label htmlFor="email" style={{ fontSize: '14px', fontWeight: 500 }}>Email Address</label>
                <Input label="Email Address" id="email" type="email" value={formData.email} onChange={v => setFormData({...formData, email: v})} required error={formData.email && !isValidEmail(formData.email) ? 'Invalid email' : ''} />
              </Stack>
              <Stack gap={12}>
                <Text variant="label">Select Avatar</Text>
                <Stack direction="horizontal" gap={12}>
                  {avatarOptions.map(opt => (
                    <button key={opt} onClick={() => setFormData({...formData, avatar: opt})} style={{ fontSize: '24px', width: '48px', height: '48px', borderRadius: '50%', cursor: 'pointer', background: formData.avatar === opt ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surface)', border: `2px solid ${formData.avatar === opt ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}` }}>{opt}</button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}
          {step === 2 && (
            <Stack gap={24}>
              <Select label="Role" value={formData.role} onChange={v => setFormData({...formData, role: v})} options={roleOptions.map(r => ({ label: r, value: r }))} required />
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={v => setFormData({...formData, emailNotifications: v})} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={v => setFormData({...formData, theme: v ? 'dark' : 'light'})} />
            </Stack>
          )}
          {step === 3 && (
            <Stack gap={24}>
              <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius={12}>
                <Stack direction="horizontal" gap={16} align="center">
                  <div style={{ fontSize: '32px' }}>{formData.avatar}</div>
                  <Stack gap={4}>
                    <Heading level={4}>{formData.name}</Heading>
                    <Text variant="bodySmall">{formData.email}</Text>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          )}
          <Spacer size={32} />
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={() => setStep(step - 1)}>Back</Button>
            {step < 3 ? (
              <Button disabled={step === 1 ? !step1Valid : !step2Valid} onClick={() => setStep(step + 1)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleFinish}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Heading, Text, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<ForecastItem>;
}

/**
 * WeatherCard component - Reusable display for current weather and 5-day forecast.
 * Built with ggui primitives and theme-aware CSS variables.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast
}: Props) {
  // Utility to map condition string to an emoji.
  const getWeatherIcon = (cond: string = '') => {
    const key = cond.toLowerCase();
    if (key.includes('sun')) return '☀️';
    if (key.includes('cloud')) return '☁️';
    if (key.includes('rain')) return '🌧️';
    if (key.includes('storm')) return '⛈️';
    if (key.includes('snow')) return '❄️';
    if (key.includes('mist') || key.includes('fog')) return '🌫️';
    return '🌡️';
  };

  return (
    <Card 
      padding={24} 
      radius="xl" 
      shadow="md" 
      border
      style={{
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        maxWidth: '450px'
      }}
    >
      <Stack gap={24}>
        {/* Header Section: City and Condition Text */}
        <Stack gap={4}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Hero Section: Large Temperature and Condition Icon */}
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {Math.round(temperature)}°{unit}
          </Heading>
          <div 
            style={{ 
              fontSize: 'var(--ggui-font-size-4xl, 48px)', 
              lineHeight: 1,
              userSelect: 'none'
            }} 
            aria-hidden="true"
          >
            {getWeatherIcon(condition)}
          </div>
        </Stack>

        {/* Current Details Section */}
        <Stack direction="horizontal" gap={16} justify="between">
          <Stack gap={2}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>
          <Stack gap={2}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind Speed
            </Text>
            <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Stack>

        <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="stretch" gap={8}>
          {forecast?.map((item, idx) => (
            <Stack 
              key={`${item.day}-${idx}`} 
              align="center" 
              gap={8} 
              style={{ 
                flex: '1 1 0'
              }}
            >
              <Text 
                variant="caption" 
                weight="medium" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.day}
              </Text>
              <div 
                style={{ 
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  userSelect: 'none'
                }} 
                aria-hidden="true"
              >
                {getWeatherIcon(item.icon)}
              </div>
              <Stack gap={0} align="center">
                <Text weight="semibold" size="sm" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high}°
                </Text>
                <Text 
                  variant="caption" 
                  size="xs" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Divider,
  Box,
  Heading,
  Progress,
  Icon,
} from '@ggui-ai/design/primitives';
import { Dropdown } from '@ggui-ai/design/components';

interface Props {
  tasks: Array<any>;
  columns: Array<any>;
}

export default function GeneratedComponent(props: Props) {
  const tasks = props.tasks || [];
  const columns = props.columns || [];
  const onTaskUpdate = (props as any).onTaskUpdate;

  const [localTasks, setLocalTasks] = useState(tasks);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [addingCol, setAddingCol] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  const stats = useMemo(() => {
    const totalCount = localTasks.length;
    const lastId = columns.length > 0 ? columns[columns.length - 1].id : null;
    const completedCount = localTasks.filter((t: any) => t.column === lastId).length;
    return { total: totalCount, completed: completedCount };
  }, [localTasks, columns]);

  return (
    <Stack gap={24} align="stretch" style={{ width: '100%' }}>
      <Card padding={24} shadow="sm" radius="lg" border>
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={3}>Project Dashboard</Heading>
            <Text variant="label" weight="semibold">{stats.completed} / {stats.total} Tasks Completed</Text>
          </Stack>
          <Progress value={stats.completed} max={stats.total} variant="success" size="md" />
        </Stack>
      </Card>

      <Box style={{ overflowX: 'auto', paddingBottom: 16 }}>
        <Stack direction="horizontal" gap={20} align="start" style={{ minWidth: 'max-content' }}>
          {columns.map((col: any) => {
            const list = localTasks.filter((t: any) => t.column === col.id);
            return (
              <Box key={col.id || 'unknown'} style={{ width: 320, backgroundColor: 'var(--ggui-color-surfaceVariant)', borderRadius: 12, padding: 16, display: 'flex', flexDirection: 'column', gap: 16 }}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text weight="bold" size="lg">{col.name}</Text>
                    <Badge variant="secondary" size="sm" pill>{list.length}</Badge>
                  </Stack>
                  <Button variant="ghost" size="xs" onClick={() => setAddingCol(addingCol === col.id ? null : col.id)}><Icon name="plus" size={16} /></Button>
                </Stack>

                <Stack gap={12}>
                  {list.map((task: any) => (
                    <Card key={task.id} padding={16} shadow="sm" radius="md" border style={{ backgroundColor: 'var(--ggui-color-surface)' }}>
                      <Stack gap={12}>
                        <Stack direction="horizontal" justify="between">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'} size="sm">{task.priority?.toUpperCase()}</Badge>
                          <Dropdown trigger={<Button variant="ghost" size="xs"><Icon name="menu" size={16} /></Button>} options={columns.filter((c: any) => c.id !== task.column).map((c: any) => ({ value: c.id || '', label: `Move to ${c.name}` }))} onChange={(val) => {
                            const next = localTasks.map((t: any) => (t.id === task.id ? { ...t, column: val } : t));
                            setLocalTasks(next);
                            onTaskUpdate?.({ action: 'move', taskId: task.id, data: { column: val } });
                          }} />
                        </Stack>
                        {editingId === task.id ? (
                          <Input label="Edit Task" value={task.title || ''} onChange={(v) => setLocalTasks(localTasks.map((t: any) => t.id === task.id ? { ...t, title: v } : t))} onBlur={() => { setEditingId(null); onTaskUpdate?.({ action: 'edit', taskId: task.id, data: { title: task.title } }); }} autoFocus />
                        ) : (
                          <div onDoubleClick={() => setEditingId(task.id)} style={{ cursor: 'pointer' }}><Text variant="body" weight="medium">{task.title}</Text></div>
                        )}
                        <Divider margin={0} />
                        <Stack direction="horizontal" justify="between" align="center">
                          <Stack direction="horizontal" gap={8} align="center">
                            <Avatar name={task.assignee || 'User'} size="xs" />
                            {task.dueDate && <Text variant="caption">{task.dueDate}</Text>}
                          </Stack>
                          <Button variant="ghost" size="xs" onClick={() => setEditingId(task.id)}>Edit</Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingCol === col.id ? (
                  <Card padding={16} radius="lg" border shadow="md" style={{ backgroundColor: 'var(--ggui-color-surface)' }}>
                    <Stack gap={12}>
                      <Input label="New Task Title" placeholder="What to do?" value={newTitle} onChange={setNewTitle} autoFocus />
                      <Select label="Priority" value={newPriority} onChange={(v) => setNewPriority(v as any)} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} size="sm" />
                      <Stack direction="horizontal" gap={8} justify="end">
                        <Button variant="ghost" size="sm" onClick={() => setAddingCol(null)}>Cancel</Button>
                        <Button variant="primary" size="sm" onClick={() => {
                          if (!newTitle.trim()) return;
                          const t = { id: `task-${Date.now()}`, title: newTitle, priority: newPriority, column: col.id, assignee: '??' };
                          setLocalTasks([...localTasks, t]);
                          setNewTitle('');
                          setAddingCol(null);
                          onTaskUpdate?.({ action: 'create', data: t });
                        }}>Create</Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="ghost" fullWidth size="sm" leftIcon={<Icon name="plus" size={16} />} onClick={() => setAddingCol(col.id)}>Add Task</Button>
                )}
              </Box>
            );
          })}
        </Stack>
      </Box>
    </Stack>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to ggui design system variants.
 */
const getCategoryVariant = (
  category: string = ''
):
  | 'primary'
  | 'secondary'
  | 'success'
  | 'warning'
  | 'error'
  | 'info'
  | 'default' => {
  const cat = category.toLowerCase();
  if (cat.includes('alkali metal')) return 'error';
  if (cat.includes('alkaline earth')) return 'warning';
  if (cat.includes('transition metal')) return 'secondary';
  if (cat.includes('metalloid')) return 'success';
  if (cat.includes('noble gas')) return 'info';
  if (cat.includes('nonmetal') || cat.includes('halogen')) return 'primary';
  return 'default';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(
    null
  );

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements.map(el => ({ ...el, isMatch: true }));
    return elements.map((el) => ({
      ...el,
      isMatch:
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query),
    }));
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const unique = Array.from(
      new Set(elements.map((e) => e.category).filter(Boolean))
    );
    return (unique as string[]).sort();
  }, [elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={32}>
        {/* Header and Search */}
        <Stack gap={16}>
          <Heading level={1}>Periodic Table of Elements</Heading>
          <SearchField
            placeholder="Search elements by name or symbol..."
            value={searchQuery}
            onChange={setSearchQuery}
            size="lg"
          />
        </Stack>

        {/* Legend */}
        <Stack direction="horizontal" gap={8} wrap align="center">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
