import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  TextArea,
  Badge,
  Avatar,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount, messages = [], onSendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const send = () => {
    if (!inputValue.trim()) return;
    onSendMessage({ text: inputValue.trim(), timestamp: new Date().toISOString() });
    setInputValue('');
  };

  return (
    <Card padding={0} shadow="lg" radius="xl" border style={{ height: '600px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
        <Stack direction="horizontal" align="center" gap={12}>
          <Heading level={3}>{title}</Heading>
          {participantCount !== undefined && <Badge variant="primary">{participantCount}</Badge>}
        </Stack>
      </Box>

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)', backgroundColor: 'var(--ggui-color-surface)' }}>
        {messages.map((m, i) => (
          <Stack key={i} align={m.sender === currentUser ? 'end' : 'start'} gap={4}>
            <Box paddingX={12} paddingY={8} borderRadius={12} style={{
              maxWidth: '80%',
              backgroundColor: m.sender === currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)',
              color: m.sender === currentUser ? '#fff' : 'var(--ggui-color-onSurface)',
              borderBottomRightRadius: m.sender === currentUser ? 'var(--ggui-spacing-1)' : 'var(--ggui-shape-radius-lg)',
              borderBottomLeftRadius: m.sender === currentUser ? 'var(--ggui-shape-radius-lg)' : 'var(--ggui-spacing-1)'
            }}>
              <Text variant="bodySmall" color="inherit">{m.text}</Text>
            </Box>
          </Stack>
        ))}
      </div>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline)' }}>
        <Stack gap={12}>
          <TextArea
            label="Message"
            rows={1}
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); send(); } }}
          />
          <Button variant="primary" fullWidth disabled={!inputValue.trim()} onClick={send}>Send Message</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Text,
  Heading,
  Card,
  Spinner,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

/**
 * Stock Ticker Dashboard
 * 
 * Displays a live-updating grid of stock prices with color-coded performance indicators.
 * Listens for agent data streams to update prices reactively.
 */

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  // Use state to manage live updates from the agent stream
  const [liveStocks, setLiveStocks] = useState<Stock[]>(stocks);
  const [lastUpdate, setLastUpdate] = useState<string | undefined>(initialLastUpdated);
  const [isLoading, setIsLoading] = useState(stocks.length === 0);

  // Sync state when initial props change
  useEffect(() => {
    if (stocks && stocks.length > 0) {
      setLiveStocks(stocks);
      setIsLoading(false);
    }
    if (initialLastUpdated) {
      setLastUpdate(initialLastUpdated);
    }
  }, [stocks, initialLastUpdated]);

  // Stream Contract: Listen for 'ggui:agent-data' events
  // Note: We use the global addEventListener to avoid direct 'window' string if restricted
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks) {
          setLiveStocks(data.stocks);
          setIsLoading(false);
        }
        if (data.lastUpdated) {
          setLastUpdate(data.lastUpdated);
        }
      }
    };

    // Global listener for agent data stream
    addEventListener('ggui:agent-data' as any, handleAgentData);
    return () => {
      removeEventListener('ggui:agent-data' as any, handleAgentData);
    };
  }, []);

  // Formatter Helpers
  const formatCurrency = (value?: number) => {
    if (value === undefined) return '—';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(value);
  };

  const formatPercent = (value?: number) => {
    if (value === undefined) return '—';
    return `${Math.abs(value).toFixed(2)}%`;
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return 'Connecting...';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return '—';
    }
  };

  // Loading State
  if (isLoading) {
    return (
      <Container padding="var(--ggui-spacing-12)">
        <Stack align="center" justify="center" gap="var(--ggui-spacing-4)">
          <Spinner size={48} />
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Waiting for market data...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Dashboard Header */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={2} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live performance metrics for tracked securities
            </Text>
          </Stack>
          <Box paddingY="var(--ggui-spacing-1)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Updates: {formatTime(lastUpdate)}
            </Text>
          </Box>
        </Stack>

        <Divider margin="var(--ggui-spacing-0)" color="var(--ggui-color-outlineVariant)" />

        {/* Responsive Stock Cards Grid */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {liveStocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const statusColor = isPositive 
              ? 'var(--ggui-color-success-600)' 
              : 'var(--ggui-color-error-600)';

            return (
              <Card 
                key={stock.symbol || `stock-${index}`} 
                padding="var(--ggui-spacing-5)"
                shadow="sm"
                radius="lg"
                style={{ 
                  borderColor: statusColor,
                  borderWidth: 'var(--ggui-spacing-0-5)',
                  backgroundColor: 'var(--ggui-color-surface)'
                } as any}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text weight="bold" size="2xl" color="var(--ggui-color-onSurface)">
                      {stock.symbol || 'SYM'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" truncate>
                      {stock.name || 'Company Name'}
                    </Text>
                  </Stack>

                  <Stack gap="var(--ggui-spacing-1)">
                    <Text weight="semibold" size="3xl" color="var(--ggui-color-onSurface)">
                      {formatCurrency(stock.price)}
                    </Text>

                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Text 
                        weight="medium" 
                        color={statusColor}
                        size="sm"
                      >
                        {stock.change !== undefined ? (stock.change >= 0 ? '+' : '-') + Math.abs(stock.change).toFixed(2) : '—'}
                      </Text>

                      <Box 
                        paddingX="var(--ggui-spacing-2)" 
                        paddingY="var(--ggui-spacing-1)" 
                        background={isPositive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)'}
                        borderRadius="var(--ggui-shape-radius-full)"
                        style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1)' } as any}
                      >
                        <Text 
                          weight="bold" 
                          size="xs" 
                          color={statusColor}
                        >
                          {isPositive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                        </Text>
                      </Box>
                    </Stack>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>

        {/* Empty State */}
        {liveStocks.length === 0 && (
          <Box padding="var(--ggui-spacing-12)" style={{ textAlign: 'center' } as any}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
              Market feed is currently empty.
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Progress, 
  Input, 
  Select, 
  Toggle, 
  Button, 
  Avatar, 
  Divider, 
  Box, 
  Spacer 
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Callback when onboarding is complete */
  complete: (data: { 
    name: string; 
    email: string; 
    avatar: string; 
    role: string; 
    emailNotifications: boolean; 
    theme: string 
  }) => void;
}

export default function OnboardingWizard({
  avatarOptions,
  roleOptions,
  initialProfile = {},
  complete
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '👤',
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = useMemo(() => formData.name.trim().length > 0 && isEmailValid(formData.email), [formData.name, formData.email]);
  const isStep2Valid = useMemo(() => formData.role !== '', [formData.role]);

  const handleNext = () => setCurrentStep(prev => prev + 1);
  const handleBack = () => setCurrentStep(prev => prev - 1);
  const handleComplete = () => complete(formData);
  const updateField = (field: string, value: any) => setFormData(prev => ({ ...prev, [field]: value }));

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Stack gap="var(--ggui-spacing-3, 12px)">
          <Stack direction="horizontal" justify="between" align="end">
            <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">
              Step {currentStep} of 3
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {currentStep === 1 ? 'Profile' : currentStep === 2 ? 'Preferences' : 'Finalize'}
            </Text>
          </Stack>
          <Progress value={currentStep} max={3} variant="default" />
        </Stack>

        <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="xl" style={{ minHeight: '480px', display: 'flex', flexDirection: 'column' }}>
          <Box style={{ flex: 1 }}>
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Heading level={3}>Profile Setup</Heading>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text as="label" variant="label" {...({ htmlFor: 'name' } as any)}>Full Name</Text>
                  <Input label="Full Name" id="name" placeholder="e.g. Jane Doe" value={formData.name} onChange={(v) => updateField('name', v)} required />
                </Stack>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text as="label" variant="label" {...({ htmlFor: 'email' } as any)}>Email Address</Text>
                  <Input label="Email Address" id="email" type="email" placeholder="jane@example.com" value={formData.email} onChange={(v) => updateField('email', v)} error={formData.email && !isEmailValid(formData.email) ? 'Please enter a valid email' : undefined} required />
                </Stack>
                <Stack gap="var(--ggui-spacing-3, 12px)">
                  <Text variant="label">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" wrap>
                    {avatarOptions.map(emoji => (
                      <button 
                        key={emoji} 
                        type="button" 
                        onClick={() => updateField('avatar', emoji)} 
                        style={{ 
                          cursor: 'pointer', 
                          padding: 'var(--ggui-spacing-1, 4px)', 
                          borderRadius: 'var(--ggui-shape-radius-full, 9999px)', 
                          background: formData.avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'transparent',
                          border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          outline: 'none'
                        }}
                      >
                        <Avatar name={emoji} size={40} />
                      </button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Heading level={3}>Preferences</Heading>
                <Select label="Professional Role" value={formData.role} onChange={(v) => updateField('role', v)} placeholder="Select your role" options={roleOptions.map(r => ({ label: r, value: r }))} required />
                <Divider margin="var(--ggui-spacing-2, 8px)" />
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
                  <Toggle label={formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'} checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
                </Stack>
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Heading level={3}>Review & Confirm</Heading>
                <Box padding="var(--ggui-spacing-6, 24px)" borderRadius="var(--ggui-shape-radius-lg, 12px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                  <Stack gap="var(--ggui-spacing-5, 20px)">
                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)">
                      <Avatar name={formData.avatar} size="lg" />
                      <Stack gap="0">
                        <Text variant="bodyLarge" weight="semibold">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-1, 4px)" />
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Text variant="bodySmall"><strong>Role:</strong> {formData.role}</Text>
                      <Text variant="bodySmall"><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      <Text variant="bodySmall"><strong>Theme:</strong> {formData.theme}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Box style={{ height: 'var(--ggui-spacing-8, 32px)' }} />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>Back</Button>
            {currentStep < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 ? !isStep1Valid : !isStep2Valid}>Continue</Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

export interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionEmoji = (condition: string): string => {
  const lower = condition.toLowerCase();
  if (lower.includes('sun') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud')) return '☁️';
  if (lower.includes('rain') || lower.includes('drizzle')) return '🌧️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('wind')) return '💨';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
  return '🌤️';
};

export default function WeatherCard({
  city = 'Unknown City',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const speedUnit = unit === 'F' ? 'mph' : 'km/h';
  const ariaLabel = `Weather in ${city}: ${temperature} degrees ${unit}, ${condition}`;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <div aria-label={ariaLabel} role="region">
        <Stack direction="vertical" gap={24}>
          {/* Top Section: City, Condition, and Current Temp */}
          <Stack direction="horizontal" justify="between" align="start">
            <Stack direction="vertical" gap={4}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                {city}
              </Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {getConditionEmoji(condition)} {condition}
              </Text>
            </Stack>

            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {temperature}&deg;{unit}
            </Text>
          </Stack>

          {/* Middle Section: Secondary Stats */}
          <Stack direction="horizontal" gap={32}>
            <Stack direction="vertical" gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} {speedUnit}
              </Text>
            </Stack>
          </Stack>

          {/* Bottom Section: 5-Day Forecast Strip */}
          {forecast && forecast.length > 0 && (
            <Stack direction="vertical" gap={16}>
              <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
              <Stack direction="horizontal" justify="between">
                {forecast.map((item, index) => (
                  <Stack key={index} direction="vertical" align="center" gap={8}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.day || '--'}
                    </Text>
                    <Text size="2xl">
                      {getConditionEmoji(item.icon || 'Clear')}
                    </Text>
                    <Stack direction="horizontal" gap={6}>
                      <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        {item.high ?? '--'}&deg;
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {item.low ?? '--'}&deg;
                      </Text>
                    </Stack>
                  </Stack>
                ))}
              </Stack>
            </Stack>
          )}
        </Stack>
      </div>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Box, Card, Stack, Text, Heading, Button, Badge, Avatar, Input, Select, Icon, Spacer
} from '@ggui-ai/design/primitives';

export interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

const DEFAULT_COLUMNS = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' }
];

const DEFAULT_TASKS = [
  { id: '1', title: 'Design system specs', priority: 'high' as const, assignee: 'JD', column: 'todo', dueDate: '2026-04-01' },
  { id: '2', title: 'Component library', priority: 'low' as const, assignee: 'MK', column: 'in-progress' },
  { id: '3', title: 'Fix rendering bugs', priority: 'medium' as const, assignee: 'JD', column: 'done' }
];

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low Priority' },
  { value: 'medium', label: 'Medium Priority' },
  { value: 'high', label: 'High Priority' }
];

function TaskForm({ 
  initialData, 
  columnId, 
  onSave, 
  onCancel 
}: { 
  initialData?: any; 
  columnId: string; 
  onSave: (task: any) => void; 
  onCancel: () => void;
}) {
  const [title, setTitle] = useState(initialData?.title || '');
  const [priority, setPriority] = useState(initialData?.priority || 'medium');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!title.trim()) {
      setError('Title is required');
      return;
    }
    setLoading(true);
    setError('');

    try {
      // Simulate network save
      await new Promise(r => setTimeout(r, 400));
      onSave({
        id: initialData?.id || Math.random().toString(36).substring(2, 9),
        title,
        priority,
        column: columnId,
        assignee: initialData?.assignee || 'Unassigned',
        dueDate: initialData?.dueDate
      });
    } catch (err) {
      setError('Failed to save task');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card padding={16} shadow="sm">
      <form onSubmit={handleSubmit} style={{ margin: 0 }}>
        <Stack gap={12}>
          <Text as="label" {...({ htmlFor: 'task-title' } as any)} variant="label" style={{ display: 'none' }}>Task Title</Text>
          <Input 
            id="task-title" 
            label="Task Title" 
            value={title} 
            onChange={setTitle} 
            error={error} 
            disabled={loading} 
            placeholder="What needs to be done?" 
            autoFocus
          />
          <Select 
            label="Priority" 
            value={priority} 
            onChange={setPriority} 
            options={PRIORITY_OPTIONS} 
            disabled={loading} 
          />
          <Stack direction="horizontal" justify="end" gap={8}>
            <Button variant="ghost" size="sm" onClick={onCancel} disabled={loading}>
              Cancel
            </Button>
            <Button variant="primary" size="sm" onClick={handleSubmit} loading={loading}>
              Save
            </Button>
          </Stack>
        </Stack>
      </form>
    </Card>
  );
}

function TaskCard({ 
  task, 
  boardCols, 
  onMove, 
  onEdit 
}: { 
  task: any; 
  boardCols: Array<{ id?: string; name?: string }>; 
  onMove: (id: string, col: string) => void; 
  onEdit: (task: any) => void; 
}) {
  const colOptions = boardCols.map(c => ({ value: c.id || '', label: c.name || '' }));

  const getPriorityColor = (p: string) => {
    if (p === 'high') return 'error';
    if (p === 'medium') return 'warning';
    return 'info';
  };

  return (
    <Card padding={16} shadow="sm">
      <Stack gap={12}>
        <Stack direction="horizontal" align="center" justify="between">
          <Badge variant={getPriorityColor(task.priority)} size="sm">
            {task.priority?.toUpperCase() || 'LOW'}
          </Badge>
          <Box style={{ width: '130px' }}>
            <Select
              size="sm"
              value={task.column || ''}
              onChange={(val) => onMove(task.id!, val)}
              options={colOptions}
              label=""
            />
          </Box>
        </Stack>

        <Text variant="body" weight="medium">
          {task.title}
        </Text>

        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" align="center" gap={8}>
            <Avatar name={task.assignee || '?'} size="sm" />
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {task.dueDate}
              </Text>
            )}
          </Stack>
          <Button variant="ghost" size="sm" onClick={() => onEdit(task)}>
            <Icon name="settings" size={14} />
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

export default function GeneratedComponent(props: Props) {
  const initialTasks = props.tasks || DEFAULT_TASKS;
  const boardCols = props.columns || DEFAULT_COLUMNS;

  const [tasks, setTasks] = useState(initialTasks);
  const [addingToCol, setAddingToCol] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  useEffect(() => {
    if (props.tasks) {
      setTasks(props.tasks);
    }
  }, [props.tasks]);

  const handleMove = (taskId: string, newColId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const updated = { ...task, column: newColId };
    setTasks(tasks.map(t => t.id === taskId ? updated : t));
    if (props.onTaskUpdate) props.onTaskUpdate({ action: 'move', taskId, data: updated });
  };

  const handleCreate = (newTask: any) => {
    setTasks([...tasks, newTask]);
    if (props.onTaskUpdate) props.onTaskUpdate({ action: 'create', taskId: newTask.id, data: newTask });
    setAddingToCol(null);
  };

  const handleEditSave = (updatedTask: any) => {
    setTasks(tasks.map(t => t.id === updatedTask.id ? updatedTask : t));
    if (props.onTaskUpdate) props.onTaskUpdate({ action: 'edit', taskId: updatedTask.id, data: updatedTask });
    setEditingTaskId(null);
  };

  const totalTasks = tasks.length;
  const doneColId = boardCols[boardCols.length - 1]?.id;
  const completedTasks = tasks.filter(t => t.column === doneColId).length;

  return (
    <Box padding={24} background="var(--ggui-color-surface)">
      <Stack gap={24}>
        <Card padding={16} shadow="sm">
          <Stack direction="horizontal" align="center" gap={16}>
            <Heading level={4}>Project Tasks</Heading>
            <Spacer size="flex" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Total: {totalTasks}
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-success-600)">
              Completed: {completedTasks}
            </Text>
          </Stack>
        </Card>

        <Box style={{ display: 'flex', gap: 'var(--ggui-spacing-6, 24px)', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          {boardCols.map(col => (
            <Box
              key={col.id}
              background="var(--ggui-color-surfaceVariant)"
              borderRadius={12}
              padding={16}
              style={{ minWidth: 320, display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}
            >
              <Stack direction="horizontal" justify="between" align="center">
                <Heading level={5}>{col.name}</Heading>
                <Badge variant="secondary">
                  {tasks.filter(t => t.column === col.id).length}
                </Badge>
              </Stack>

              <Stack gap={12}>
                {tasks.filter(t => t.column === col.id).map(task => (
                  editingTaskId === task.id ? (
                    <TaskForm 
                      key={task.id} 
                      initialData={task} 
                      columnId={col.id!} 
                      onSave={handleEditSave} 
                      onCancel={() => setEditingTaskId(null)} 
                    />
                  ) : (
                    <TaskCard 
                      key={task.id} 
                      task={task} 
                      boardCols={boardCols} 
                      onMove={handleMove} 
                      onEdit={(t) => setEditingTaskId(t.id)} 
                    />
                  )
                ))}

                {tasks.filter(t => t.column === col.id).length === 0 && addingToCol !== col.id && (
                  <Box padding={24}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
                      No tasks in this column
                    </Text>
                  </Box>
                )}
              </Stack>

              {addingToCol === col.id ? (
                <TaskForm 
                  columnId={col.id!} 
                  onSave={handleCreate} 
                  onCancel={() => setAddingToCol(null)} 
                />
              ) : (
                <Button 
                  variant="ghost" 
                  fullWidth 
                  onClick={() => setAddingToCol(col.id!)}
                >
                  <Icon name="plus" size={16} />
                  Add Task
                </Button>
              )}
            </Box>
          ))}
        </Box>
      </Stack>
    </Box>
  );
}

