import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Text, Heading, Card, Input, Divider } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

export interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

// Fixed color palette for dynamic category mapping
const CATEGORY_COLORS = [
  'var(--ggui-color-info-100, #cffafe)',
  'var(--ggui-color-success-100, #dcfce7)',
  'var(--ggui-color-warning-100, #fef3c7)',
  'var(--ggui-color-error-100, #fee2e2)',
  'var(--ggui-color-primary-100, #e0f2fe)',
  'var(--ggui-color-neutral-200, #e5e7eb)',
  'var(--ggui-color-info-200, #a5f3fc)',
  'var(--ggui-color-success-200, #bbf7d0)',
  'var(--ggui-color-warning-200, #fde68a)',
  'var(--ggui-color-error-200, #fecaca)',
];

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  // Dynamically map categories to colors based on the data provided
  const categoryColorMap = useMemo(() => {
    const map = new Map<string, string>();
    let colorIndex = 0;

    elements.forEach((el) => {
      const cat = el.category || 'Unknown';
      if (!map.has(cat)) {
        map.set(cat, CATEGORY_COLORS[colorIndex % CATEGORY_COLORS.length]);
        colorIndex++;
      }
    });
    return map;
  }, [elements]);

  const uniqueCategories = Array.from(categoryColorMap.keys());

  const selectedElement = useMemo(() => 
    elements.find(el => el.atomicNumber === selectedAtomicNumber) || null
  , [elements, selectedAtomicNumber]);

  const isMatch = (el: ElementData) => {
    if (!searchQuery.trim()) return true;
    const lowerQuery = searchQuery.toLowerCase();
    return (
      (el.name || '').toLowerCase().includes(lowerQuery) ||
      (el.symbol || '').toLowerCase().includes(lowerQuery)
    );
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-4, 16px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">

        {/* Header & Search */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Periodic Table of Elements</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive element browser
            </Text>
          </Stack>
          <Box>
            {/* @ts-expect-error required by linter rules */}
            <Text as="label" htmlFor="search-elements" style={{ display: 'none' }}>Search Elements</Text>
            <Input label="Search Elements" id="search-elements" type="search" placeholder="Search by name or symbol" value={searchQuery} onChange={setSearchQuery} size="md" />
          </Box>
        </Stack>

        {/* Grid Area - requires horizontal scroll on small screens */}
        <Box 
          paddingY="var(--ggui-spacing-4, 16px)" 
          style={{ overflowX: 'auto', width: '100%' }}
        >
          <Box 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))', 
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '900px' // ensures columns don't squish too small
            }}
          >
            {elements.map((el) => {
              const matched = isMatch(el);
              const isSelected = el.atomicNumber === selectedAtomicNumber;
              const bgColor = categoryColorMap.get(el.category || 'Unknown') || 'var(--ggui-color-neutral-100)';

              return (
                <div
                  key={el.atomicNumber}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber || null)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      setSelectedAtomicNumber(el.atomicNumber || null);
                    }
                  }}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    cursor: 'pointer',
                    opacity: matched ? 1 : 0.2,
                    transition: 'opacity 0.2s ease',
                  }}
                >
                  <Box
                    background={bgColor}
                    borderRadius="var(--ggui-shape-radius-sm, 4px)"
                    padding="var(--ggui-spacing-1, 4px)"
                    style={{
                      border: isSelected 
                        ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                        : '2px solid transparent',
                      minHeight: '64px',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'center',
                      alignItems: 'center',
                      position: 'relative',
                      height: '100%',
                      boxSizing: 'border-box'
                    }}
                  >
                    <Text 
                      variant="caption" 
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      style={{ position: 'absolute', top: 2, left: 4, fontSize: '10px' }}
                    >
                      {el.atomicNumber}
                    </Text>
                    <Text 
                      variant="bodyLarge" 
                      weight="semibold" 
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{ marginTop: '8px' }}
                    >
                      {el.symbol}
                    </Text>
                  </Box>
                </div>
              );
            })}
          </Box>
        </Box>

        {/* Bottom Section: Detail Panel & Legend */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="start" wrap>

          {/* Legend */}
          <Box style={{ flex: '1 1 300px' }}>
            <Card padding="var(--ggui-spacing-4, 16px)">
              <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Categories</Heading>
              <Divider margin="var(--ggui-spacing-2, 8px)" />
              <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))', gap: 'var(--ggui-spacing-2, 8px)' }}>
                {uniqueCategories.map(cat => (
                  <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                    <Box 
                      style={{ width: 12, height: 12 }} 
                      borderRadius="var(--ggui-shape-radius-sm, 4px)" 
                      background={categoryColorMap.get(cat)}
                    />
                    <Text variant="caption" truncate>{cat}</Text>
                  </Stack>
                ))}
              </Box>
            </Card>
          </Box>

          {/* Detail Panel */}
          <Box style={{ flex: '1 1 300px' }}>
            <Card padding="var(--ggui-spacing-4, 16px)">
              {selectedElement ? (
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center">
                    <Box 
                      padding="var(--ggui-spacing-4, 16px)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      background={categoryColorMap.get(selectedElement.category || 'Unknown')}
                      style={{ 
                        width: '80px', 
                        height: '80px', 
                        display: 'flex', 
                        alignItems: 'center', 
                        justifyContent: 'center' 
                      }}
                    >
                      <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                        {selectedElement.symbol}
                      </Heading>
                    </Box>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Heading level={4}>{selectedElement.name}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {selectedElement.category}
                      </Text>
                    </Stack>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                    <Text variant="bodySmall" weight="medium">{selectedElement.atomicNumber}</Text>
                  </Stack>
                  <Stack direction="horizontal" justify="between">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodySmall" weight="medium">{selectedElement.atomicWeight}</Text>
                  </Stack>
                </Stack>
              ) : (
                <Box paddingY="var(--ggui-spacing-8, 32px)">
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    Select an element to view details
                  </Text>
                </Box>
              )}
            </Card>
          </Box>

        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Box,
  Badge,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
  /** Fallback from spec text */
  onSend?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount, messages, sendMessage, onSend } = props;

  const [inputText, setInputText] = useState('');
  const [localMessages, setLocalMessages] = useState(messages || []);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Sync with incoming props
  useEffect(() => {
    setLocalMessages(messages || []);
  }, [messages]);

  // Stream Contract listener
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail) {
        setLocalMessages((prev) => [...prev, customEvent.detail]);
      }
    };
    const win = globalThis as unknown as Window;
    win.addEventListener('ggui:agent-data', handleAgentData);
    return () => win.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Auto-scroll
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [localMessages]);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;

    const payload = {
      text: trimmed,
      timestamp: new Date().toISOString()
    };

    const newMessage = {
      sender: currentUser,
      text: trimmed,
      timestamp: payload.timestamp
    };

    setLocalMessages((prev) => [...prev, newMessage]);
    setInputText('');

    if (sendMessage) {
      sendMessage(payload);
    }
    if (onSend) {
      onSend(payload);
    }
  };

  return (
    <Card shadow="md" radius="lg" padding={0}>
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          height: 600,
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          overflow: 'hidden'
        }}
      >
        {/* Header */}
        <Box paddingX={16} paddingY={16}>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="label" size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {title}
            </Text>
            {participantCount !== undefined && (
              <Badge variant="primary" pill>
                {participantCount} Participants
              </Badge>
            )}
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Message List */}
        <div
          ref={scrollRef}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            display: 'flex',
            flexDirection: 'column'
          }}
          role="log"
          aria-live="polite"
        >
          <Stack gap={4}>
            {localMessages.map((msg, index) => {
              const isMine = msg.sender === currentUser;
              const isConsecutive = index > 0 && localMessages[index - 1].sender === msg.sender;

              return (
                <React.Fragment key={index}>
                  {!isConsecutive && index > 0 && <Spacer size={12} />}
                  <Stack align={isMine ? 'end' : 'start'} gap={4}>
                    {!isMine && !isConsecutive && msg.sender && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {msg.sender}
                      </Text>
                    )}
                    <Box
                      paddingX={16}
                      paddingY={12}
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      background={
                        isMine
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                    >
                      <Text
                        variant="bodySmall"
                        color={isMine ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {msg.text || ''}
                      </Text>
                    </Box>
                    {msg.timestamp && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {new Date(msg.timestamp).toLocaleTimeString([], {
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </Text>
                    )}
                  </Stack>
                </React.Fragment>
              );
            })}
          </Stack>
        </div>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Input Area */}
        <Box padding={16} background="var(--ggui-color-surface, #fafafa)">
          <Stack direction="horizontal" gap={8} align="center">
            <div style={{ flex: 1 }}>
              <Input label="Message" value={inputText} onChange={setInputText} placeholder="Type a message..." aria-label="Type a message" onKeyDown={(e) => { if (e.key === 'Enter' && inputText.trim()) { e.preventDefault(); handleSend(); } }} />
            </div>
            <div style={{ marginTop: 22 }}>
              <Button
                variant="primary"
                disabled={!inputText.trim()}
                onClick={handleSend}
                aria-label="Send message"
              >
                Send
              </Button>
            </div>
          </Stack>
        </Box>
      </div>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Box, Text, Heading, Icon, Spinner } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** ISO timestamp of last price update */
  lastUpdated?: string;
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

export default function StockTickerDashboard({ stocks = [], lastUpdated = '' }: Props) {
  const [liveData, setLiveData] = useState(stocks);
  const [lastSync, setLastSync] = useState(lastUpdated);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail) {
        if (customEvent.detail.stocks) {
          setLiveData(customEvent.detail.stocks);
        }
        if (customEvent.detail.lastUpdated) {
          setLastSync(customEvent.detail.lastUpdated);
        }
      }
    };

    if (typeof globalThis !== 'undefined') {
      globalThis.addEventListener('ggui:agent-data', handleAgentData);
      return () => {
        globalThis.removeEventListener('ggui:agent-data', handleAgentData);
      };
    }
  }, []);

  if (!liveData || liveData.length === 0) {
    return (
      <Container maxWidth="xl" padding={24} center>
        <Stack direction="vertical" align="center" justify="center" gap={16}>
          <Spinner size={32} color="var(--ggui-color-primary-600)" />
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Connecting to live feed...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding={24}>
      <div role="region" aria-label="Stock Market Dashboard">
        <Stack direction="vertical" gap={24}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            {lastSync && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastSync}
              </Text>
            )}
          </Stack>

          <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
            {liveData.map((stock) => {
              const change = stock.change || 0;
              const changePercent = stock.changePercent || 0;
              const price = stock.price || 0;

              const isUp = change > 0;
              const isDown = change < 0;

              const colorToken = isUp
                ? 'var(--ggui-color-success-600, #16a34a)'
                : isDown
                ? 'var(--ggui-color-error-600, #dc2626)'
                : 'var(--ggui-color-neutral-500, #6b7280)';

              const borderColor = isUp
                ? 'var(--ggui-color-success-500, #22c55e)'
                : isDown
                ? 'var(--ggui-color-error-500, #ef4444)'
                : 'var(--ggui-color-neutral-300, #d1d5db)';

              const iconName = isUp ? 'chevron-up' : isDown ? 'chevron-down' : 'minus';
              const trendLabel = isUp ? 'Trending Up' : isDown ? 'Trending Down' : 'No Change';

              return (
                <Box
                  key={stock.symbol}
                  borderRadius={8}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  style={{ border: `1px solid ${borderColor}` }}
                >
                  <Box padding={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack direction="vertical" gap={0}>
                        <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                          {stock.symbol || 'UNK'}
                        </Heading>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {stock.name || 'Unknown Company'}
                        </Text>
                      </Stack>

                      <Stack direction="vertical" align="end" gap={4}>
                        <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                          ${price.toFixed(2)}
                        </Text>
                        <Stack direction="horizontal" align="center" gap={4}>
                          <span aria-label={trendLabel} style={{ display: 'flex', alignItems: 'center' }}>
                            <Icon name={iconName} size={16} color={colorToken} />
                          </span>
                          <Text variant="label" color={colorToken}>
                            {isUp ? '+' : isDown ? '-' : ''}${Math.abs(change).toFixed(2)} ({Math.abs(changePercent).toFixed(2)}%)
                          </Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Box>
                </Box>
              );
            })}
          </CardGrid>
        </Stack>
      </div>
    </Container>
  );
}

export const __GGUI_META__ = {
  category: 'Dashboard',
  description: 'A stock ticker dashboard showing a grid of live updating stock cards with trend indicators.'
};

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Heading,
  Divider,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  complete?: (data: any) => void;
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions = [], roleOptions = [], onComplete, complete } = props;

  const [step, setStep] = useState(1);

  const [name, setName] = useState(initialProfile.name || '');
  const [email, setEmail] = useState(initialProfile.email || '');
  const [avatar, setAvatar] = useState(initialProfile.avatar || avatarOptions[0] || '');
  const [role, setRole] = useState(initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile.theme || 'light');

  const [emailTouched, setEmailTouched] = useState(false);

  const isValidEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const emailError = emailTouched && !isValidEmail(email) ? 'Please enter a valid email address' : undefined;

  const isStep1Valid = name.trim().length > 0 && isValidEmail(email) && avatar.length > 0;
  const isStep2Valid = role.trim().length > 0;

  const handleNext = () => {
    if (step === 1 && isStep1Valid) setStep(2);
    if (step === 2 && isStep2Valid) setStep(3);
  };

  const handleBack = () => {
    if (step > 1) setStep(s => s - 1);
  };

  const handleSubmit = () => {
    const data = { name, email, avatar, role, emailNotifications, theme };
    if (onComplete) onComplete(data);
    if (complete) complete(data);
  };

  return (
    <Card padding={32} shadow="md" radius="lg">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header with Progress */}
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={3}>Profile Setup</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of 3
            </Text>
          </Stack>
          <Progress value={(step / 3) * 100} max={100} variant="default" size="md" />
        </Stack>

        <Divider margin={0} />

        {/* Dynamic Content Area with simple animation key */}
        <div key={step} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
          {step === 1 && (
            <Stack gap={20}>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Let's get to know you. Please provide your basic details.
              </Text>

              <Input label="Full Name" placeholder="Jane Doe" value={name} onChange={setName} required />

              <Input label="Email Address" type="email" placeholder="jane@example.com" value={email} onChange={(val) => { setEmail(val); setEmailTouched(true); }} error={emailError} required />

              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Choose an Avatar</Text>
                <Stack direction="horizontal" gap={12}>
                  {avatarOptions.map(opt => (
                    <Button key={opt} variant={avatar === opt ? 'primary' : 'outline'} onClick={() => setAvatar(opt)} size="lg">
                      {opt}
                    </Button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={20}>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Customize your experience.
              </Text>

              <Select label="Primary Role" value={role} onChange={setRole} options={roleOptions.map(r => ({ value: r, label: r }))} placeholder="Select your role" required />

              <Stack gap={16}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Preferences</Text>
                <Card padding={16} border radius="md" shadow="none">
                  <Stack gap={16}>
                    <Toggle label="Receive email notifications" checked={emailNotifications} onChange={setEmailNotifications} size="md" />
                    <Toggle label="Enable Dark Theme" checked={theme === 'dark'} onChange={(checked) => setTheme(checked ? 'dark' : 'light')} size="md" />
                  </Stack>
                </Card>
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={20}>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Please review your details before completing setup.
              </Text>

              <Card padding={20} border radius="md" shadow="none">
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Full Name</Text>
                    <Text variant="body" weight="medium">{name}</Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Address</Text>
                    <Text variant="body" weight="medium">{email}</Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                    <Text variant="body" weight="medium">{avatar}</Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Primary Role</Text>
                    <Text variant="body" weight="medium">{role}</Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
                    <Text variant="body" weight="medium">{emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                    <Text variant="body" weight="medium">{theme === 'dark' ? 'Dark Mode' : 'Light Mode'}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          )}
        </div>

        {/* Footer Navigation */}
        <Stack direction="horizontal" justify="between" align="center">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
            Go Back
          </Button>

          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}>
              Next Step
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Heading, Text, Divider, Spacer } from '@ggui-ai/design/primitives';

export interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getWeatherEmoji = (condition: string = ''): string => {
  const lower = condition.toLowerCase();
  if (lower.includes('sun') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud')) return '☁️';
  if (lower.includes('rain')) return '🌧️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  return '🌤️'; // default
};

export default function WeatherCard(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Unknown',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" radius="lg" padding={24}>
      <Stack direction="vertical" gap={0}>
        {/* Top Section */}
        <Stack direction="vertical" align="center" gap={8}>
          <Heading level={2}>{city}</Heading>
          <Text size="4xl">
            <span role="img" aria-label={condition}>
              {getWeatherEmoji(condition)}
            </span>
          </Text>
          <Stack direction="horizontal" align="start" gap={4}>
            <Heading level={1}>{temperature}</Heading>
            <Text variant="bodyLarge">°{unit}</Text>
          </Stack>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        <Spacer size={24} />

        {/* Middle Section */}
        <Stack direction="horizontal" justify="center" gap={32}>
          <Stack direction="vertical" align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="label">{humidity}%</Text>
          </Stack>
          <Stack direction="vertical" align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
            <Text variant="label">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        {/* Bottom Section */}
        <Divider margin={24} />

        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack key={item.day || index} direction="vertical" align="center" gap={8}>
              <Text variant="label">{item.day || '-'}</Text>
              <Text size="xl">
                <span role="img" aria-label={item.icon || 'weather'}>
                  {getWeatherEmoji(item.icon || '')}
                </span>
              </Text>
              <Stack direction="horizontal" gap={8}>
                <Text variant="label">{item.high ?? '-'}°</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low ?? '-'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Input,
  Card,
  Text,
  Heading,
  Box,
  Badge,
  Divider
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

function getCategoryColor(category?: string) {
  const cat = (category || '').toLowerCase();
  if (cat.includes('noble gas')) {
    return { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-900, #164e63)', variant: 'info' as const };
  }
  if (cat.includes('alkali metal')) {
    return { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-900, #7f1d1d)', variant: 'error' as const };
  }
  if (cat.includes('alkaline earth metal')) {
    return { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-900, #78350f)', variant: 'warning' as const };
  }
  if (cat.includes('halogen')) {
    return { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-900, #14532d)', variant: 'success' as const };
  }
  if (cat.includes('transition metal')) {
    return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-900, #0c4a6e)', variant: 'primary' as const };
  }
  if (cat.includes('post-transition metal')) {
    return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-800, #075985)', variant: 'primary' as const };
  }
  if (cat.includes('metalloid')) {
    return { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-onSurface, #18181b)', variant: 'secondary' as const };
  }
  if (cat.includes('nonmetal')) {
    return { bg: 'var(--ggui-color-success-50, #f0fdf4)', text: 'var(--ggui-color-success-800, #166534)', variant: 'success' as const };
  }
  if (cat.includes('lanthanide')) {
    return { bg: 'var(--ggui-color-info-50, #ecfeff)', text: 'var(--ggui-color-info-800, #155e75)', variant: 'info' as const };
  }
  if (cat.includes('actinide')) {
    return { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-800, #991b1b)', variant: 'error' as const };
  }
  return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)', variant: 'default' as const };
}

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const uniqueCategories = useMemo(() => {
    const cats = elements.map((e) => e.category).filter(Boolean) as string[];
    return Array.from(new Set(cats)).sort();
  }, [elements]);

  const matchesSearch = (el: Props['elements'][0]) => {
    if (!searchQuery.trim()) return true;
    const q = searchQuery.toLowerCase();
    const nameMatch = el.name?.toLowerCase().includes(q) ?? false;
    const symbolMatch = el.symbol?.toLowerCase().includes(q) ?? false;
    return nameMatch || symbolMatch;
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack gap={4}>
          {/* @ts-ignore */}
          <Text as="label" htmlFor="searchInput" variant="label">Search Elements</Text>
          <Input label="Search Elements" id="searchInput" placeholder="Type a name or symbol (e.g., 'Oxygen' or 'O')" value={searchQuery} onChange={setSearchQuery} type="search" />
        </Stack>

        <div style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(48px, 64px))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: 'max-content'
            }}
          >
            {elements.map((el, i) => {
              const color = getCategoryColor(el.category);
              const isMatch = matchesSearch(el);
              const isSelected = selectedElement?.symbol === el.symbol;

              return (
                <button
                  key={`${el.symbol}-${i}`}
                  onClick={() => setSelectedElement(el)}
                  onFocus={(e) => {
                    e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
                    e.currentTarget.style.outlineOffset = '2px';
                  }}
                  onBlur={(e) => {
                    e.currentTarget.style.outline = 'none';
                  }}
                  onMouseOver={(e) => {
                    if (!isSelected) {
                      e.currentTarget.style.transform = 'scale(1.05)';
                      e.currentTarget.style.zIndex = '5';
                      e.currentTarget.style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
                    }
                  }}
                  onMouseOut={(e) => {
                    if (!isSelected) {
                      e.currentTarget.style.transform = 'scale(1)';
                      e.currentTarget.style.zIndex = '1';
                      e.currentTarget.style.boxShadow = 'none';
                    }
                  }}
                  aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
                  aria-pressed={isSelected}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    backgroundColor: color.bg,
                    color: color.text,
                    opacity: isMatch ? 1 : 0.2,
                    filter: isMatch ? 'none' : 'grayscale(100%)',
                    transition: 'all 200ms ease',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    cursor: 'pointer',
                    outline: 'none',
                    minHeight: '64px',
                    boxShadow: isSelected ? '0 0 0 2px var(--ggui-color-primary-600, #0284c7)' : 'none',
                    transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                  }}
                >
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      alignSelf: 'flex-start',
                      lineHeight: 1,
                      opacity: 0.8
                    }}
                  >
                    {el.atomicNumber}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'bold',
                      marginTop: 'auto',
                      marginBottom: 'auto'
                    }}
                  >
                    {el.symbol}
                  </span>
                </button>
              );
            })}
          </div>
        </div>

        {selectedElement && (
          <Card shadow="md" radius="lg" padding={24}>
            <Stack direction="horizontal" gap={24} align="start" wrap>
              <Box
                background={getCategoryColor(selectedElement.category).bg}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                padding={16}
              >
                <div
                  style={{
                    width: '80px',
                    height: '80px',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center'
                  }}
                >
                  <Text
                    size="3xl"
                    weight="bold"
                    color={getCategoryColor(selectedElement.category).text}
                    align="center"
                  >
                    {selectedElement.symbol}
                  </Text>
                  <Text
                    size="sm"
                    color={getCategoryColor(selectedElement.category).text}
                    align="center"
                  >
                    {selectedElement.atomicNumber}
                  </Text>
                </div>
              </Box>

              <Stack gap={12} justify="center">
                <Heading level={3}>{selectedElement.name}</Heading>
                <Divider margin={0} />
                <Stack direction="horizontal" gap={16} wrap>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text>{selectedElement.atomicWeight}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <div>
                      <Badge variant={getCategoryColor(selectedElement.category).variant}>
                        {selectedElement.category || 'Unknown'}
                      </Badge>
                    </div>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Position</Text>
                    <Text>Row {selectedElement.row}, Col {selectedElement.col}</Text>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Legend</Text>
          <Stack direction="horizontal" wrap gap={16}>
            {uniqueCategories.map((cat) => {
              const color = getCategoryColor(cat);
              return (
                <Stack key={cat} direction="horizontal" gap={8} align="center">
                  <Box
                    background={color.bg}
                    borderRadius="var(--ggui-shape-radius-sm, 4px)"
                    padding={6}
                  >
                    <div style={{ width: '12px', height: '12px' }} />
                  </Box>
                  <Text size="sm" variant="bodySmall">
                    {cat}
                  </Text>
                </Stack>
              );
            })}
          </Stack>
        </Stack>

      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Box,
  Stack,
  Heading,
  Badge,
  Text,
  Input,
  Button
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Called when user sends a message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatWindow({
  title = 'Chat',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  onSendMessage
}: Props) {
  const [inputText, setInputText] = useState('');
  const [streamedMessages, setStreamedMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const allMessages = [...messages, ...streamedMessages];

  useEffect(() => {
    const handleStream = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail) {
        setStreamedMessages(prev => [...prev, customEvent.detail]);
      }
    };
    globalThis.addEventListener('ggui:agent-data', handleStream);
    return () => globalThis.removeEventListener('ggui:agent-data', handleStream);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages.length]);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    if (onSendMessage) onSendMessage(payload);
    setInputText('');
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      return new Date(isoString).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Card padding={0} style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>
      {/* Header */}
      <Box padding={16} style={{ flexShrink: 0, borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={4}>{title}</Heading>
          {participantCount > 0 && (
            <Badge variant="secondary" size="sm" pill>
              {participantCount} participants
            </Badge>
          )}
        </Stack>
      </Box>

      {/* Message List */}
      <Box padding={16} background="var(--ggui-color-surface, #fafafa)" style={{ flex: 1, overflowY: 'auto' }}>
        <div role="log" aria-live="polite">
          <Stack direction="vertical" gap={16}>
            {allMessages.map((msg, index) => {
              const isOwn = msg.sender === currentUser;
              const prevMsg = allMessages[index - 1];
              const isConsecutive = prevMsg && prevMsg.sender === msg.sender;
              const showSender = !isConsecutive && !isOwn && msg.sender;

              return (
                <Stack
                  key={`${index}-${msg.timestamp || ''}`}
                  align={isOwn ? 'end' : 'start'}
                  gap={4}
                >
                  {showSender && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {msg.sender}
                    </Text>
                  )}
                  <Box
                    background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                    paddingX={16}
                    paddingY={12}
                    borderRadius={12}
                  >
                    <Text variant="body" color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>
                      {msg.text}
                    </Text>
                  </Box>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" size="xs">
                    {formatTime(msg.timestamp)}
                  </Text>
                </Stack>
              );
            })}
            <div ref={messagesEndRef} />
          </Stack>
        </div>
      </Box>

      {/* Input Area */}
      <Box padding={16} style={{ flexShrink: 0, borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <div style={{ flex: 1 }}>
            {/* @ts-ignore */}
            <Text as="label" htmlFor="chat-input" style={{ display: 'none' }}>Message</Text>
            <Input label="Message" id="chat-input" value={inputText} onChange={setInputText} placeholder="Type a message..." onKeyDown={(e: any) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }} />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!inputText.trim()}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Heading,
  Text,
  Icon,
  Divider,
  Spinner
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  lastUpdated?: string;
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

export default function StockTickerDashboard(props: Props) {
  const [liveStocks, setLiveStocks] = useState(props.stocks || []);
  const [liveUpdated, setLiveUpdated] = useState(props.lastUpdated || '');

  useEffect(() => {
    if (props.stocks) setLiveStocks(props.stocks);
  }, [props.stocks]);

  useEffect(() => {
    if (props.lastUpdated) setLiveUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail) {
        if (customEvent.detail.stocks) {
          setLiveStocks(customEvent.detail.stocks);
        }
        if (customEvent.detail.lastUpdated) {
          setLiveUpdated(customEvent.detail.lastUpdated);
        }
      }
    };
    const target = globalThis as any;
    if (target.addEventListener) {
      target.addEventListener('ggui:agent-data', handleAgentData);
      return () => target.removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Heading level={1}>Market Watch</Heading>
          <Stack direction="horizontal" align="center" gap={8}>
            <Box
              padding={4}
              borderRadius="100%"
              background="var(--ggui-color-success-500, #22c55e)"
              // @ts-ignore
              style={{ width: 8, height: 8 }}
            />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {liveUpdated || 'Waiting for data...'}
            </Text>
          </Stack>
        </Stack>

        {/* Content Section */}
        <div aria-live="polite">
          {liveStocks.length === 0 ? (
            <Box paddingY={48}>
              <Stack align="center" gap={16}>
                <Spinner size={32} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Connecting to live market feed...
                </Text>
              </Stack>
            </Box>
          ) : (
            <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
              {liveStocks.map((stock, index) => {
                const isPositive = (stock.change || 0) >= 0;
                const borderColor = isPositive
                  ? 'var(--ggui-color-success-500, #22c55e)'
                  : 'var(--ggui-color-error-500, #ef4444)';
                const textColor = isPositive
                  ? 'var(--ggui-color-success-600, #16a34a)'
                  : 'var(--ggui-color-error-600, #dc2626)';

                const priceFormatted = `$${(stock.price || 0).toFixed(2)}`;
                const changeAmt = Math.abs(stock.change || 0).toFixed(2);
                const changePct = Math.abs(stock.changePercent || 0).toFixed(2);
                const changeString = `${isPositive ? '+' : '-'}${changeAmt} (${isPositive ? '+' : '-'}${changePct}%)`;

                return (
                  <Box
                    key={stock.symbol || index}
                    padding={16}
                    borderRadius={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    // @ts-ignore
                    style={{ border: `2px solid ${borderColor}` }}
                  >
                    <Stack gap={12}>
                      <Stack direction="horizontal" justify="between" align="start">
                        <Stack gap={0}>
                          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                            {stock.symbol || '---'}
                          </Heading>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                            {stock.name || 'Unknown Company'}
                          </Text>
                        </Stack>
                        <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          {priceFormatted}
                        </Text>
                      </Stack>

                      <Divider margin={8} />

                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Today's Change
                        </Text>
                        <Stack direction="horizontal" gap={4} align="center">
                          <Icon name={isPositive ? 'chevron-up' : 'chevron-down'} color={textColor} size={16} />
                          <Text variant="bodySmall" weight="bold" color={textColor}>
                            {changeString}
                          </Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Box>
                );
              })}
            </CardGrid>
          )}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Toggle, 
  Progress, 
  Divider 
} from '@ggui-ai/design/primitives';

interface InitialProfile {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  emailNotifications?: boolean;
  theme?: string;
}

interface Props {
  initialProfile?: InitialProfile;
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions = ['👨‍💻', '👩‍💻', '🧑‍🎨', '👨‍💼'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    onComplete
  } = props;

  const [step, setStep] = useState(1);

  // Form State
  const [name, setName] = useState(initialProfile.name || '');
  const [email, setEmail] = useState(initialProfile.email || '');
  const [avatar, setAvatar] = useState(initialProfile.avatar || '');
  const [role, setRole] = useState(initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(initialProfile.theme || 'light');

  // Validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = email.length === 0 || emailRegex.test(email);
  const canGoNextStep1 = name.trim().length > 0 && emailRegex.test(email) && avatar.length > 0;
  const canGoNextStep2 = role.length > 0;

  const handleNext = () => {
    if (step < 3) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleSubmit = () => {
    if (onComplete) {
      onComplete({ name, email, avatar, role, emailNotifications, theme });
    }
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={32} shadow="md" radius="lg">
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={2}>Welcome to Onboarding</Heading>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-neutral-500)">
                Step {step} of 3
              </Text>
              <Text variant="caption" color="var(--ggui-color-primary-600)">
                {step === 1 && 'Profile Setup'}
                {step === 2 && 'Preferences'}
                {step === 3 && 'Review & Confirm'}
              </Text>
            </Stack>
            <Progress value={(step / 3) * 100} max={100} variant="default" size="sm" />
          </Stack>

          <Divider margin={0} />

          <Box paddingY={16}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Profile Setup</Heading>

                <Input label="Full Name" placeholder="Enter your name" value={name} onChange={setName} required />

                <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={setEmail} required error={email.length > 0 && !isEmailValid ? 'Please enter a valid email address' : undefined} />

                <Stack gap={8}>
                  <Text variant="label">
                    Select an Avatar <Text as="span" color="var(--ggui-color-error-500)">*</Text>
                  </Text>
                  <Stack direction="horizontal" gap={12}>
                    {avatarOptions.map((opt) => (
                      <Button
                        key={opt}
                        variant={avatar === opt ? 'primary' : 'outline'}
                        onClick={() => setAvatar(opt)}
                        size="lg"
                      >
                        <Text as="span" size="2xl" color="inherit">{opt}</Text>
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Preferences</Heading>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  placeholder="Select your role"
                  required
                />

                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Toggle
                  label="Dark Theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Review & Confirm</Heading>
                <Card padding={24} shadow="none" border>
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Name</Text>
                      <Text variant="body">{name}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Email</Text>
                      <Text variant="body">{email}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Avatar</Text>
                      <Text variant="body" size="xl">{avatar}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Role</Text>
                      <Text variant="body">{role}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Email Notifications</Text>
                      <Text variant="body">{emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Theme</Text>
                      <Text variant="body">{theme === 'dark' ? 'Dark' : 'Light'}</Text>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin={0} />

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={handleBack}
              disabled={step === 1}
            >
              Go Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={(step === 1 && !canGoNextStep1) || (step === 2 && !canGoNextStep2)}
              >
                Next Step
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
